static void *v3_xmalloc(size_t size) {
    void *ptr = malloc(size);
    if (!ptr) {
        fprintf(stderr, "[cheng_v3_seed] out of memory size=%zu\n", size);
        exit(1);
    }
    return ptr;
}

static char *v3_strdup(const char *text) {
    size_t len = strlen(text);
    char *out = (char *)v3_xmalloc(len + 1);
    memcpy(out, text, len + 1);
    return out;
}

static char *v3_trim_inplace(char *text) {
    char *start = text;
    char *end;
    while (*start != '\0' && isspace((unsigned char)*start)) {
        start++;
    }
    end = start + strlen(start);
    while (end > start && isspace((unsigned char)end[-1])) {
        end--;
    }
    *end = '\0';
    return start;
}

static bool v3_streq(const char *a, const char *b) {
    return strcmp(a, b) == 0;
}

static bool v3_has_csv_token(const char *csv, const char *needle) {
    size_t needle_len = strlen(needle);
    const char *cursor = csv;
    while (*cursor != '\0') {
        while (*cursor == ' ' || *cursor == '\t' || *cursor == ',') {
            cursor++;
        }
        if (*cursor == '\0') {
            return false;
        }
        const char *stop = cursor;
        while (*stop != '\0' && *stop != ',') {
            stop++;
        }
        while (stop > cursor && (stop[-1] == ' ' || stop[-1] == '\t')) {
            stop--;
        }
        if ((size_t)(stop - cursor) == needle_len && strncmp(cursor, needle, needle_len) == 0) {
            return true;
        }
        cursor = stop;
        if (*cursor == ',') {
            cursor++;
        }
    }
    return false;
}

static uint64_t v3_fnv1a64(const char *text) {
    uint64_t hash = 1469598103934665603ULL;
    const unsigned char *cursor = (const unsigned char *)text;
    while (*cursor != '\0') {
        hash ^= (uint64_t)(*cursor);
        hash *= 1099511628211ULL;
        cursor++;
    }
    return hash;
}

static const uint32_t v3_sha256_table[64] = {
    0x428a2f98U, 0x71374491U, 0xb5c0fbcfU, 0xe9b5dba5U, 0x3956c25bU, 0x59f111f1U, 0x923f82a4U, 0xab1c5ed5U,
    0xd807aa98U, 0x12835b01U, 0x243185beU, 0x550c7dc3U, 0x72be5d74U, 0x80deb1feU, 0x9bdc06a7U, 0xc19bf174U,
    0xe49b69c1U, 0xefbe4786U, 0x0fc19dc6U, 0x240ca1ccU, 0x2de92c6fU, 0x4a7484aaU, 0x5cb0a9dcU, 0x76f988daU,
    0x983e5152U, 0xa831c66dU, 0xb00327c8U, 0xbf597fc7U, 0xc6e00bf3U, 0xd5a79147U, 0x06ca6351U, 0x14292967U,
    0x27b70a85U, 0x2e1b2138U, 0x4d2c6dfcU, 0x53380d13U, 0x650a7354U, 0x766a0abbU, 0x81c2c92eU, 0x92722c85U,
    0xa2bfe8a1U, 0xa81a664bU, 0xc24b8b70U, 0xc76c51a3U, 0xd192e819U, 0xd6990624U, 0xf40e3585U, 0x106aa070U,
    0x19a4c116U, 0x1e376c08U, 0x2748774cU, 0x34b0bcb5U, 0x391c0cb3U, 0x4ed8aa4aU, 0x5b9cca4fU, 0x682e6ff3U,
    0x748f82eeU, 0x78a5636fU, 0x84c87814U, 0x8cc70208U, 0x90befffaU, 0xa4506cebU, 0xbef9a3f7U, 0xc67178f2U
};

static uint32_t v3_sha256_rotr(uint32_t value, uint32_t shift) {
    return (value >> shift) | (value << (32U - shift));
}

static void v3_sha256_init(V3Sha256Ctx *ctx) {
    ctx->datalen = 0U;
    ctx->bitlen = 0ULL;
    ctx->state[0] = 0x6a09e667U;
    ctx->state[1] = 0xbb67ae85U;
    ctx->state[2] = 0x3c6ef372U;
    ctx->state[3] = 0xa54ff53aU;
    ctx->state[4] = 0x510e527fU;
    ctx->state[5] = 0x9b05688cU;
    ctx->state[6] = 0x1f83d9abU;
    ctx->state[7] = 0x5be0cd19U;
}

static void v3_sha256_transform(V3Sha256Ctx *ctx, const uint8_t data[64]) {
    uint32_t m[64];
    uint32_t a, b, c, d, e, f, g, h;
    size_t i;
    for (i = 0U; i < 16U; ++i) {
        m[i] = ((uint32_t)data[i * 4U] << 24) |
               ((uint32_t)data[i * 4U + 1U] << 16) |
               ((uint32_t)data[i * 4U + 2U] << 8) |
               ((uint32_t)data[i * 4U + 3U]);
    }
    for (i = 16U; i < 64U; ++i) {
        uint32_t s0 = v3_sha256_rotr(m[i - 15U], 7U) ^ v3_sha256_rotr(m[i - 15U], 18U) ^ (m[i - 15U] >> 3U);
        uint32_t s1 = v3_sha256_rotr(m[i - 2U], 17U) ^ v3_sha256_rotr(m[i - 2U], 19U) ^ (m[i - 2U] >> 10U);
        m[i] = m[i - 16U] + s0 + m[i - 7U] + s1;
    }
    a = ctx->state[0];
    b = ctx->state[1];
    c = ctx->state[2];
    d = ctx->state[3];
    e = ctx->state[4];
    f = ctx->state[5];
    g = ctx->state[6];
    h = ctx->state[7];
    for (i = 0U; i < 64U; ++i) {
        uint32_t S1 = v3_sha256_rotr(e, 6U) ^ v3_sha256_rotr(e, 11U) ^ v3_sha256_rotr(e, 25U);
        uint32_t ch = (e & f) ^ ((~e) & g);
        uint32_t temp1 = h + S1 + ch + v3_sha256_table[i] + m[i];
        uint32_t S0 = v3_sha256_rotr(a, 2U) ^ v3_sha256_rotr(a, 13U) ^ v3_sha256_rotr(a, 22U);
        uint32_t maj = (a & b) ^ (a & c) ^ (b & c);
        uint32_t temp2 = S0 + maj;
        h = g;
        g = f;
        f = e;
        e = d + temp1;
        d = c;
        c = b;
        b = a;
        a = temp1 + temp2;
    }
    ctx->state[0] += a;
    ctx->state[1] += b;
    ctx->state[2] += c;
    ctx->state[3] += d;
    ctx->state[4] += e;
    ctx->state[5] += f;
    ctx->state[6] += g;
    ctx->state[7] += h;
}

static void v3_sha256_update(V3Sha256Ctx *ctx, const uint8_t *data, size_t len) {
    size_t i;
    for (i = 0U; i < len; ++i) {
        ctx->data[ctx->datalen] = data[i];
        ctx->datalen += 1U;
        if (ctx->datalen == 64U) {
            v3_sha256_transform(ctx, ctx->data);
            ctx->bitlen += 512ULL;
            ctx->datalen = 0U;
        }
    }
}

static void v3_sha256_final(V3Sha256Ctx *ctx, uint8_t hash[32]) {
    uint32_t i;
    i = ctx->datalen;
    if (ctx->datalen < 56U) {
        ctx->data[i++] = 0x80U;
        while (i < 56U) {
            ctx->data[i++] = 0x00U;
        }
    } else {
        ctx->data[i++] = 0x80U;
        while (i < 64U) {
            ctx->data[i++] = 0x00U;
        }
        v3_sha256_transform(ctx, ctx->data);
        memset(ctx->data, 0, 56U);
    }
    ctx->bitlen += (uint64_t)ctx->datalen * 8ULL;
    ctx->data[63] = (uint8_t)(ctx->bitlen);
    ctx->data[62] = (uint8_t)(ctx->bitlen >> 8);
    ctx->data[61] = (uint8_t)(ctx->bitlen >> 16);
    ctx->data[60] = (uint8_t)(ctx->bitlen >> 24);
    ctx->data[59] = (uint8_t)(ctx->bitlen >> 32);
    ctx->data[58] = (uint8_t)(ctx->bitlen >> 40);
    ctx->data[57] = (uint8_t)(ctx->bitlen >> 48);
    ctx->data[56] = (uint8_t)(ctx->bitlen >> 56);
    v3_sha256_transform(ctx, ctx->data);
    for (i = 0U; i < 4U; ++i) {
        hash[i] = (uint8_t)((ctx->state[0] >> (24U - i * 8U)) & 0xffU);
        hash[i + 4U] = (uint8_t)((ctx->state[1] >> (24U - i * 8U)) & 0xffU);
        hash[i + 8U] = (uint8_t)((ctx->state[2] >> (24U - i * 8U)) & 0xffU);
        hash[i + 12U] = (uint8_t)((ctx->state[3] >> (24U - i * 8U)) & 0xffU);
        hash[i + 16U] = (uint8_t)((ctx->state[4] >> (24U - i * 8U)) & 0xffU);
        hash[i + 20U] = (uint8_t)((ctx->state[5] >> (24U - i * 8U)) & 0xffU);
        hash[i + 24U] = (uint8_t)((ctx->state[6] >> (24U - i * 8U)) & 0xffU);
        hash[i + 28U] = (uint8_t)((ctx->state[7] >> (24U - i * 8U)) & 0xffU);
    }
}

static void v3_cid_fill_hex(V3Cid32 *cid) {
    static const char *HEX = "0123456789abcdef";
    size_t i;
    for (i = 0U; i < 32U; ++i) {
        cid->hex[i * 2U] = HEX[(cid->bytes[i] >> 4U) & 0x0fU];
        cid->hex[i * 2U + 1U] = HEX[cid->bytes[i] & 0x0fU];
    }
    cid->hex[CHENG_V3_CID_HEX_LEN] = '\0';
}

static int v3_hex_value(char ch) {
    if (ch >= '0' && ch <= '9') {
        return (int)(ch - '0');
    }
    if (ch >= 'a' && ch <= 'f') {
        return (int)(10 + (ch - 'a'));
    }
    if (ch >= 'A' && ch <= 'F') {
        return (int)(10 + (ch - 'A'));
    }
    return -1;
}

static V3Cid32 v3_cid_zero(void) {
    V3Cid32 out;
    memset(&out, 0, sizeof(out));
    v3_cid_fill_hex(&out);
    return out;
}

static V3Cid32 v3_cid_from_bytes(const uint8_t *data, size_t len) {
    V3Cid32 out;
    V3Sha256Ctx ctx;
    memset(&out, 0, sizeof(out));
    v3_sha256_init(&ctx);
    if (data && len > 0U) {
        v3_sha256_update(&ctx, data, len);
    }
    v3_sha256_final(&ctx, out.bytes);
    v3_cid_fill_hex(&out);
    return out;
}

static void v3_bytebuf_init(V3ByteBuf *buf, size_t cap) {
    buf->len = 0U;
    buf->cap = cap > 0U ? cap : 64U;
    buf->data = (uint8_t *)v3_xmalloc(buf->cap);
}

static void v3_bytebuf_reserve(V3ByteBuf *buf, size_t extra) {
    size_t need = buf->len + extra;
    if (need <= buf->cap) {
        return;
    }
    while (buf->cap < need) {
        buf->cap *= 2U;
    }
    buf->data = (uint8_t *)realloc(buf->data, buf->cap);
    if (!buf->data) {
        fprintf(stderr, "[cheng_v3_seed] out of memory while growing byte buffer\n");
        exit(1);
    }
}

static void v3_bytebuf_append_bytes(V3ByteBuf *buf, const uint8_t *data, size_t len) {
    if (len <= 0U) {
        return;
    }
    v3_bytebuf_reserve(buf, len);
    memcpy(buf->data + buf->len, data, len);
    buf->len += len;
}

static void v3_bytebuf_append_u32_be(V3ByteBuf *buf, uint32_t value) {
    uint8_t bytes[4];
    bytes[0] = (uint8_t)((value >> 24U) & 0xffU);
    bytes[1] = (uint8_t)((value >> 16U) & 0xffU);
    bytes[2] = (uint8_t)((value >> 8U) & 0xffU);
    bytes[3] = (uint8_t)(value & 0xffU);
    v3_bytebuf_append_bytes(buf, bytes, 4U);
}

static void v3_bytebuf_append_text(V3ByteBuf *buf, const char *text) {
    size_t len = text ? strlen(text) : 0U;
    v3_bytebuf_append_u32_be(buf, (uint32_t)len);
    if (len > 0U) {
        v3_bytebuf_append_bytes(buf, (const uint8_t *)text, len);
    }
}

static void v3_bytebuf_append_cid(V3ByteBuf *buf, V3Cid32 cid) {
    v3_bytebuf_append_bytes(buf, cid.bytes, 32U);
}

static V3Cid32 v3_cid_from_bytebuf(const V3ByteBuf *buf) {
    return v3_cid_from_bytes(buf->data, buf->len);
}

static bool v3_cid_equal(V3Cid32 left, V3Cid32 right) {
    return memcmp(left.bytes, right.bytes, sizeof(left.bytes)) == 0;
}

static bool v3_cid_from_hex_text(const char *text, V3Cid32 *out) {
    size_t i;
    if (!text || strlen(text) != CHENG_V3_CID_HEX_LEN) {
        return false;
    }
    memset(out, 0, sizeof(*out));
    for (i = 0U; i < 32U; ++i) {
        int high = v3_hex_value(text[i * 2U]);
        int low = v3_hex_value(text[i * 2U + 1U]);
        if (high < 0 || low < 0) {
            return false;
        }
        out->bytes[i] = (uint8_t)((high << 4) | low);
    }
    v3_cid_fill_hex(out);
    return true;
}

static void v3_bytebuf_free(V3ByteBuf *buf) {
    free(buf->data);
    buf->data = NULL;
    buf->len = 0U;
    buf->cap = 0U;
}

static char *v3_read_file(const char *path) {
    FILE *fp = fopen(path, "rb");
    long size;
    char *buffer;
    if (!fp) {
        fprintf(stderr, "[cheng_v3_seed] failed to open: %s\n", path);
        return NULL;
    }
    if (fseek(fp, 0, SEEK_END) != 0) {
        fclose(fp);
        fprintf(stderr, "[cheng_v3_seed] failed to seek: %s\n", path);
        return NULL;
    }
    size = ftell(fp);
    if (size < 0) {
        fclose(fp);
        fprintf(stderr, "[cheng_v3_seed] failed to size: %s\n", path);
        return NULL;
    }
    if (fseek(fp, 0, SEEK_SET) != 0) {
        fclose(fp);
        fprintf(stderr, "[cheng_v3_seed] failed to rewind: %s\n", path);
        return NULL;
    }
    buffer = (char *)v3_xmalloc((size_t)size + 1U);
    if (size > 0 && fread(buffer, 1U, (size_t)size, fp) != (size_t)size) {
        fclose(fp);
        free(buffer);
        fprintf(stderr, "[cheng_v3_seed] failed to read: %s\n", path);
        return NULL;
    }
    buffer[size] = '\0';
    fclose(fp);
    return buffer;
}

static void v3_contract_init(V3BootstrapContract *contract, const char *source_path) {
    size_t i;
    memset(contract, 0, sizeof(*contract));
    if (source_path && *source_path != '\0') {
        snprintf(contract->source_path, sizeof(contract->source_path), "%s", source_path);
    }
    for (i = 0; i < CHENG_V3_MAX_FIELDS; ++i) {
        contract->fields[i].key = NULL;
        contract->fields[i].value = NULL;
    }
}

static void v3_contract_free(V3BootstrapContract *contract) {
    size_t i;
    for (i = 0; i < contract->len; ++i) {
        free(contract->fields[i].key);
        free(contract->fields[i].value);
    }
    contract->len = 0;
}

static const char *v3_contract_get(const V3BootstrapContract *contract, const char *key) {
    size_t i;
    for (i = 0; i < contract->len; ++i) {
        if (v3_streq(contract->fields[i].key, key)) {
            return contract->fields[i].value;
        }
    }
    return NULL;
}

static bool v3_contract_add(V3BootstrapContract *contract, const char *key, const char *value) {
    size_t i;
    if (contract->len >= CHENG_V3_MAX_FIELDS) {
        fprintf(stderr, "[cheng_v3_seed] too many bootstrap fields\n");
        return false;
    }
    for (i = 0; i < contract->len; ++i) {
        if (v3_streq(contract->fields[i].key, key)) {
            fprintf(stderr, "[cheng_v3_seed] duplicate bootstrap field: %s\n", key);
            return false;
        }
    }
    contract->fields[contract->len].key = v3_strdup(key);
    contract->fields[contract->len].value = v3_strdup(value);
    contract->len += 1U;
    return true;
}

static bool v3_parse_contract_text(V3BootstrapContract *contract, const char *source_path, const char *text) {
    char *owned = v3_strdup(text);
    char *cursor = owned;
    char *line;
    v3_contract_init(contract, source_path);
    while ((line = strsep(&cursor, "\n")) != NULL) {
        char *comment = strchr(line, '#');
        char *eq;
        char *key;
        char *value;
        if (comment) {
            *comment = '\0';
        }
        line = v3_trim_inplace(line);
        if (*line == '\0') {
            continue;
        }
        eq = strchr(line, '=');
        if (!eq) {
            fprintf(stderr, "[cheng_v3_seed] invalid bootstrap line (missing '='): %s\n", line);
            free(owned);
            return false;
        }
        *eq = '\0';
        key = v3_trim_inplace(line);
        value = v3_trim_inplace(eq + 1);
        if (*key == '\0' || *value == '\0') {
            fprintf(stderr, "[cheng_v3_seed] invalid bootstrap line: %s = %s\n", key, value);
            free(owned);
            return false;
        }
        if (!v3_contract_add(contract, key, value)) {
            free(owned);
            return false;
        }
    }
    free(owned);
    return true;
}

static bool v3_parse_contract_file(V3BootstrapContract *contract, const char *path) {
    char *text = v3_read_file(path);
    bool ok;
    if (!text) {
        return false;
    }
    ok = v3_parse_contract_text(contract, path, text);
    free(text);
    return ok;
}

static bool v3_validate_contract(const V3BootstrapContract *contract) {
    static const char *REQUIRED_IR_FACTS[] = {
        "move", "borrow", "noalias", "escape", "layout", "abi"
    };
    static const char *REQUIRED_LAYOUT[] = {
        "dod", "soa", "fixed_layout"
    };
    static const char *REQUIRED_FORBIDDEN[] = {
        "local_payload",
        "exec_plan_payload",
        "payloadText",
        "BigInt",
        "legacy_proof_surface",
        "legacy_sidecar_mode"
    };
    size_t i;
    const char *ir_facts;
    const char *data_layout;
    const char *forbidden;
    const char *commands;
    for (i = 0; i < sizeof(V3_REQUIRED_KEYS) / sizeof(V3_REQUIRED_KEYS[0]); ++i) {
        if (!v3_contract_get(contract, V3_REQUIRED_KEYS[i])) {
            fprintf(stderr, "[cheng_v3_seed] missing bootstrap field: %s\n", V3_REQUIRED_KEYS[i]);
            return false;
        }
    }
    if (!v3_streq(v3_contract_get(contract, "syntax"), "v3-bootstrap-v1")) {
        fprintf(stderr, "[cheng_v3_seed] unsupported bootstrap syntax\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "compiler_class"), "bootstrap_subset")) {
        fprintf(stderr, "[cheng_v3_seed] bootstrap compiler_class must be bootstrap_subset\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "target"), "arm64-apple-darwin")) {
        fprintf(stderr, "[cheng_v3_seed] bootstrap target must be arm64-apple-darwin\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "compiler_parallel_model"),
                  "two_pass,function_scheduler,thread_local_arena")) {
        fprintf(stderr, "[cheng_v3_seed] compiler parallel model drift\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "program_parallel_model"),
                  "deterministic_single_thread")) {
        fprintf(stderr, "[cheng_v3_seed] program parallel model drift\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "aot"), "required")) {
        fprintf(stderr, "[cheng_v3_seed] aot must be required\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "user_program_auto_parallel"), "off")) {
        fprintf(stderr, "[cheng_v3_seed] user_program_auto_parallel must be off\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "bagua_bpi"), "sidecar_only")) {
        fprintf(stderr, "[cheng_v3_seed] bagua_bpi must be sidecar_only\n");
        return false;
    }
    ir_facts = v3_contract_get(contract, "ir_facts");
    data_layout = v3_contract_get(contract, "data_layout");
    forbidden = v3_contract_get(contract, "forbidden");
    commands = v3_contract_get(contract, "supported_commands");
    for (i = 0; i < sizeof(REQUIRED_IR_FACTS) / sizeof(REQUIRED_IR_FACTS[0]); ++i) {
        if (!v3_has_csv_token(ir_facts, REQUIRED_IR_FACTS[i])) {
            fprintf(stderr, "[cheng_v3_seed] missing ir fact: %s\n", REQUIRED_IR_FACTS[i]);
            return false;
        }
    }
    for (i = 0; i < sizeof(REQUIRED_LAYOUT) / sizeof(REQUIRED_LAYOUT[0]); ++i) {
        if (!v3_has_csv_token(data_layout, REQUIRED_LAYOUT[i])) {
            fprintf(stderr, "[cheng_v3_seed] missing data layout default: %s\n", REQUIRED_LAYOUT[i]);
            return false;
        }
    }
    for (i = 0; i < sizeof(REQUIRED_FORBIDDEN) / sizeof(REQUIRED_FORBIDDEN[0]); ++i) {
        if (!v3_has_csv_token(forbidden, REQUIRED_FORBIDDEN[i])) {
            fprintf(stderr, "[cheng_v3_seed] missing forbidden token: %s\n", REQUIRED_FORBIDDEN[i]);
            return false;
        }
    }
    if (!v3_has_csv_token(commands, "print-contract") ||
        !v3_has_csv_token(commands, "self-check") ||
        !v3_has_csv_token(commands, "compile-bootstrap") ||
        !v3_has_csv_token(commands, "status") ||
        !v3_has_csv_token(commands, "print-build-plan") ||
        !v3_has_csv_token(commands, "debug-report") ||
        !v3_has_csv_token(commands, "print-symbols") ||
        !v3_has_csv_token(commands, "print-line-map") ||
        !v3_has_csv_token(commands, "print-elf") ||
        !v3_has_csv_token(commands, "emit-csg") ||
        !v3_has_csv_token(commands, "migrate-csg") ||
        !v3_has_csv_token(commands, "verify-world") ||
        !v3_has_csv_token(commands, "world-sync") ||
        !v3_has_csv_token(commands, "prove-equivalence") ||
        !v3_has_csv_token(commands, "prove-migration") ||
        !v3_has_csv_token(commands, "publish-world") ||
        !v3_has_csv_token(commands, "fresh-node-selfhost") ||
        !v3_has_csv_token(commands, "selfhost-build") ||
        !v3_has_csv_token(commands, "system-link-exec")) {
        fprintf(stderr, "[cheng_v3_seed] supported_commands drift\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "ordinary_command"), "system-link-exec")) {
        fprintf(stderr, "[cheng_v3_seed] ordinary_command drift\n");
        return false;
    }
    if (!v3_streq(v3_contract_get(contract, "ordinary_pipeline_state"),
                  "canonical_csg_verified_primary_object_codegen_missing")) {
        fprintf(stderr, "[cheng_v3_seed] ordinary_pipeline_state drift\n");
        return false;
    }
    return true;
}

static char *v3_contract_normalized_text(const V3BootstrapContract *contract) {
    static const char *ORDER[] = {
        "syntax",
        "bootstrap_name",
        "bootstrap_entry",
        "compiler_class",
        "bootstrap_source_kind",
        "target",
        "compiler_parallel_model",
        "program_parallel_model",
        "ir_facts",
        "data_layout",
        "aot",
        "forbidden",
        "supported_commands",
        "compiler_entry_source",
        "compiler_runtime_source",
        "compiler_request_source",
        "lang_parser_source",
        "backend_system_link_plan_source",
        "backend_lowering_plan_source",
        "backend_primary_object_plan_source",
        "backend_object_plan_source",
        "backend_native_link_plan_source",
        "backend_system_link_exec_source",
        "runtime_core_runtime_source",
        "runtime_compiler_runtime_source",
        "tooling_bootstrap_contract_source",
        "backend_build_plan_source",
        "tooling_build_driver_script",
        "ordinary_command",
        "ordinary_pipeline_state",
        "user_program_auto_parallel",
        "bagua_bpi"
    };
    size_t i;
    size_t cap = 8192U;
    size_t used = 0U;
    char *out = (char *)v3_xmalloc(cap);
    out[0] = '\0';
    for (i = 0; i < sizeof(ORDER) / sizeof(ORDER[0]); ++i) {
        const char *value = v3_contract_get(contract, ORDER[i]);
        int wrote;
        if (!value) {
            continue;
        }
        wrote = snprintf(out + used, cap - used, "%s=%s\n", ORDER[i], value);
        if (wrote < 0) {
            free(out);
            return NULL;
        }
        if (used + (size_t)wrote + 1U >= cap) {
            cap *= 2U;
            out = (char *)realloc(out, cap);
            if (!out) {
                fprintf(stderr, "[cheng_v3_seed] out of memory while normalizing contract\n");
                exit(1);
            }
            wrote = snprintf(out + used, cap - used, "%s=%s\n", ORDER[i], value);
            if (wrote < 0) {
                free(out);
                return NULL;
            }
        }
        used += (size_t)wrote;
    }
    return out;
}

static char *v3_c_escape(const char *text) {
    size_t i;
    size_t len = 0U;
    char *out;
    char *cursor;
    for (i = 0; text[i] != '\0'; ++i) {
        switch (text[i]) {
            case '\\':
            case '"':
                len += 2U;
                break;
            case '\n':
            case '\r':
            case '\t':
                len += 2U;
                break;
            default:
                len += 1U;
                break;
        }
    }
    out = (char *)v3_xmalloc(len + 1U);
    cursor = out;
    for (i = 0; text[i] != '\0'; ++i) {
        switch (text[i]) {
            case '\\':
                *cursor++ = '\\';
                *cursor++ = '\\';
                break;
            case '"':
                *cursor++ = '\\';
                *cursor++ = '"';
                break;
            case '\n':
                *cursor++ = '\\';
                *cursor++ = 'n';
                break;
            case '\r':
                *cursor++ = '\\';
                *cursor++ = 'r';
                break;
            case '\t':
                *cursor++ = '\\';
                *cursor++ = 't';
                break;
            default:
                *cursor++ = text[i];
                break;
        }
    }
    *cursor = '\0';
    return out;
}

static bool v3_write_text_file(const char *path, const char *text) {
    FILE *fp = fopen(path, "wb");
    size_t len = strlen(text);
    if (!fp) {
        fprintf(stderr, "[cheng_v3_seed] failed to write: %s\n", path);
        return false;
    }
    if (len > 0 && fwrite(text, 1U, len, fp) != len) {
        fclose(fp);
        fprintf(stderr, "[cheng_v3_seed] failed to flush: %s\n", path);
        return false;
    }
    fclose(fp);
    return true;
}

static bool v3_write_binary_file(const char *path, const unsigned char *data, size_t len) {
    FILE *fp = fopen(path, "wb");
    if (!fp) {
        fprintf(stderr, "[cheng_v3_seed] failed to write binary: %s\n", path);
        return false;
    }
    if (len > 0U && fwrite(data, 1U, len, fp) != len) {
        fclose(fp);
        fprintf(stderr, "[cheng_v3_seed] failed to flush binary: %s\n", path);
        return false;
    }
    fclose(fp);
    return true;
}

static bool v3_mkdir_p(const char *path) {
    char temp[PATH_MAX];
    size_t i;
    if (!path || *path == '\0') {
        return true;
    }
    if (strlen(path) >= sizeof(temp)) {
        fprintf(stderr, "[cheng_v3_seed] path too long: %s\n", path);
        return false;
    }
    snprintf(temp, sizeof(temp), "%s", path);
    for (i = 1U; temp[i] != '\0'; ++i) {
        if (temp[i] == '/') {
            temp[i] = '\0';
            if (temp[0] != '\0' && mkdir(temp, 0777) != 0 && errno != EEXIST) {
                fprintf(stderr, "[cheng_v3_seed] mkdir failed: %s\n", temp);
                return false;
            }
            temp[i] = '/';
        }
    }
    if (mkdir(temp, 0777) != 0 && errno != EEXIST) {
        fprintf(stderr, "[cheng_v3_seed] mkdir failed: %s\n", temp);
        return false;
    }
    return true;
}

static bool v3_ensure_parent_dir(const char *path) {
    char temp[PATH_MAX];
    char *slash;
    if (strlen(path) >= sizeof(temp)) {
        fprintf(stderr, "[cheng_v3_seed] path too long: %s\n", path);
        return false;
    }
    snprintf(temp, sizeof(temp), "%s", path);
    slash = strrchr(temp, '/');
    if (!slash) {
        return true;
    }
    if (slash == temp) {
        return true;
    }
    *slash = '\0';
    return v3_mkdir_p(temp);
}

static bool v3_copy_file_bytes(const char *source_path, const char *dest_path) {
    FILE *in = NULL;
    FILE *out = NULL;
    unsigned char buffer[16384];
    size_t read_len = 0U;
    if (!v3_ensure_parent_dir(dest_path)) {
        return false;
    }
    in = fopen(source_path, "rb");
    if (!in) {
        fprintf(stderr, "[cheng_v3_seed] failed to open copy source: %s\n", source_path);
        return false;
    }
    out = fopen(dest_path, "wb");
    if (!out) {
        fclose(in);
        fprintf(stderr, "[cheng_v3_seed] failed to open copy dest: %s\n", dest_path);
        return false;
    }
    while ((read_len = fread(buffer, 1U, sizeof(buffer), in)) > 0U) {
        if (fwrite(buffer, 1U, read_len, out) != read_len) {
            fclose(in);
            fclose(out);
            fprintf(stderr, "[cheng_v3_seed] failed to copy bytes: %s -> %s\n", source_path, dest_path);
            return false;
        }
    }
    fclose(in);
    fclose(out);
    return true;
}

static char *v3_shell_quote(const char *text) {
    size_t i;
    size_t len = 2U;
    char *out;
    char *cursor;
    for (i = 0; text[i] != '\0'; ++i) {
        if (text[i] == '\'') {
            len += 4U;
        } else {
            len += 1U;
        }
    }
    out = (char *)v3_xmalloc(len + 1U);
    cursor = out;
    *cursor++ = '\'';
    for (i = 0; text[i] != '\0'; ++i) {
        if (text[i] == '\'') {
            *cursor++ = '\'';
            *cursor++ = '\\';
            *cursor++ = '\'';
            *cursor++ = '\'';
        } else {
            *cursor++ = text[i];
        }
    }
    *cursor++ = '\'';
    *cursor = '\0';
    return out;
}

static bool v3_compile_wrapper(const char *wrapper_path, const char *out_path) {
    const char *cc = getenv("CC");
    char command[PATH_MAX * 3];
    char *quoted_cc;
    char *quoted_wrapper;
    char *quoted_out;
    int rc;
    if (!cc || *cc == '\0') {
        cc = "cc";
    }
    quoted_cc = v3_shell_quote(cc);
    quoted_wrapper = v3_shell_quote(wrapper_path);
    quoted_out = v3_shell_quote(out_path);
    snprintf(command, sizeof(command),
             "%s -std=c11 -O2 -Wall -Wextra -pedantic %s -o %s",
             quoted_cc, quoted_wrapper, quoted_out);
    free(quoted_cc);
    free(quoted_wrapper);
    free(quoted_out);
    rc = system(command);
    if (rc != 0) {
        fprintf(stderr, "[cheng_v3_seed] cc failed rc=%d command=%s\n", rc, command);
        return false;
    }
    return true;
}

static bool v3_write_wrapper_source(const char *wrapper_path,
                                    const char *embedded_source_path,
                                    const char *contract_text) {
    char *escaped_impl = v3_c_escape(CHENG_V3_IMPL_SOURCE_PATH);
    char *escaped_source = v3_c_escape(embedded_source_path);
    char *escaped_contract = v3_c_escape(contract_text);
    size_t cap = strlen(escaped_impl) + strlen(escaped_source) + strlen(escaped_contract) + 256U;
    char *text = (char *)v3_xmalloc(cap);
    snprintf(text, cap,
             "#define CHENG_V3_IMPL_SOURCE_PATH \"%s\"\n"
             "#define CHENG_V3_EMBEDDED_SOURCE_PATH \"%s\"\n"
             "#define CHENG_V3_EMBEDDED_CONTRACT_TEXT \"%s\"\n"
             "#include CHENG_V3_IMPL_SOURCE_PATH\n",
             escaped_impl, escaped_source, escaped_contract);
    free(escaped_impl);
    free(escaped_source);
    free(escaped_contract);
    if (!v3_ensure_parent_dir(wrapper_path)) {
        free(text);
        return false;
    }
    if (!v3_write_text_file(wrapper_path, text)) {
        free(text);
        return false;
    }
    free(text);
    return true;
}

static bool v3_write_compile_report(const char *report_path,
                                    const V3BootstrapContract *contract,
                                    const char *source_path,
                                    const char *out_path,
                                    const char *contract_text) {
    char buffer[8192];
    snprintf(buffer, sizeof(buffer),
             "compiler_class=%s\n"
             "target=%s\n"
             "source=%s\n"
             "output=%s\n"
             "contract_hash=%016llx\n"
             "compiler_parallel_model=%s\n"
             "program_parallel_model=%s\n"
             "data_layout=%s\n",
             v3_contract_get(contract, "compiler_class"),
             v3_contract_get(contract, "target"),
             source_path,
             out_path,
             (unsigned long long)v3_fnv1a64(contract_text),
             v3_contract_get(contract, "compiler_parallel_model"),
             v3_contract_get(contract, "program_parallel_model"),
             v3_contract_get(contract, "data_layout"));
    if (!v3_ensure_parent_dir(report_path)) {
        return false;
    }
    return v3_write_text_file(report_path, buffer);
}

static const char *v3_flag_value(int argc, char **argv, const char *flag) {
    size_t flag_len = strlen(flag);
    int i;
    for (i = 2; i < argc; ++i) {
        const char *arg = argv[i];
        if (strncmp(arg, flag, flag_len) == 0) {
            if (arg[flag_len] == ':') {
                return arg + flag_len + 1;
            }
            if (arg[flag_len] == '=') {
                return arg + flag_len + 1;
            }
            if (arg[flag_len] == '\0' && (i + 1) < argc) {
                return argv[i + 1];
            }
        }
    }
    return NULL;
}

