static int32_t v3_line_indent(const char *line) {
    int32_t indent = 0;
    while (*line == ' ') {
        indent += 1;
        line++;
    }
    return indent;
}

static bool v3_collect_statement_from_lines(char **lines,
                                            size_t line_count,
                                            size_t *index_io,
                                            char *out,
                                            size_t out_cap) {
    size_t index = *index_io;
    size_t used = 0U;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    bool in_string = false;
    if (index >= line_count) {
        return false;
    }
    out[0] = '\0';
    while (index < line_count) {
        char piece[4096];
        char line_copy[4096];
        char *trimmed;
        size_t i;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[index]);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            index += 1U;
            if (used > 0U &&
                paren_depth <= 0 &&
                bracket_depth <= 0 &&
                brace_depth <= 0) {
                break;
            }
            continue;
        }
        if (used > 0U) {
            snprintf(out + used, out_cap - used, " ");
            used = strlen(out);
        }
        snprintf(piece, sizeof(piece), "%s", trimmed);
        v3_strip_trailing_comment_inplace(piece);
        if (piece[0] == '\0') {
            index += 1U;
            if (used > 0U &&
                paren_depth <= 0 &&
                bracket_depth <= 0 &&
                brace_depth <= 0) {
                break;
            }
            continue;
        }
        snprintf(out + used, out_cap - used, "%s", piece);
        used = strlen(out);
        for (i = 0; piece[i] != '\0'; ++i) {
            if (piece[i] == '"') {
                in_string = !in_string;
                continue;
            }
            if (in_string) {
                continue;
            }
            if (piece[i] == '(') {
                paren_depth += 1;
            } else if (piece[i] == ')') {
                paren_depth -= 1;
            } else if (piece[i] == '[') {
                bracket_depth += 1;
            } else if (piece[i] == ']') {
                bracket_depth -= 1;
            } else if (piece[i] == '{') {
                brace_depth += 1;
            } else if (piece[i] == '}') {
                brace_depth -= 1;
            }
        }
        index += 1U;
        if (paren_depth <= 0 &&
            bracket_depth <= 0 &&
            brace_depth <= 0 &&
            !(used >= 2U &&
              (strcmp(out + used - 2U, "||") == 0 ||
               strcmp(out + used - 2U, "&&") == 0 ||
               strcmp(out + used - 2U, "==") == 0 ||
               strcmp(out + used - 2U, "!=") == 0 ||
               strcmp(out + used - 2U, "<=") == 0 ||
               strcmp(out + used - 2U, ">=") == 0 ||
               strcmp(out + used - 2U, "<<") == 0 ||
               strcmp(out + used - 2U, ">>") == 0)) &&
            !(used >= 1U &&
              (out[used - 1U] == '|' ||
               out[used - 1U] == '^' ||
               out[used - 1U] == '&' ||
               out[used - 1U] == '+' ||
               out[used - 1U] == '-' ||
               out[used - 1U] == '*' ||
               out[used - 1U] == '/' ||
               out[used - 1U] == '%' ||
               out[used - 1U] == ','))) {
            if (v3_statement_has_incomplete_if_expr(out)) {
                continue;
            }
            break;
        }
    }
    *index_io = index;
    return used > 0U;
}

static bool v3_is_top_level_decl_start(const char *trimmed) {
    if (!trimmed || trimmed[0] == '\0') {
        return false;
    }
    if (v3_startswith(trimmed, "fn ")) {
        return true;
    }
    if (strcmp(trimmed, "type") == 0 || v3_startswith(trimmed, "type ")) {
        return true;
    }
    if (strcmp(trimmed, "const") == 0 || v3_startswith(trimmed, "const ")) {
        return true;
    }
    if (strcmp(trimmed, "var") == 0 || v3_startswith(trimmed, "var ")) {
        return true;
    }
    if (v3_startswith(trimmed, "import ") ||
        v3_startswith(trimmed, "importc ") ||
        trimmed[0] == '@') {
        return true;
    }
    return false;
}

static size_t v3_count_function_body_statements(char **lines,
                                                size_t line_count,
                                                size_t signature_end_index) {
    size_t index = signature_end_index + 1U;
    size_t count = 0U;
    while (index < line_count) {
        char raw_copy[4096];
        char statement[8192];
        char *trimmed;
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[index]);
        trimmed = v3_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            index += 1U;
            continue;
        }
        if (v3_line_indent(lines[index]) <= 0 && v3_is_top_level_decl_start(trimmed)) {
            break;
        }
        if (!v3_collect_statement_from_lines(lines, line_count, &index, statement, sizeof(statement))) {
            break;
        }
        count += 1U;
    }
    return count;
}

static bool v3_is_last_logical_statement_in_function(char **lines,
                                                     size_t line_count,
                                                     size_t index_after_statement) {
    size_t index = index_after_statement;
    while (index < line_count) {
        char raw_copy[4096];
        char statement[8192];
        char *trimmed;
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[index]);
        trimmed = v3_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            index += 1U;
            continue;
        }
        if (v3_line_indent(lines[index]) <= 0 && v3_is_top_level_decl_start(trimmed)) {
            return true;
        }
        if (!v3_collect_statement_from_lines(lines, line_count, &index, statement, sizeof(statement))) {
            break;
        }
        return false;
    }
    return true;
}

static bool v3_const_is_whitespace_char(char ch) {
    return ch == ' ' || ch == '\t' || ch == '\n' || ch == '\r';
}

static bool v3_const_str_strip_ascii(const char *text, char *out, size_t cap) {
    const char *start = text;
    const char *end = text + strlen(text);
    while (*start != '\0' && v3_const_is_whitespace_char(*start)) {
        start++;
    }
    while (end > start && v3_const_is_whitespace_char(end[-1])) {
        end--;
    }
    snprintf(out, cap, "%.*s", (int)(end - start), start);
    return true;
}

static bool v3_const_os_is_absolute(const char *text) {
    size_t len = strlen(text);
    if (len <= 0U || text[0] == '\0') {
        return false;
    }
    if (text[0] == '/' || text[0] == '\\') {
        return true;
    }
    if (len > 1U && text[1] == ':') {
        return true;
    }
    return false;
}

static bool v3_const_os_join_path(const char *a, const char *b, char *out, size_t cap) {
    size_t a_len = strlen(a);
    size_t b_len = strlen(b);
    if (a_len <= 0U || a[0] == '\0') {
        snprintf(out, cap, "%s", b);
        return true;
    }
    if (b_len <= 0U || b[0] == '\0') {
        snprintf(out, cap, "%s", a);
        return true;
    }
    if (a[a_len - 1U] == '/' || a[a_len - 1U] == '\\') {
        snprintf(out, cap, "%s%s", a, b);
        return true;
    }
    snprintf(out, cap, "%s/%s", a, b);
    return true;
}

static bool v3_const_parse_function_signature(const char *line,
                                              const char *function_name,
                                              char param_names[][128],
                                              size_t *param_count,
                                              size_t param_cap) {
    const char *open_paren;
    const char *close_paren;
    char params[4096];
    char items[32][4096];
    size_t item_count = 0U;
    size_t i;
    *param_count = 0U;
    open_paren = strchr(line, '(');
    close_paren = strchr(line, ')');
    if (!open_paren || !close_paren || close_paren <= open_paren) {
        return false;
    }
    char header_copy[4096];
    snprintf(header_copy, sizeof(header_copy), "%s", line);
    if (!v3_startswith(v3_trim_inplace(header_copy), "fn ")) {
        return false;
    }
    if (strstr(line, function_name) == NULL) {
        return false;
    }
    snprintf(params, sizeof(params), "%.*s", (int)(close_paren - open_paren - 1), open_paren + 1);
    if (!v3_split_top_level_args(params, items, &item_count, 32U)) {
        return false;
    }
    for (i = 0; i < item_count; ++i) {
        char *colon = strchr(items[i], ':');
        if (*param_count >= param_cap) {
            return false;
        }
        if (colon) {
            *colon = '\0';
        }
        v3_trim_copy_text(items[i], param_names[*param_count], sizeof(param_names[*param_count]));
        if (param_names[*param_count][0] != '\0') {
            *param_count += 1U;
        }
    }
    return true;
}

static bool v3_type_text_strip_one_pointer_suffix(const char *type_text,
                                                  char *base_out,
                                                  size_t base_cap) {
    char trimmed[256];
    size_t len;
    if (!type_text || !base_out || base_cap == 0U) {
        return false;
    }
    v3_trim_copy_text(type_text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    while (len > 0U && isspace((unsigned char)trimmed[len - 1U])) {
        trimmed[len - 1U] = '\0';
        len -= 1U;
    }
    if (len == 0U || trimmed[len - 1U] != '*') {
        return false;
    }
    trimmed[len - 1U] = '\0';
    v3_trim_copy_text(trimmed, base_out, base_cap);
    return base_out[0] != '\0';
}

static int32_t v3_type_text_pointer_depth(const char *type_text,
                                          char *base_out,
                                          size_t base_cap) {
    char current[256];
    char next[256];
    int32_t depth = 0;
    if (!type_text) {
        return 0;
    }
    v3_trim_copy_text(type_text, current, sizeof(current));
    while (v3_type_text_strip_one_pointer_suffix(current, next, sizeof(next))) {
        snprintf(current, sizeof(current), "%s", next);
        depth += 1;
    }
    if (base_out && base_cap > 0U) {
        snprintf(base_out, base_cap, "%s", current);
    }
    return depth;
}

static const char *v3_type_abi_class(const char *type_text) {
    char pointer_base[256];
    if (!type_text || *type_text == '\0' || strcmp(type_text, "void") == 0) {
        return "void";
    }
    if (v3_startswith(type_text, "ref@")) {
        return "ptr";
    }
    if (v3_startswith(type_text, "fn ") || v3_startswith(type_text, "fn(")) {
        return "ptr";
    }
    if (strcmp(type_text, "int8") == 0) {
        return "i8";
    }
    if (strcmp(type_text, "uint8") == 0) {
        return "u8";
    }
    if (strcmp(type_text, "int16") == 0) {
        return "i16";
    }
    if (strcmp(type_text, "uint16") == 0) {
        return "u16";
    }
    if (strcmp(type_text, "int32") == 0 ||
        strcmp(type_text, "int") == 0 ||
        strcmp(type_text, "uint32") == 0 ||
        strcmp(type_text, "char") == 0) {
        return "i32";
    }
    if (strcmp(type_text, "int64") == 0 ||
        strcmp(type_text, "uint64") == 0) {
        return "i64";
    }
    if (strcmp(type_text, "float") == 0 ||
        strcmp(type_text, "float32") == 0 ||
        strcmp(type_text, "float64") == 0) {
        return "i64";
    }
    if (strcmp(type_text, "bool") == 0) {
        return "bool";
    }
    if (strcmp(type_text, "ptr") == 0 ||
        strcmp(type_text, "cstring") == 0) {
        return "ptr";
    }
    if (v3_type_text_strip_one_pointer_suffix(type_text, pointer_base, sizeof(pointer_base))) {
        return "ptr";
    }
    return "composite";
}

static bool v3_is_internal_ref_type(const char *type_text) {
    return type_text != NULL && v3_startswith(type_text, "ref@");
}

static void v3_strip_internal_ref_type(const char *type_text, char *out, size_t cap) {
    if (cap == 0U) {
        return;
    }
    if (v3_is_internal_ref_type(type_text)) {
        snprintf(out, cap, "%s", type_text + 4);
        return;
    }
    snprintf(out, cap, "%s", type_text ? type_text : "");
}

static void v3_write_type_def_normalized(const V3TypeDefStub *type_def, char *out, size_t cap) {
    if (cap == 0U) {
        return;
    }
    if (type_def == NULL) {
        out[0] = '\0';
        return;
    }
    if (type_def->ref_object) {
        snprintf(out, cap, "ref@%s::%s", type_def->owner_module_path, type_def->type_name);
        return;
    }
    snprintf(out, cap, "%s::%s", type_def->owner_module_path, type_def->type_name);
}

static void v3_text_appendf(char *out, size_t cap, const char *fmt, ...);
static bool v3_abi_class_scalar_or_ptr(const char *abi_class);

static const char *v3_canonical_scalar_type_name(const char *type_text) {
    if (type_text == NULL) {
        return "";
    }
    if (strcmp(type_text, "int") == 0) {
        return "int32";
    }
    return type_text;
}

static bool v3_scalar_type_is_unsigned(const char *type_text) {
    const char *canonical = v3_canonical_scalar_type_name(type_text);
    return strcmp(canonical, "uint8") == 0 ||
           strcmp(canonical, "uint16") == 0 ||
           strcmp(canonical, "uint32") == 0 ||
           strcmp(canonical, "uint64") == 0;
}

static bool v3_text_case_equal(const char *lhs, const char *rhs) {
    size_t i = 0U;
    if (!lhs || !rhs) {
        return false;
    }
    while (lhs[i] != '\0' && rhs[i] != '\0') {
        if (tolower((unsigned char)lhs[i]) != tolower((unsigned char)rhs[i])) {
            return false;
        }
        i += 1U;
    }
    return lhs[i] == '\0' && rhs[i] == '\0';
}

static bool v3_emit_scalar_cast_reg(char *out,
                                    size_t cap,
                                    const char *src_type_text,
                                    const char *src_abi,
                                    const char *dst_type_text,
                                    const char *dst_abi,
                                    int reg_index) {
    const char *src_type = v3_canonical_scalar_type_name(src_type_text);
    const char *dst_type = v3_canonical_scalar_type_name(dst_type_text);
    if (!v3_abi_class_scalar_or_ptr(src_abi) || !v3_abi_class_scalar_or_ptr(dst_abi)) {
        return false;
    }
    if (strcmp(dst_abi, "bool") == 0) {
        v3_text_appendf(out, cap, "  cmp %c%d, #0\n  cset w%d, ne\n",
                        strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0 ? 'x' : 'w',
                        reg_index,
                        reg_index);
        return true;
    }
    if (strcmp(src_abi, dst_abi) == 0 &&
        strcmp(src_type, dst_type) == 0) {
        return true;
    }
    if (strcmp(dst_abi, "i64") == 0 || strcmp(dst_abi, "ptr") == 0) {
        if (strcmp(src_abi, "bool") == 0 ||
            strcmp(src_abi, "i8") == 0 ||
            strcmp(src_abi, "u8") == 0 ||
            strcmp(src_abi, "i16") == 0 ||
            strcmp(src_abi, "u16") == 0 ||
            strcmp(src_abi, "i32") == 0) {
            if (v3_scalar_type_is_unsigned(src_type) ||
                strcmp(src_abi, "bool") == 0 ||
                strcmp(src_abi, "u8") == 0 ||
                strcmp(src_abi, "u16") == 0) {
                v3_text_appendf(out, cap, "  uxtw x%d, w%d\n", reg_index, reg_index);
            } else {
                v3_text_appendf(out, cap, "  sxtw x%d, w%d\n", reg_index, reg_index);
            }
            return true;
        }
        if (strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0) {
            return true;
        }
        return false;
    }
    if (strcmp(dst_abi, "i32") == 0) {
        if (strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0) {
            v3_text_appendf(out, cap, "  mov w%d, w%d\n", reg_index, reg_index);
            return true;
        }
        if (strcmp(src_abi, "bool") == 0 ||
            strcmp(src_abi, "i8") == 0 ||
            strcmp(src_abi, "u8") == 0 ||
            strcmp(src_abi, "i16") == 0 ||
            strcmp(src_abi, "u16") == 0 ||
            strcmp(src_abi, "i32") == 0) {
            return true;
        }
        return false;
    }
    if (strcmp(dst_abi, "i16") == 0) {
        v3_text_appendf(out,
                        cap,
                        v3_scalar_type_is_unsigned(dst_type) ? "  uxth w%d, w%d\n" : "  sxth w%d, w%d\n",
                        reg_index,
                        reg_index);
        return true;
    }
    if (strcmp(dst_abi, "u16") == 0) {
        v3_text_appendf(out, cap, "  uxth w%d, w%d\n", reg_index, reg_index);
        return true;
    }
    if (strcmp(dst_abi, "i8") == 0) {
        v3_text_appendf(out,
                        cap,
                        v3_scalar_type_is_unsigned(dst_type) ? "  uxtb w%d, w%d\n" : "  sxtb w%d, w%d\n",
                        reg_index,
                        reg_index);
        return true;
    }
    if (strcmp(dst_abi, "u8") == 0) {
        v3_text_appendf(out, cap, "  uxtb w%d, w%d\n", reg_index, reg_index);
        return true;
    }
    return false;
}

static bool v3_strip_var_type_text(const char *type_text,
                                   char *out,
                                   size_t cap) {
    char trimmed[256];
    if (!type_text || !out || cap == 0U) {
        return false;
    }
    v3_trim_copy_text(type_text, trimmed, sizeof(trimmed));
    if (!v3_startswith(trimmed, "var ")) {
        snprintf(out, cap, "%s", trimmed);
        return false;
    }
    v3_trim_copy_text(trimmed + 4, out, cap);
    return out[0] != '\0';
}

static bool v3_parse_top_level_const_binding(const char *statement,
                                             char *name_out,
                                             size_t name_cap,
                                             char *type_out,
                                             size_t type_cap,
                                             char *expr_out,
                                             size_t expr_cap) {
    const char *eq = strchr(statement, '=');
    char left[256];
    char right[4096];
    char *colon;
    if (!eq) {
        return false;
    }
    snprintf(left, sizeof(left), "%.*s", (int)(eq - statement), statement);
    snprintf(right, sizeof(right), "%s", eq + 1);
    v3_trim_copy_text(left, left, sizeof(left));
    v3_trim_copy_text(right, expr_out, expr_cap);
    if (left[0] == '\0' || expr_out[0] == '\0') {
        return false;
    }
    colon = strchr(left, ':');
    if (colon) {
        *colon = '\0';
        snprintf(type_out, type_cap, "%s", colon + 1);
        v3_trim_copy_text(type_out, type_out, type_cap);
    } else {
        type_out[0] = '\0';
    }
    v3_trim_copy_text(left, name_out, name_cap);
    return name_out[0] != '\0';
}

static int32_t v3_find_top_level_const_index_by_symbol(const V3LoweringPlanStub *lowering,
                                                       const char *symbol_text) {
    size_t i;
    for (i = 0; i < lowering->const_count; ++i) {
        if (strcmp(lowering->consts[i].symbol_text, symbol_text) == 0) {
            return (int32_t)i;
        }
    }
    return -1;
}

static bool v3_parse_string_literal_text(const char *expr_text,
                                         char *literal_out,
                                         size_t literal_cap);
static bool v3_parse_int_literal_text(const char *expr_text, int64_t *value_out);
static int32_t v3_find_top_level_binary_op_last(const char *text, const char *op);
static bool v3_parse_top_level_var_binding_text(const char *statement,
                                                char *name_out,
                                                size_t name_cap,
                                                char *type_out,
                                                size_t type_cap,
                                                bool *has_init_out,
                                                char *expr_out,
                                                size_t expr_cap);

static bool v3_try_resolve_i64_top_level_const_expr(const char *expr_text,
                                                    const V3LoweringPlanStub *lowering,
                                                    const char *owner_module_path,
                                                    const V3ImportAlias *aliases,
                                                    size_t alias_count,
                                                    int64_t *value_out) {
    char expr[4096];
    int64_t literal = 0;
    int32_t shl_index = -1;
    int32_t plus_index = -1;
    int32_t minus_index = -1;
    int64_t lhs = 0;
    int64_t rhs = 0;
    char left[4096];
    char right[4096];
    char symbol_text[PATH_MAX];
    int32_t index = -1;
    const V3TopLevelConstStub *existing = NULL;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    if (v3_parse_int_literal_text(expr, &literal)) {
        *value_out = literal;
        return true;
    }
    shl_index = v3_find_top_level_binary_op_last(expr, "<<");
    if (shl_index > 0) {
        snprintf(left, sizeof(left), "%.*s", shl_index, expr);
        snprintf(right, sizeof(right), "%s", expr + shl_index + 2);
        v3_trim_copy_text(left, left, sizeof(left));
        v3_trim_copy_text(right, right, sizeof(right));
        return v3_try_resolve_i64_top_level_const_expr(left,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &lhs) &&
               v3_try_resolve_i64_top_level_const_expr(right,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &rhs) &&
               rhs >= 0 &&
               rhs < 63 &&
               ((*value_out = (int64_t)((uint64_t)lhs << (uint32_t)rhs)), true);
    }
    plus_index = v3_find_top_level_binary_op_last(expr, "+");
    if (plus_index > 0) {
        snprintf(left, sizeof(left), "%.*s", plus_index, expr);
        snprintf(right, sizeof(right), "%s", expr + plus_index + 1);
        v3_trim_copy_text(left, left, sizeof(left));
        v3_trim_copy_text(right, right, sizeof(right));
        return v3_try_resolve_i64_top_level_const_expr(left,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &lhs) &&
               v3_try_resolve_i64_top_level_const_expr(right,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &rhs) &&
               ((*value_out = lhs + rhs), true);
    }
    minus_index = v3_find_top_level_binary_op_last(expr, "-");
    if (minus_index > 0) {
        snprintf(left, sizeof(left), "%.*s", minus_index, expr);
        snprintf(right, sizeof(right), "%s", expr + minus_index + 1);
        v3_trim_copy_text(left, left, sizeof(left));
        v3_trim_copy_text(right, right, sizeof(right));
        return v3_try_resolve_i64_top_level_const_expr(left,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &lhs) &&
               v3_try_resolve_i64_top_level_const_expr(right,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &rhs) &&
               ((*value_out = lhs - rhs), true);
    }
    if (strchr(expr, '.') != NULL) {
        char alias_text[128];
        char const_name[128];
        char expr_copy[4096];
        char *dot;
        const char *module_path;
        snprintf(expr_copy, sizeof(expr_copy), "%s", expr);
        dot = strchr(expr_copy, '.');
        *dot = '\0';
        snprintf(alias_text, sizeof(alias_text), "%s", expr_copy);
        snprintf(const_name, sizeof(const_name), "%s", dot + 1);
        module_path = v3_alias_module_path(aliases, alias_count, alias_text);
        if (!module_path) {
            return false;
        }
        snprintf(symbol_text, sizeof(symbol_text), "%s::%s", module_path, const_name);
    } else {
        snprintf(symbol_text, sizeof(symbol_text), "%s::%s", owner_module_path, expr);
    }
    index = v3_find_top_level_const_index_by_symbol(lowering, symbol_text);
    if (index < 0) {
        return false;
    }
    existing = &lowering->consts[index];
    if (strcmp(existing->abi_class, "i32") != 0 &&
        strcmp(existing->abi_class, "i64") != 0 &&
        strcmp(existing->abi_class, "bool") != 0) {
        return false;
    }
    *value_out = existing->i64_value;
    return true;
}

static bool v3_try_parse_scalar_const_literal(const char *expr_text,
                                              const char *declared_type,
                                              const V3LoweringPlanStub *lowering,
                                              const char *owner_module_path,
                                              const V3ImportAlias *aliases,
                                              size_t alias_count,
                                              V3TopLevelConstStub *out) {
    char expr[4096];
    char literal[8192];
    char *end = NULL;
    const char *declared_abi = v3_type_abi_class(declared_type);
    int64_t resolved_i64 = 0;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    memset(out, 0, sizeof(*out));
    if (strcmp(expr, "true") == 0 || strcmp(expr, "false") == 0) {
        snprintf(out->abi_class, sizeof(out->abi_class), "%s", "bool");
        out->bool_value = strcmp(expr, "true") == 0;
        out->i64_value = out->bool_value ? 1 : 0;
        return true;
    }
    if ((expr[0] >= '0' && expr[0] <= '9') ||
        (expr[0] == '-' && ((expr[1] >= '0' && expr[1] <= '9') || expr[1] == '0'))) {
        long long value = strtoll(expr, &end, 0);
        if (end && *v3_trim_inplace(end) == '\0') {
            snprintf(out->abi_class,
                     sizeof(out->abi_class),
                     "%s",
                     strcmp(declared_abi, "i64") == 0 ? "i64" : "i32");
            out->i64_value = (int64_t)value;
            return true;
        }
    }
    if ((declared_type[0] == '\0' ||
         strcmp(declared_abi, "i32") == 0 ||
         strcmp(declared_abi, "i64") == 0 ||
         strcmp(declared_abi, "bool") == 0) &&
        v3_try_resolve_i64_top_level_const_expr(expr,
                                                lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                &resolved_i64)) {
        snprintf(out->abi_class,
                 sizeof(out->abi_class),
                 "%s",
                 strcmp(declared_abi, "i64") == 0 ? "i64" :
                 (strcmp(declared_abi, "bool") == 0 ? "bool" : "i32"));
        out->i64_value = resolved_i64;
        out->bool_value = resolved_i64 != 0;
        return true;
    }
    if (v3_parse_string_literal_text(expr, literal, sizeof(literal))) {
        if (declared_type[0] != '\0' &&
            strcmp(declared_type, "str") != 0 &&
            strcmp(declared_type, "cstring") != 0) {
            return false;
        }
        snprintf(out->abi_class, sizeof(out->abi_class), "%s", "composite");
        snprintf(out->str_value, sizeof(out->str_value), "%s", literal);
        out->has_str_value = true;
        return true;
    }
    if (strchr(expr, '(') == NULL && strchr(expr, '[') == NULL && strchr(expr, ' ') == NULL) {
        char symbol_text[PATH_MAX];
        const V3TopLevelConstStub *existing = NULL;
        if (strchr(expr, '.') != NULL) {
            char alias_text[128];
            char const_name[128];
            char expr_copy[4096];
            char *dot;
            const char *module_path;
            snprintf(expr_copy, sizeof(expr_copy), "%s", expr);
            dot = strchr(expr_copy, '.');
            *dot = '\0';
            snprintf(alias_text, sizeof(alias_text), "%s", expr_copy);
            snprintf(const_name, sizeof(const_name), "%s", dot + 1);
            module_path = v3_alias_module_path(aliases, alias_count, alias_text);
            if (!module_path) {
                return false;
            }
            snprintf(symbol_text, sizeof(symbol_text), "%s::%s", module_path, const_name);
        } else {
            snprintf(symbol_text, sizeof(symbol_text), "%s::%s", owner_module_path, expr);
        }
        {
            int32_t index = v3_find_top_level_const_index_by_symbol(lowering, symbol_text);
            if (index < 0) {
                return false;
            }
            existing = &lowering->consts[index];
        }
        snprintf(out->abi_class, sizeof(out->abi_class), "%s", existing->abi_class);
        snprintf(out->str_value, sizeof(out->str_value), "%s", existing->str_value);
        out->has_str_value = existing->has_str_value;
        out->i64_value = existing->i64_value;
        out->bool_value = existing->bool_value;
        if (strcmp(declared_abi, "i64") == 0 && strcmp(out->abi_class, "i32") == 0) {
            snprintf(out->abi_class, sizeof(out->abi_class), "%s", "i64");
        }
        if (declared_type[0] != '\0' &&
            strcmp(out->abi_class, "composite") == 0 &&
            strcmp(declared_type, "str") != 0 &&
            strcmp(declared_type, "cstring") != 0) {
            return false;
        }
        return out->abi_class[0] != '\0';
    }
    return false;
}

static bool v3_collect_top_level_consts_from_source(const V3SystemLinkPlanStub *plan,
                                                    const char *source_path,
                                                    V3LoweringPlanStub *lowering) {
    char owner_module_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    char *owned;
    char *cursor;
    char *line;
    char *lines[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t line_count = 0U;
    size_t i;
    bool in_const_block = false;
    v3_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    owned = v3_read_file(source_path);
    if (!owned) {
        fprintf(stderr, "[cheng_v3_seed] type scan read failed: %s\n", source_path);
        return false;
    }
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            fprintf(stderr, "[cheng_v3_seed] type scan line overflow: %s\n", source_path);
            free(owned);
            return false;
        }
        lines[line_count++] = line;
    }
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    for (i = 0; i < line_count; ++i) {
        char line_copy[4096];
        char name[128];
        char type_text[128];
        char expr_text[4096];
        V3TopLevelConstStub value;
        int32_t indent;
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        indent = v3_line_indent(line_copy);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0') {
            continue;
        }
        if (indent <= 0 &&
            v3_startswith(trimmed, "const ") &&
            v3_parse_top_level_const_binding(trimmed + 6,
                                             name,
                                             sizeof(name),
                                             type_text,
                                             sizeof(type_text),
                                             expr_text,
                                             sizeof(expr_text))) {
            if (!v3_try_parse_scalar_const_literal(expr_text,
                                                   type_text,
                                                   lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   &value)) {
                continue;
            }
            if (lowering->const_count >= CHENG_V3_MAX_TOP_LEVEL_CONSTS) {
                free(owned);
                return false;
            }
            snprintf(lowering->consts[lowering->const_count].owner_module_path,
                     sizeof(lowering->consts[lowering->const_count].owner_module_path),
                     "%s",
                     owner_module_path);
            snprintf(lowering->consts[lowering->const_count].const_name,
                     sizeof(lowering->consts[lowering->const_count].const_name),
                     "%s",
                     name);
            snprintf(lowering->consts[lowering->const_count].symbol_text,
                     sizeof(lowering->consts[lowering->const_count].symbol_text),
                     "%s::%s",
                     owner_module_path,
                     name);
            snprintf(lowering->consts[lowering->const_count].type_text,
                     sizeof(lowering->consts[lowering->const_count].type_text),
                     "%s",
                     type_text[0] != '\0' ? type_text : "int32");
            snprintf(lowering->consts[lowering->const_count].abi_class,
                     sizeof(lowering->consts[lowering->const_count].abi_class),
                     "%s",
                     value.abi_class);
            snprintf(lowering->consts[lowering->const_count].str_value,
                     sizeof(lowering->consts[lowering->const_count].str_value),
                     "%s",
                     value.str_value);
            lowering->consts[lowering->const_count].has_str_value = value.has_str_value;
            lowering->consts[lowering->const_count].i64_value = value.i64_value;
            lowering->consts[lowering->const_count].bool_value = value.bool_value;
            lowering->const_count += 1U;
            continue;
        }
        if (indent <= 0 && strcmp(trimmed, "const") == 0) {
            in_const_block = true;
            continue;
        }
        if (!in_const_block) {
            continue;
        }
        if (indent <= 0) {
            in_const_block = false;
            continue;
        }
        if (!v3_parse_top_level_const_binding(trimmed,
                                              name,
                                              sizeof(name),
                                              type_text,
                                              sizeof(type_text),
                                              expr_text,
                                              sizeof(expr_text))) {
            continue;
        }
        if (!v3_try_parse_scalar_const_literal(expr_text,
                                               type_text,
                                               lowering,
                                               owner_module_path,
                                               aliases,
                                               alias_count,
                                               &value)) {
            continue;
        }
        if (lowering->const_count >= CHENG_V3_MAX_TOP_LEVEL_CONSTS) {
            free(owned);
            return false;
        }
        snprintf(lowering->consts[lowering->const_count].symbol_text,
                 sizeof(lowering->consts[lowering->const_count].symbol_text),
                 "%s::%s",
                 owner_module_path,
                 name);
        snprintf(lowering->consts[lowering->const_count].owner_module_path,
                 sizeof(lowering->consts[lowering->const_count].owner_module_path),
                 "%s",
                 owner_module_path);
        snprintf(lowering->consts[lowering->const_count].const_name,
                 sizeof(lowering->consts[lowering->const_count].const_name),
                 "%s",
                 name);
        snprintf(lowering->consts[lowering->const_count].type_text,
                 sizeof(lowering->consts[lowering->const_count].type_text),
                 "%s",
                 type_text[0] != '\0' ? type_text :
                 (strcmp(value.abi_class, "composite") == 0 && value.has_str_value ? "str" :
                 (strcmp(value.abi_class, "i64") == 0 ? "int64" :
                  (strcmp(value.abi_class, "bool") == 0 ? "bool" : "int32"))));
        snprintf(lowering->consts[lowering->const_count].abi_class,
                 sizeof(lowering->consts[lowering->const_count].abi_class),
                 "%s",
                 value.abi_class);
        snprintf(lowering->consts[lowering->const_count].str_value,
                 sizeof(lowering->consts[lowering->const_count].str_value),
                 "%s",
                 value.str_value);
        lowering->consts[lowering->const_count].has_str_value = value.has_str_value;
        lowering->consts[lowering->const_count].i64_value = value.i64_value;
        lowering->consts[lowering->const_count].bool_value = value.bool_value;
        lowering->const_count += 1U;
    }
    free(owned);
    return true;
}

static const V3TopLevelConstStub *v3_find_expr_top_level_const(const V3LoweringPlanStub *lowering,
                                                               const char *owner_module_path,
                                                               const V3ImportAlias *aliases,
                                                               size_t alias_count,
                                                               const char *expr_text) {
    char expr[4096];
    char symbol_text[PATH_MAX];
    int32_t index;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0' || strchr(expr, '(') != NULL || strchr(expr, '[') != NULL) {
        return NULL;
    }
    if (strchr(expr, '.') != NULL) {
        char alias_text[128];
        char const_name[128];
        char expr_copy[4096];
        char *dot;
        const char *module_path;
        snprintf(expr_copy, sizeof(expr_copy), "%s", expr);
        dot = strchr(expr_copy, '.');
        *dot = '\0';
        snprintf(alias_text, sizeof(alias_text), "%s", expr_copy);
        snprintf(const_name, sizeof(const_name), "%s", dot + 1);
        module_path = v3_alias_module_path(aliases, alias_count, alias_text);
        if (!module_path) {
            return NULL;
        }
        snprintf(symbol_text, sizeof(symbol_text), "%s::%s", module_path, const_name);
        index = v3_find_top_level_const_index_by_symbol(lowering, symbol_text);
        return index >= 0 ? &lowering->consts[index] : NULL;
    }
    snprintf(symbol_text, sizeof(symbol_text), "%s::%s", owner_module_path, expr);
    index = v3_find_top_level_const_index_by_symbol(lowering, symbol_text);
    if (index >= 0) {
        return &lowering->consts[index];
    }
    {
        const V3TopLevelConstStub *match = NULL;
        size_t i;
        for (i = 0; i < alias_count; ++i) {
            snprintf(symbol_text, sizeof(symbol_text), "%s::%s", aliases[i].module_path, expr);
            index = v3_find_top_level_const_index_by_symbol(lowering, symbol_text);
            if (index < 0) {
                continue;
            }
            if (match != NULL) {
                return NULL;
            }
            match = &lowering->consts[index];
        }
        if (match != NULL) {
            return match;
        }
    }
    {
        const V3TopLevelConstStub *match = NULL;
        size_t i;
        for (i = 0; i < lowering->const_count; ++i) {
            if (strcmp(lowering->consts[i].const_name, expr) != 0) {
                continue;
            }
            if (match != NULL) {
                return NULL;
            }
            match = &lowering->consts[i];
        }
        return match;
    }
}

static int32_t v3_align_up_i32(int32_t value, int32_t align) {
    if (align <= 1) {
        return value;
    }
    return (value + align - 1) / align * align;
}

static void v3_strip_var_prefix(const char *type_text, char *out, size_t cap) {
    char scratch[256];
    v3_trim_copy_text(type_text, scratch, sizeof(scratch));
    if (v3_startswith(scratch, "var ")) {
        v3_trim_copy_text(scratch + 4, out, cap);
        return;
    }
    v3_copy_text(out, cap, scratch);
}

static bool v3_eval_type_int32_expr(const V3LoweringPlanStub *lowering,
                                    const char *owner_module_path,
                                    const V3ImportAlias *aliases,
                                    size_t alias_count,
                                    const char *expr_text,
                                    int32_t *value_out) {
    char expr[256];
    char *end = NULL;
    long long parsed;
    const V3TopLevelConstStub *top_level_const;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    parsed = strtoll(expr, &end, 0);
    if (end && *v3_trim_inplace(end) == '\0') {
        *value_out = (int32_t)parsed;
        return true;
    }
    top_level_const = v3_find_expr_top_level_const(lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   expr);
    if (!top_level_const) {
        return false;
    }
    *value_out = (int32_t)top_level_const->i64_value;
    return true;
}

static bool v3_load_import_aliases_from_source_path(const char *source_path,
                                                    V3ImportAlias *aliases,
                                                    size_t *alias_count,
                                                    size_t alias_cap);
static bool v3_normalize_type_text_with_params(const V3LoweringPlanStub *lowering,
                                               const char *owner_module_path,
                                               const V3ImportAlias *aliases,
                                               size_t alias_count,
                                               const char generic_param_names[][128],
                                               const char generic_param_types[][256],
                                               size_t generic_param_count,
                                               const char *type_text,
                                               char *out,
                                               size_t cap);

static bool v3_split_trailing_type_arg_items(const char *text,
                                             char *base_out,
                                             size_t base_cap,
                                             char items[][4096],
                                             size_t *item_count,
                                             size_t item_cap) {
    char trimmed[256];
    int32_t depth = 0;
    int32_t open_index = -1;
    size_t i;
    size_t len;
    char inner[256];
    v3_trim_copy_text(text, trimmed, sizeof(trimmed));
    if (base_out && base_cap > 0U) {
        base_out[0] = '\0';
    }
    if (item_count) {
        *item_count = 0U;
    }
    if (trimmed[0] == '\0') {
        return false;
    }
    len = strlen(trimmed);
    for (i = 0; i < len; ++i) {
        if (trimmed[i] == '[') {
            if (depth == 0) {
                open_index = (int32_t)i;
            }
            depth += 1;
            continue;
        }
        if (trimmed[i] == ']') {
            if (depth == 0) {
                return false;
            }
            depth -= 1;
            continue;
        }
    }
    if (depth != 0) {
        return false;
    }
    if (open_index <= 0 || trimmed[len - 1U] != ']') {
        v3_copy_text(base_out, base_cap, trimmed);
        return true;
    }
    snprintf(base_out, base_cap, "%.*s", open_index, trimmed);
    v3_trim_copy_text(base_out, base_out, base_cap);
    if (base_out[0] == '\0') {
        return false;
    }
    snprintf(inner, sizeof(inner), "%.*s", (int)(len - (size_t)open_index - 2U), trimmed + open_index + 1);
    v3_trim_copy_text(inner, inner, sizeof(inner));
    if (inner[0] == '\0') {
        return false;
    }
    return v3_split_top_level_args(inner, items, item_count, item_cap);
}

static bool v3_parse_type_head_text(const char *text,
                                    char *base_name_out,
                                    size_t base_name_cap,
                                    char generic_param_names[][128],
                                    size_t *generic_param_count_out,
                                    size_t generic_param_cap) {
    char items[CHENG_V3_MAX_TYPE_PARAMS][4096];
    size_t item_count = 0U;
    size_t i;
    if (!v3_split_trailing_type_arg_items(text,
                                          base_name_out,
                                          base_name_cap,
                                          items,
                                          &item_count,
                                          CHENG_V3_MAX_TYPE_PARAMS)) {
        return false;
    }
    if (item_count > generic_param_cap) {
        return false;
    }
    if (generic_param_count_out) {
        *generic_param_count_out = item_count;
    }
    for (i = 0; i < item_count; ++i) {
        v3_trim_copy_text(items[i], generic_param_names[i], 128U);
        if (generic_param_names[i][0] == '\0') {
            return false;
        }
    }
    return base_name_out[0] != '\0';
}

static bool v3_parse_type_instance_text(const char *text,
                                        char *base_name_out,
                                        size_t base_name_cap,
                                        char type_args_out[][256],
                                        size_t *type_arg_count_out,
                                        size_t type_arg_cap) {
    char items[CHENG_V3_MAX_TYPE_PARAMS][4096];
    size_t item_count = 0U;
    size_t i;
    if (!v3_split_trailing_type_arg_items(text,
                                          base_name_out,
                                          base_name_cap,
                                          items,
                                          &item_count,
                                          CHENG_V3_MAX_TYPE_PARAMS)) {
        return false;
    }
    if (item_count > type_arg_cap) {
        return false;
    }
    if (type_arg_count_out) {
        *type_arg_count_out = item_count;
    }
    for (i = 0; i < item_count; ++i) {
        v3_trim_copy_text(items[i], type_args_out[i], 256U);
        if (type_args_out[i][0] == '\0') {
            return false;
        }
    }
    return base_name_out[0] != '\0';
}

static bool v3_split_qualified_type_text(const char *text,
                                         char *owner_out,
                                         size_t owner_cap,
                                         char *type_name_out,
                                         size_t type_name_cap) {
    char trimmed[PATH_MAX];
    int32_t depth = 0;
    int32_t sep_index = -1;
    size_t i;
    size_t len;
    v3_trim_copy_text(text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    for (i = 0; i < len; ++i) {
        if (trimmed[i] == '[') {
            depth += 1;
            continue;
        }
        if (trimmed[i] == ']') {
            if (depth == 0) {
                return false;
            }
            depth -= 1;
            continue;
        }
        if (depth == 0 && i + 1U < len && trimmed[i] == ':' && trimmed[i + 1U] == ':') {
            sep_index = (int32_t)i;
            i += 1U;
        }
    }
    if (depth != 0 || sep_index <= 0) {
        return false;
    }
    snprintf(owner_out, owner_cap, "%.*s", sep_index, trimmed);
    snprintf(type_name_out, type_name_cap, "%s", trimmed + sep_index + 2);
    v3_trim_copy_text(owner_out, owner_out, owner_cap);
    v3_trim_copy_text(type_name_out, type_name_out, type_name_cap);
    return owner_out[0] != '\0' && type_name_out[0] != '\0';
}

static void v3_write_normalized_type_instance_text(const char *owner_module_path,
                                                   const char *type_name,
                                                   char type_args[][256],
                                                   size_t type_arg_count,
                                                   bool ref_object,
                                                   char *out,
                                                   size_t cap) {
    size_t i;
    snprintf(out, cap, "%s%s::%s", ref_object ? "ref@" : "", owner_module_path, type_name);
    for (i = 0; i < type_arg_count; ++i) {
        size_t used = strlen(out);
        if (used + 2U >= cap) {
            return;
        }
        snprintf(out + used, cap - used, "%s%s", i == 0U ? "[" : ", ", type_args[i]);
    }
    if (type_arg_count > 0U) {
        size_t used = strlen(out);
        if (used + 1U < cap) {
            snprintf(out + used, cap - used, "%s", "]");
        }
    }
}

static void v3_write_type_def_instance_normalized(const V3TypeDefStub *type_def,
                                                  char type_args[][256],
                                                  size_t type_arg_count,
                                                  char *out,
                                                  size_t cap) {
    if (cap == 0U) {
        return;
    }
    if (type_def == NULL) {
        out[0] = '\0';
        return;
    }
    v3_write_normalized_type_instance_text(type_def->owner_module_path,
                                           type_def->type_name,
                                           type_args,
                                           type_arg_count,
                                           type_def->ref_object,
                                           out,
                                           cap);
}

static const char *v3_find_generic_type_param(const char generic_param_names[][128],
                                              const char generic_param_types[][256],
                                              size_t generic_param_count,
                                              const char *type_name) {
    size_t i;
    for (i = 0; i < generic_param_count; ++i) {
        if (strcmp(generic_param_names[i], type_name) == 0) {
            return generic_param_types[i];
        }
    }
    return NULL;
}

static int32_t v3_find_type_def_index_by_symbol(const V3LoweringPlanStub *lowering,
                                                const char *owner_module_path,
                                                const char *type_name);
static bool v3_parse_fixed_array_type(const char *type_text,
                                      char *elem_type_out,
                                      size_t elem_cap,
                                      int32_t *len_out);
static bool v3_normalize_type_text(const V3LoweringPlanStub *lowering,
                                   const char *owner_module_path,
                                   const V3ImportAlias *aliases,
                                   size_t alias_count,
                                   const char *type_text,
                                   char *out,
                                   size_t cap) {
    char generic_param_names[CHENG_V3_MAX_TYPE_PARAMS][128];
    char generic_param_types[CHENG_V3_MAX_TYPE_PARAMS][256];
    memset(generic_param_names, 0, sizeof(generic_param_names));
    memset(generic_param_types, 0, sizeof(generic_param_types));
    return v3_normalize_type_text_with_params(lowering,
                                              owner_module_path,
                                              aliases,
                                              alias_count,
                                              generic_param_names,
                                              generic_param_types,
                                              0U,
                                              type_text,
                                              out,
                                              cap);
}

static bool v3_normalize_type_text_with_params(const V3LoweringPlanStub *lowering,
                                               const char *owner_module_path,
                                               const V3ImportAlias *aliases,
                                               size_t alias_count,
                                               const char generic_param_names[][128],
                                               const char generic_param_types[][256],
                                               size_t generic_param_count,
                                               const char *type_text,
                                               char *out,
                                               size_t cap) {
    char trimmed[256];
    char inner[256];
    char normalized_inner[256];
    char base_name[128];
    char raw_type_args[CHENG_V3_MAX_TYPE_PARAMS][256];
    char normalized_type_args[CHENG_V3_MAX_TYPE_PARAMS][256];
    size_t raw_type_arg_count = 0U;
    int32_t fixed_len = 0;
    int32_t pointer_depth = 0;
    size_t i;
    int32_t type_index = -1;
    const char *generic_type_arg;
    v3_strip_var_prefix(type_text, trimmed, sizeof(trimmed));
    if (trimmed[0] == '\0') {
        return false;
    }
    generic_type_arg = v3_find_generic_type_param(generic_param_names,
                                                  generic_param_types,
                                                  generic_param_count,
                                                  trimmed);
    if (generic_type_arg) {
        v3_copy_text(out, cap, generic_type_arg);
        return true;
    }
    if (v3_is_internal_ref_type(trimmed)) {
        snprintf(out, cap, "%s", trimmed);
        return true;
    }
    if (v3_startswith(trimmed, "fn ") || v3_startswith(trimmed, "fn(")) {
        v3_copy_text(out, cap, trimmed);
        return true;
    }
    if (strcmp(trimmed, "void") == 0 ||
        strcmp(trimmed, "int8") == 0 ||
        strcmp(trimmed, "uint8") == 0 ||
        strcmp(trimmed, "int16") == 0 ||
        strcmp(trimmed, "uint16") == 0 ||
        strcmp(trimmed, "int32") == 0 ||
        strcmp(trimmed, "int") == 0 ||
        strcmp(trimmed, "uint32") == 0 ||
        strcmp(trimmed, "char") == 0 ||
        strcmp(trimmed, "int64") == 0 ||
        strcmp(trimmed, "uint64") == 0 ||
        strcmp(trimmed, "float") == 0 ||
        strcmp(trimmed, "float32") == 0 ||
        strcmp(trimmed, "float64") == 0 ||
        strcmp(trimmed, "bool") == 0 ||
        strcmp(trimmed, "ptr") == 0 ||
        strcmp(trimmed, "cstring") == 0 ||
        strcmp(trimmed, "str") == 0 ||
        strcmp(trimmed, "Bytes") == 0) {
        v3_copy_text(out, cap, trimmed);
        return true;
    }
    pointer_depth = v3_type_text_pointer_depth(trimmed, inner, sizeof(inner));
    if (pointer_depth > 0) {
        if (!v3_normalize_type_text_with_params(lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                generic_param_names,
                                                generic_param_types,
                                                generic_param_count,
                                                inner,
                                                normalized_inner,
                                                sizeof(normalized_inner))) {
            return false;
        }
        snprintf(out, cap, "%s", normalized_inner);
        for (i = 0; i < (size_t)pointer_depth; ++i) {
            size_t used = strlen(out);
            if (used + 2U >= cap) {
                return false;
            }
            snprintf(out + used, cap - used, " *");
        }
        return true;
    }
    if (v3_parse_fixed_array_type(trimmed, inner, sizeof(inner), &fixed_len)) {
        if (!v3_normalize_type_text_with_params(lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                generic_param_names,
                                                generic_param_types,
                                                generic_param_count,
                                                inner,
                                                normalized_inner,
                                                sizeof(normalized_inner))) {
            return false;
        }
        snprintf(out, cap, "%s[%d]", normalized_inner, fixed_len);
        return true;
    }
    if (v3_startswith(trimmed, "Result[") && trimmed[strlen(trimmed) - 1U] == ']') {
        snprintf(inner, sizeof(inner), "%.*s", (int)(strlen(trimmed) - 8U), trimmed + 7);
        if (!v3_normalize_type_text_with_params(lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                generic_param_names,
                                                generic_param_types,
                                                generic_param_count,
                                                inner,
                                                normalized_inner,
                                                sizeof(normalized_inner))) {
            return false;
        }
        snprintf(out, cap, "Result[%s]", normalized_inner);
        return true;
    }
    if (strlen(trimmed) > 2U && strcmp(trimmed + strlen(trimmed) - 2U, "[]") == 0) {
        snprintf(inner, sizeof(inner), "%.*s", (int)(strlen(trimmed) - 2U), trimmed);
        if (!v3_normalize_type_text_with_params(lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                generic_param_names,
                                                generic_param_types,
                                                generic_param_count,
                                                inner,
                                                normalized_inner,
                                                sizeof(normalized_inner))) {
            return false;
        }
        snprintf(out, cap, "%s[]", normalized_inner);
        return true;
    }
    if (!v3_parse_type_instance_text(trimmed,
                                     base_name,
                                     sizeof(base_name),
                                     raw_type_args,
                                     &raw_type_arg_count,
                                     CHENG_V3_MAX_TYPE_PARAMS)) {
        return false;
    }
    if (raw_type_arg_count > 0U) {
        char lookup_module[PATH_MAX];
        char lookup_name[128];
        const char *resolved_module_path = NULL;
        lookup_name[0] = '\0';
        for (i = 0; i < raw_type_arg_count; ++i) {
            if (!v3_normalize_type_text_with_params(lowering,
                                                    owner_module_path,
                                                    aliases,
                                                    alias_count,
                                                    generic_param_names,
                                                    generic_param_types,
                                                    generic_param_count,
                                                    raw_type_args[i],
                                                    normalized_type_args[i],
                                                    sizeof(normalized_type_args[i]))) {
                return false;
            }
        }
        if (v3_split_qualified_type_text(trimmed,
                                         lookup_module,
                                         sizeof(lookup_module),
                                         lookup_name,
                                         sizeof(lookup_name))) {
            type_index = v3_find_type_def_index_by_symbol(lowering, lookup_module, lookup_name);
            resolved_module_path = lookup_module;
            if (!v3_parse_type_instance_text(lookup_name,
                                             lookup_name,
                                             sizeof(lookup_name),
                                             raw_type_args,
                                             &raw_type_arg_count,
                                             CHENG_V3_MAX_TYPE_PARAMS)) {
                return false;
            }
        } else if (strchr(trimmed, '.') != NULL) {
            char alias_text[128];
            char *dot;
            char copy[256];
            snprintf(copy, sizeof(copy), "%s", trimmed);
            dot = strchr(copy, '.');
            *dot = '\0';
            snprintf(alias_text, sizeof(alias_text), "%s", copy);
            snprintf(lookup_name, sizeof(lookup_name), "%s", dot + 1);
            resolved_module_path = v3_alias_module_path(aliases, alias_count, alias_text);
            if (!resolved_module_path) {
                return false;
            }
            type_index = v3_find_type_def_index_by_symbol(lowering, resolved_module_path, lookup_name);
            if (!v3_parse_type_instance_text(lookup_name,
                                             lookup_name,
                                             sizeof(lookup_name),
                                             raw_type_args,
                                             &raw_type_arg_count,
                                             CHENG_V3_MAX_TYPE_PARAMS)) {
                return false;
            }
        } else {
            snprintf(lookup_name, sizeof(lookup_name), "%s", base_name);
            type_index = v3_find_type_def_index_by_symbol(lowering, owner_module_path, trimmed);
            resolved_module_path = owner_module_path;
            if (type_index < 0) {
                for (i = 0; i < alias_count; ++i) {
                    type_index = v3_find_type_def_index_by_symbol(lowering, aliases[i].module_path, trimmed);
                    if (type_index >= 0) {
                        resolved_module_path = aliases[i].module_path;
                        break;
                    }
                }
            }
        }
        if (type_index < 0 &&
            raw_type_arg_count == 1U &&
            v3_eval_type_int32_expr(lowering,
                                    owner_module_path,
                                    aliases,
                                    alias_count,
                                    raw_type_args[0],
                                    &fixed_len)) {
            if (!v3_normalize_type_text_with_params(lowering,
                                                    owner_module_path,
                                                    aliases,
                                                    alias_count,
                                                    generic_param_names,
                                                    generic_param_types,
                                                    generic_param_count,
                                                    base_name,
                                                    normalized_inner,
                                                    sizeof(normalized_inner))) {
                return false;
            }
            snprintf(out, cap, "%s[%d]", normalized_inner, fixed_len);
            return true;
        }
        if (type_index >= 0) {
            if (lowering->type_defs[type_index].kind == V3_TYPE_DEF_ALIAS) {
                if (lowering->type_defs[type_index].generic_param_count > 0U) {
                    V3ImportAlias type_aliases[CHENG_V3_MAX_IMPORT_ALIASES];
                    size_t type_alias_count = 0U;
                    if (!v3_load_import_aliases_from_source_path(lowering->type_defs[type_index].source_path,
                                                                 type_aliases,
                                                                 &type_alias_count,
                                                                 CHENG_V3_MAX_IMPORT_ALIASES)) {
                        return false;
                    }
                    return v3_normalize_type_text_with_params(lowering,
                                                              lowering->type_defs[type_index].owner_module_path,
                                                              type_aliases,
                                                              type_alias_count,
                                                              lowering->type_defs[type_index].generic_param_names,
                                                              normalized_type_args,
                                                              raw_type_arg_count,
                                                              lowering->type_defs[type_index].alias_target,
                                                              out,
                                                              cap);
                }
                return v3_normalize_type_text_with_params(lowering,
                                                          lowering->type_defs[type_index].owner_module_path,
                                                          aliases,
                                                          alias_count,
                                                          generic_param_names,
                                                          generic_param_types,
                                                          generic_param_count,
                                                          lowering->type_defs[type_index].alias_target,
                                                          out,
                                                          cap);
            }
            v3_write_type_def_instance_normalized(&lowering->type_defs[type_index],
                                                  normalized_type_args,
                                                  raw_type_arg_count,
                                                  out,
                                                  cap);
            return true;
        }
        if (!resolved_module_path) {
            resolved_module_path = owner_module_path;
        }
        v3_write_normalized_type_instance_text(resolved_module_path,
                                               lookup_name[0] != '\0' ? lookup_name : base_name,
                                               normalized_type_args,
                                               raw_type_arg_count,
                                               false,
                                               out,
                                               cap);
        return true;
    }
    if (v3_split_qualified_type_text(trimmed,
                                     inner,
                                     sizeof(inner),
                                     base_name,
                                     sizeof(base_name))) {
        type_index = v3_find_type_def_index_by_symbol(lowering, inner, base_name);
        if (type_index >= 0) {
            if (lowering->type_defs[type_index].kind == V3_TYPE_DEF_ALIAS) {
                return v3_normalize_type_text_with_params(lowering,
                                                          inner,
                                                          aliases,
                                                          alias_count,
                                                          generic_param_names,
                                                          generic_param_types,
                                                          generic_param_count,
                                                          lowering->type_defs[type_index].alias_target,
                                                          out,
                                                          cap);
            }
            v3_write_type_def_normalized(&lowering->type_defs[type_index], out, cap);
            return true;
        }
        v3_copy_text(out, cap, trimmed);
        return true;
    }
    if (strchr(trimmed, '.') != NULL) {
        char alias_text[128];
        char type_name[128];
        char copy[256];
        char *dot;
        const char *module_path;
        snprintf(copy, sizeof(copy), "%s", trimmed);
        dot = strchr(copy, '.');
        *dot = '\0';
        snprintf(alias_text, sizeof(alias_text), "%s", copy);
        snprintf(type_name, sizeof(type_name), "%s", dot + 1);
        module_path = v3_alias_module_path(aliases, alias_count, alias_text);
        if (!module_path) {
            return false;
        }
        type_index = v3_find_type_def_index_by_symbol(lowering, module_path, type_name);
        if (type_index >= 0) {
            if (lowering->type_defs[type_index].kind == V3_TYPE_DEF_ALIAS) {
                return v3_normalize_type_text_with_params(lowering,
                                                          module_path,
                                                          aliases,
                                                          alias_count,
                                                          generic_param_names,
                                                          generic_param_types,
                                                          generic_param_count,
                                                          lowering->type_defs[type_index].alias_target,
                                                          out,
                                                          cap);
            }
            v3_write_type_def_normalized(&lowering->type_defs[type_index], out, cap);
            return true;
        }
        snprintf(out, cap, "%s::%s", module_path, type_name);
        return true;
    }
    type_index = v3_find_type_def_index_by_symbol(lowering, owner_module_path, trimmed);
    if (type_index >= 0) {
        if (lowering->type_defs[type_index].kind == V3_TYPE_DEF_ALIAS) {
            return v3_normalize_type_text_with_params(lowering,
                                                      owner_module_path,
                                                      aliases,
                                                      alias_count,
                                                      generic_param_names,
                                                      generic_param_types,
                                                      generic_param_count,
                                                      lowering->type_defs[type_index].alias_target,
                                                      out,
                                                      cap);
        }
        v3_write_type_def_normalized(&lowering->type_defs[type_index], out, cap);
        return true;
    }
    for (i = 0; i < alias_count; ++i) {
        type_index = v3_find_type_def_index_by_symbol(lowering, aliases[i].module_path, trimmed);
        if (type_index >= 0) {
            if (lowering->type_defs[type_index].kind == V3_TYPE_DEF_ALIAS) {
                return v3_normalize_type_text_with_params(lowering,
                                                          aliases[i].module_path,
                                                          aliases,
                                                          alias_count,
                                                          generic_param_names,
                                                          generic_param_types,
                                                          generic_param_count,
                                                          lowering->type_defs[type_index].alias_target,
                                                          out,
                                                          cap);
            }
            v3_write_type_def_normalized(&lowering->type_defs[type_index], out, cap);
            return true;
        }
    }
    snprintf(out, cap, "%s::%s", owner_module_path, trimmed);
    return true;
}

static bool v3_resolve_pointer_pointee_type(const V3LoweringPlanStub *lowering,
                                            const char *owner_module_path,
                                            const V3ImportAlias *aliases,
                                            size_t alias_count,
                                            const char *pointer_type_text,
                                            char *pointee_type_out,
                                            size_t pointee_type_cap,
                                            char *pointee_abi_out,
                                            size_t pointee_abi_cap) {
    char normalized_pointer[256];
    char pointee_type[256];
    if (!v3_normalize_type_text(lowering,
                                owner_module_path,
                                aliases,
                                alias_count,
                                pointer_type_text,
                                normalized_pointer,
                                sizeof(normalized_pointer))) {
        return false;
    }
    if (strcmp(normalized_pointer, "ptr") == 0 ||
        strcmp(normalized_pointer, "cstring") == 0) {
        snprintf(pointee_type_out, pointee_type_cap, "%s", "char");
        snprintf(pointee_abi_out, pointee_abi_cap, "%s", "i32");
        return true;
    }
    if (!v3_type_text_strip_one_pointer_suffix(normalized_pointer, pointee_type, sizeof(pointee_type))) {
        return false;
    }
    snprintf(pointee_type_out, pointee_type_cap, "%s", pointee_type);
    snprintf(pointee_abi_out, pointee_abi_cap, "%s", v3_type_abi_class(pointee_type));
    return true;
}

static bool v3_resolve_scalar_or_pointer_cast_target(const V3LoweringPlanStub *lowering,
                                                     const char *owner_module_path,
                                                     const V3ImportAlias *aliases,
                                                     size_t alias_count,
                                                     const char *callee_text,
                                                     char *target_type_out,
                                                     size_t target_type_cap,
                                                     char *target_abi_out,
                                                     size_t target_abi_cap) {
    char normalized_type[256];
    const char *target_abi;
    if (!v3_normalize_type_text(lowering,
                                owner_module_path,
                                aliases,
                                alias_count,
                                callee_text,
                                normalized_type,
                                sizeof(normalized_type))) {
        return false;
    }
    target_abi = v3_type_abi_class(normalized_type);
    if (!v3_abi_class_scalar_or_ptr(target_abi)) {
        return false;
    }
    snprintf(target_type_out, target_type_cap, "%s", normalized_type);
    snprintf(target_abi_out, target_abi_cap, "%s", target_abi);
    return true;
}

static int32_t v3_find_type_def_index_by_symbol(const V3LoweringPlanStub *lowering,
                                                const char *owner_module_path,
                                                const char *type_name) {
    char lookup_base[128];
    char lookup_args[CHENG_V3_MAX_TYPE_PARAMS][256];
    size_t lookup_arg_count = 0U;
    size_t i;
    if (!v3_parse_type_instance_text(type_name,
                                     lookup_base,
                                     sizeof(lookup_base),
                                     lookup_args,
                                     &lookup_arg_count,
                                     CHENG_V3_MAX_TYPE_PARAMS)) {
        return -1;
    }
    for (i = 0; i < lowering->type_def_count; ++i) {
        if (strcmp(lowering->type_defs[i].owner_module_path, owner_module_path) == 0 &&
            lowering->type_defs[i].generic_param_count == lookup_arg_count &&
            strcmp(lowering->type_defs[i].type_name, lookup_base) == 0) {
            return (int32_t)i;
        }
    }
    for (i = 0; i < lowering->type_def_count; ++i) {
        if (strcmp(lowering->type_defs[i].owner_module_path, owner_module_path) == 0 &&
            lowering->type_defs[i].generic_param_count == lookup_arg_count &&
            v3_text_case_equal(lowering->type_defs[i].type_name, lookup_base)) {
            return (int32_t)i;
        }
    }
    return -1;
}

static bool v3_collect_type_defs_from_source(const V3SystemLinkPlanStub *plan,
                                             const char *source_path,
                                             V3LoweringPlanStub *lowering) {
    char owner_module_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    char *owned;
    char *cursor;
    char *line;
    char *lines[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t line_count = 0U;
    size_t i = 0U;
    bool in_type_block = false;
    v3_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    owned = v3_read_file(source_path);
    if (!owned) {
        return false;
    }
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(owned);
            return false;
        }
        lines[line_count++] = line;
    }
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    while (i < line_count) {
        char line_copy[4096];
        char head_text[256];
        char *trimmed;
        int32_t indent;
        int32_t header_indent = 0;
        bool saw_type_head = false;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        indent = v3_line_indent(line_copy);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            i += 1U;
            continue;
        }
        if (indent == 0 && strcmp(trimmed, "type") == 0) {
            in_type_block = true;
            i += 1U;
            continue;
        }
        if (indent == 0 && v3_startswith(trimmed, "type ")) {
            snprintf(head_text, sizeof(head_text), "%s", trimmed + 5);
            v3_trim_copy_text(head_text, head_text, sizeof(head_text));
            header_indent = 0;
            saw_type_head = strchr(head_text, '=') != NULL;
        } else if (in_type_block && indent > 0 && strchr(trimmed, '=') != NULL) {
            snprintf(head_text, sizeof(head_text), "%s", trimmed);
            header_indent = indent;
            saw_type_head = true;
        }
        if (!saw_type_head && !in_type_block) {
            i += 1U;
            continue;
        }
        if (!saw_type_head && indent == 0) {
            in_type_block = false;
            continue;
        }
        if (saw_type_head) {
            char name[128];
            char type_name[128];
            char generic_param_names[CHENG_V3_MAX_TYPE_PARAMS][128];
            size_t generic_param_count = 0U;
            char rhs[256];
            char normalized_rhs[256];
            char *eq = strchr(head_text, '=');
            V3TypeDefStub *type_def;
            *eq = '\0';
            snprintf(name, sizeof(name), "%s", head_text);
            snprintf(rhs, sizeof(rhs), "%s", eq + 1);
            v3_trim_copy_text(name, name, sizeof(name));
            v3_trim_copy_text(rhs, rhs, sizeof(rhs));
            if (!v3_parse_type_head_text(name,
                                         type_name,
                                         sizeof(type_name),
                                         generic_param_names,
                                         &generic_param_count,
                                         CHENG_V3_MAX_TYPE_PARAMS) ||
                type_name[0] == '\0' ||
                v3_find_type_def_index_by_symbol(lowering, owner_module_path, name) >= 0 ||
                lowering->type_def_count >= CHENG_V3_MAX_TYPE_DEFS) {
                fprintf(stderr, "[cheng_v3_seed] invalid or duplicate type head: %s line=%zu text=%s\n",
                        source_path,
                        i + 1U,
                        lines[i]);
                free(owned);
                return false;
            }
            type_def = &lowering->type_defs[lowering->type_def_count];
            memset(type_def, 0, sizeof(*type_def));
            snprintf(type_def->source_path, sizeof(type_def->source_path), "%s", source_path);
            snprintf(type_def->owner_module_path, sizeof(type_def->owner_module_path), "%s", owner_module_path);
            snprintf(type_def->type_name, sizeof(type_def->type_name), "%s", type_name);
            type_def->generic_param_count = generic_param_count;
            memcpy(type_def->generic_param_names,
                   generic_param_names,
                   sizeof(type_def->generic_param_names));
            if (rhs[0] != '\0') {
                if (strcmp(rhs, "enum") == 0) {
                    int32_t enum_ordinal = 0;
                    type_def->kind = V3_TYPE_DEF_ALIAS;
                    snprintf(type_def->alias_target, sizeof(type_def->alias_target), "%s", "int32");
                    lowering->type_def_count += 1U;
                    i += 1U;
                    while (i < line_count) {
                        char enum_line_copy[4096];
                        char *enum_trimmed;
                        int32_t enum_indent;
                        char enum_member_name[128];
                        snprintf(enum_line_copy, sizeof(enum_line_copy), "%s", lines[i]);
                        enum_indent = v3_line_indent(enum_line_copy);
                        enum_trimmed = v3_trim_inplace(enum_line_copy);
                        if (*enum_trimmed == '\0') {
                            i += 1U;
                            continue;
                        }
                        if (*enum_trimmed == '#') {
                            i += 1U;
                            continue;
                        }
                        if (enum_indent <= header_indent) {
                            break;
                        }
                        snprintf(enum_member_name, sizeof(enum_member_name), "%s", enum_trimmed);
                        v3_trim_copy_text(enum_member_name, enum_member_name, sizeof(enum_member_name));
                        if (enum_member_name[0] != '\0') {
                            size_t member_len = strcspn(enum_member_name, " \t#=");
                            enum_member_name[member_len] = '\0';
                        }
                        if (enum_member_name[0] != '\0') {
                            if (lowering->const_count >= CHENG_V3_MAX_TOP_LEVEL_CONSTS) {
                                free(owned);
                                return false;
                            }
                            snprintf(lowering->consts[lowering->const_count].symbol_text,
                                     sizeof(lowering->consts[lowering->const_count].symbol_text),
                                     "%s::%s",
                                     owner_module_path,
                                     enum_member_name);
                            snprintf(lowering->consts[lowering->const_count].owner_module_path,
                                     sizeof(lowering->consts[lowering->const_count].owner_module_path),
                                     "%s",
                                     owner_module_path);
                            snprintf(lowering->consts[lowering->const_count].const_name,
                                     sizeof(lowering->consts[lowering->const_count].const_name),
                                     "%s",
                                     enum_member_name);
                            snprintf(lowering->consts[lowering->const_count].type_text,
                                     sizeof(lowering->consts[lowering->const_count].type_text),
                                     "%s",
                                     name);
                            snprintf(lowering->consts[lowering->const_count].abi_class,
                                     sizeof(lowering->consts[lowering->const_count].abi_class),
                                     "%s",
                                     "i32");
                            lowering->consts[lowering->const_count].i64_value = (int64_t)enum_ordinal;
                            lowering->consts[lowering->const_count].bool_value = enum_ordinal != 0;
                            lowering->const_count += 1U;
                            enum_ordinal += 1;
                        }
                        i += 1U;
                    }
                    continue;
                }
                if (strcmp(rhs, "object") == 0) {
                    rhs[0] = '\0';
                } else if (strcmp(rhs, "ref") == 0 || strcmp(rhs, "ref object") == 0) {
                    type_def->ref_object = true;
                    rhs[0] = '\0';
                }
            }
            if (rhs[0] != '\0') {
                type_def->kind = V3_TYPE_DEF_ALIAS;
                if (type_def->generic_param_count > 0U) {
                    snprintf(type_def->alias_target, sizeof(type_def->alias_target), "%s", rhs);
                } else {
                    if (!v3_normalize_type_text(lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                rhs,
                                                normalized_rhs,
                                                sizeof(normalized_rhs))) {
                        fprintf(stderr, "[cheng_v3_seed] type alias normalize failed: %s line=%zu text=%s\n",
                                source_path,
                                i + 1U,
                                lines[i]);
                        free(owned);
                        return false;
                    }
                    snprintf(type_def->alias_target, sizeof(type_def->alias_target), "%s", normalized_rhs);
                }
                lowering->type_def_count += 1U;
                i += 1U;
                continue;
            }
            type_def->kind = V3_TYPE_DEF_RECORD;
            i += 1U;
            while (i < line_count) {
                char field_line_copy[4096];
                char *field_trimmed;
                int32_t field_indent;
                char *colon;
                snprintf(field_line_copy, sizeof(field_line_copy), "%s", lines[i]);
                field_indent = v3_line_indent(field_line_copy);
                field_trimmed = v3_trim_inplace(field_line_copy);
                if (*field_trimmed == '\0' || *field_trimmed == '#') {
                    i += 1U;
                    continue;
                }
                if (field_indent <= header_indent) {
                    break;
                }
                colon = strchr(field_trimmed, ':');
                if (!colon || type_def->field_count >= CHENG_V3_MAX_TYPE_FIELDS) {
                    fprintf(stderr, "[cheng_v3_seed] invalid type field: %s line=%zu text=%s\n",
                            source_path,
                            i + 1U,
                            lines[i]);
                    free(owned);
                    return false;
                }
                *colon = '\0';
                snprintf(type_def->fields[type_def->field_count].name,
                         sizeof(type_def->fields[type_def->field_count].name),
                         "%s",
                         v3_trim_inplace(field_trimmed));
                if (type_def->fields[type_def->field_count].name[0] == '\0') {
                    fprintf(stderr, "[cheng_v3_seed] empty type field name: %s line=%zu\n",
                            source_path,
                            i + 1U);
                    free(owned);
                    return false;
                }
                if (type_def->generic_param_count > 0U) {
                    v3_trim_copy_text(colon + 1,
                                      type_def->fields[type_def->field_count].type_text,
                                      sizeof(type_def->fields[type_def->field_count].type_text));
                } else if (!v3_normalize_type_text(lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   colon + 1,
                                                   type_def->fields[type_def->field_count].type_text,
                                                   sizeof(type_def->fields[type_def->field_count].type_text))) {
                    fprintf(stderr, "[cheng_v3_seed] type field normalize failed: %s line=%zu text=%s\n",
                            source_path,
                            i + 1U,
                            lines[i]);
                    free(owned);
                    return false;
                }
                type_def->field_count += 1U;
                i += 1U;
            }
            lowering->type_def_count += 1U;
            continue;
        }
        fprintf(stderr, "[cheng_v3_seed] malformed type block: %s line=%zu text=%s\n",
                source_path,
                i + 1U,
                lines[i]);
        free(owned);
        return false;
    }
    free(owned);
    return true;
}

static bool v3_refresh_type_defs_from_source(const V3SystemLinkPlanStub *plan,
                                             const char *source_path,
                                             V3LoweringPlanStub *lowering) {
    char owner_module_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    char *owned;
    char *cursor;
    char *line;
    char *lines[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t line_count = 0U;
    size_t i = 0U;
    bool in_type_block = false;
    v3_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    owned = v3_read_file(source_path);
    if (!owned) {
        return false;
    }
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(owned);
            return false;
        }
        lines[line_count++] = line;
    }
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    while (i < line_count) {
        char line_copy[4096];
        char head_text[256];
        char *trimmed;
        int32_t indent;
        int32_t header_indent = 0;
        bool saw_type_head = false;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        indent = v3_line_indent(line_copy);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            i += 1U;
            continue;
        }
        if (indent == 0 && strcmp(trimmed, "type") == 0) {
            in_type_block = true;
            i += 1U;
            continue;
        }
        if (indent == 0 && v3_startswith(trimmed, "type ")) {
            snprintf(head_text, sizeof(head_text), "%s", trimmed + 5);
            v3_trim_copy_text(head_text, head_text, sizeof(head_text));
            header_indent = 0;
            saw_type_head = strchr(head_text, '=') != NULL;
        } else if (in_type_block && indent > 0 && strchr(trimmed, '=') != NULL) {
            snprintf(head_text, sizeof(head_text), "%s", trimmed);
            header_indent = indent;
            saw_type_head = true;
        }
        if (!saw_type_head && !in_type_block) {
            i += 1U;
            continue;
        }
        if (!saw_type_head && indent == 0) {
            in_type_block = false;
            continue;
        }
        if (saw_type_head) {
            char name[128];
            char type_name[128];
            char generic_param_names[CHENG_V3_MAX_TYPE_PARAMS][128];
            size_t generic_param_count = 0U;
            char rhs[256];
            char normalized_rhs[256];
            char *eq = strchr(head_text, '=');
            int32_t type_index;
            V3TypeDefStub *type_def;
            *eq = '\0';
            snprintf(name, sizeof(name), "%s", head_text);
            snprintf(rhs, sizeof(rhs), "%s", eq + 1);
            v3_trim_copy_text(name, name, sizeof(name));
            v3_trim_copy_text(rhs, rhs, sizeof(rhs));
            if (!v3_parse_type_head_text(name,
                                         type_name,
                                         sizeof(type_name),
                                         generic_param_names,
                                         &generic_param_count,
                                         CHENG_V3_MAX_TYPE_PARAMS)) {
                fprintf(stderr,
                        "[cheng_v3_seed] refresh type head parse failed source=%s type=%s line=%zu\n",
                        source_path,
                        name,
                        i + 1U);
                free(owned);
                return false;
            }
            type_index = v3_find_type_def_index_by_symbol(lowering, owner_module_path, name);
            if (type_index < 0) {
                fprintf(stderr,
                        "[cheng_v3_seed] refresh type def missing source=%s type=%s line=%zu\n",
                        source_path,
                        name,
                        i + 1U);
                free(owned);
                return false;
            }
            type_def = &lowering->type_defs[type_index];
            snprintf(type_def->source_path, sizeof(type_def->source_path), "%s", source_path);
            snprintf(type_def->type_name, sizeof(type_def->type_name), "%s", type_name);
            type_def->generic_param_count = generic_param_count;
            memcpy(type_def->generic_param_names,
                   generic_param_names,
                   sizeof(type_def->generic_param_names));
            type_def->ref_object = false;
            if (rhs[0] != '\0') {
                if (strcmp(rhs, "enum") == 0) {
                    i += 1U;
                    while (i < line_count) {
                        char enum_line_copy[4096];
                        char *enum_trimmed;
                        int32_t enum_indent;
                        snprintf(enum_line_copy, sizeof(enum_line_copy), "%s", lines[i]);
                        enum_indent = v3_line_indent(enum_line_copy);
                        enum_trimmed = v3_trim_inplace(enum_line_copy);
                        if (*enum_trimmed == '\0' || *enum_trimmed == '#') {
                            i += 1U;
                            continue;
                        }
                        if (enum_indent <= header_indent) {
                            break;
                        }
                        i += 1U;
                    }
                    continue;
                }
                if (strcmp(rhs, "object") == 0) {
                    rhs[0] = '\0';
                } else if (strcmp(rhs, "ref") == 0 || strcmp(rhs, "ref object") == 0) {
                    type_def->ref_object = true;
                    rhs[0] = '\0';
                }
            }
            if (rhs[0] != '\0') {
                type_def->kind = V3_TYPE_DEF_ALIAS;
                if (type_def->generic_param_count > 0U) {
                    snprintf(type_def->alias_target, sizeof(type_def->alias_target), "%s", rhs);
                } else {
                    if (!v3_normalize_type_text(lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                rhs,
                                                normalized_rhs,
                                                sizeof(normalized_rhs))) {
                        fprintf(stderr,
                                "[cheng_v3_seed] refresh type alias normalize failed: %s line=%zu text=%s\n",
                                source_path,
                                i + 1U,
                                lines[i]);
                        free(owned);
                        return false;
                    }
                    snprintf(type_def->alias_target, sizeof(type_def->alias_target), "%s", normalized_rhs);
                }
                i += 1U;
                continue;
            }
            type_def->kind = V3_TYPE_DEF_RECORD;
            type_def->field_count = 0U;
            i += 1U;
            while (i < line_count) {
                char field_line_copy[4096];
                char *field_trimmed;
                int32_t field_indent;
                char *colon;
                snprintf(field_line_copy, sizeof(field_line_copy), "%s", lines[i]);
                field_indent = v3_line_indent(field_line_copy);
                field_trimmed = v3_trim_inplace(field_line_copy);
                if (*field_trimmed == '\0' || *field_trimmed == '#') {
                    i += 1U;
                    continue;
                }
                if (field_indent <= header_indent) {
                    break;
                }
                colon = strchr(field_trimmed, ':');
                if (!colon || type_def->field_count >= CHENG_V3_MAX_TYPE_FIELDS) {
                    fprintf(stderr,
                            "[cheng_v3_seed] refresh invalid type field: %s line=%zu text=%s\n",
                            source_path,
                            i + 1U,
                            lines[i]);
                    free(owned);
                    return false;
                }
                *colon = '\0';
                snprintf(type_def->fields[type_def->field_count].name,
                         sizeof(type_def->fields[type_def->field_count].name),
                         "%s",
                         v3_trim_inplace(field_trimmed));
                if (type_def->fields[type_def->field_count].name[0] == '\0') {
                    fprintf(stderr,
                            "[cheng_v3_seed] refresh empty type field name: %s line=%zu\n",
                            source_path,
                            i + 1U);
                    free(owned);
                    return false;
                }
                if (type_def->generic_param_count > 0U) {
                    v3_trim_copy_text(colon + 1,
                                      type_def->fields[type_def->field_count].type_text,
                                      sizeof(type_def->fields[type_def->field_count].type_text));
                } else if (!v3_normalize_type_text(lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   colon + 1,
                                                   type_def->fields[type_def->field_count].type_text,
                                                   sizeof(type_def->fields[type_def->field_count].type_text))) {
                    fprintf(stderr,
                            "[cheng_v3_seed] refresh type field normalize failed: %s line=%zu text=%s\n",
                            source_path,
                            i + 1U,
                            lines[i]);
                    free(owned);
                    return false;
                }
                type_def->field_count += 1U;
                i += 1U;
            }
            continue;
        }
        i += 1U;
    }
    free(owned);
    return true;
}

static bool v3_refresh_function_abis_from_source(const V3SystemLinkPlanStub *plan,
                                                 const char *source_path,
                                                 V3LoweringPlanStub *lowering) {
    char owner_module_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    char *owned;
    char *cursor;
    char *line;
    char *lines[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t line_count = 0U;
    size_t i;
    v3_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    owned = v3_read_file(source_path);
    if (!owned) {
        return false;
    }
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(owned);
            return false;
        }
        lines[line_count++] = line;
    }
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    for (i = 0; i < lowering->function_count; ++i) {
        V3LoweredFunctionStub *function = &lowering->functions[i];
        size_t param_i;
        char normalized_type[256];
        if (strcmp(function->source_path, source_path) != 0) {
            continue;
        }
        for (param_i = 0; param_i < function->param_count; ++param_i) {
            if (function->param_types[param_i][0] == '\0' ||
                strcmp(function->param_types[param_i], "unknown") == 0) {
                continue;
            }
            if (!v3_normalize_type_text(lowering,
                                        function->owner_module_path[0] != '\0' ? function->owner_module_path
                                                                                : owner_module_path,
                                        aliases,
                                        alias_count,
                                        function->param_types[param_i],
                                        normalized_type,
                                        sizeof(normalized_type))) {
                snprintf(function->param_abi_classes[param_i],
                         sizeof(function->param_abi_classes[param_i]),
                         "%s",
                         v3_type_abi_class(function->param_types[param_i]));
                continue;
            }
            snprintf(function->param_types[param_i],
                     sizeof(function->param_types[param_i]),
                     "%s",
                     normalized_type);
            snprintf(function->param_abi_classes[param_i],
                     sizeof(function->param_abi_classes[param_i]),
                     "%s",
                     v3_type_abi_class(normalized_type));
        }
        if (function->return_type[0] != '\0' &&
            strcmp(function->return_type, "unknown") != 0 &&
            strcmp(function->return_type, "void") != 0) {
            if (!v3_normalize_type_text(lowering,
                                        function->owner_module_path[0] != '\0' ? function->owner_module_path
                                                                                : owner_module_path,
                                        aliases,
                                        alias_count,
                                        function->return_type,
                                        normalized_type,
                                        sizeof(normalized_type))) {
                snprintf(function->return_abi_class,
                         sizeof(function->return_abi_class),
                         "%s",
                         v3_type_abi_class(function->return_type));
                continue;
            }
            snprintf(function->return_type, sizeof(function->return_type), "%s", normalized_type);
        }
        snprintf(function->return_abi_class,
                 sizeof(function->return_abi_class),
                 "%s",
                 v3_type_abi_class(function->return_type));
    }
    free(owned);
    return true;
}

static bool v3_parse_fixed_array_type(const char *type_text,
                                      char *elem_type_out,
                                      size_t elem_cap,
                                      int32_t *len_out) {
    char copy[256];
    char len_text[64];
    char *end = NULL;
    long parsed_len;
    char *open;
    char *close;
    if (v3_startswith(type_text, "Result[") || strlen(type_text) <= 3U) {
        return false;
    }
    snprintf(copy, sizeof(copy), "%s", type_text);
    open = strrchr(copy, '[');
    close = strrchr(copy, ']');
    if (!open || !close || close <= open || close[1] != '\0') {
        return false;
    }
    *open = '\0';
    if (strchr(open + 1, '[') != NULL) {
        return false;
    }
    v3_trim_copy_text(copy, elem_type_out, elem_cap);
    snprintf(len_text, sizeof(len_text), "%.*s", (int)(close - open - 1), open + 1);
    v3_trim_copy_text(len_text, len_text, sizeof(len_text));
    if (elem_type_out[0] == '\0' || len_text[0] == '\0') {
        return false;
    }
    parsed_len = strtol(len_text, &end, 10);
    if (!end || *end != '\0' || parsed_len < 0L || parsed_len > INT32_MAX) {
        return false;
    }
    *len_out = (int32_t)parsed_len;
    return true;
}

static bool v3_compute_type_layout_impl(const V3LoweringPlanStub *lowering,
                                        const char *type_text,
                                        V3TypeLayoutStub *layout_out,
                                        size_t depth) {
    char stripped[256];
    char inner[256];
    char owner_module[PATH_MAX];
    char type_name[128];
    int32_t fixed_len = 0;
    int32_t found = -1;
    size_t i;
    if (depth > 64U) {
        return false;
    }
    v3_strip_var_prefix(type_text, stripped, sizeof(stripped));
    memset(layout_out, 0, sizeof(*layout_out));
    if (v3_startswith(stripped, "fn ") || v3_startswith(stripped, "fn(")) {
        layout_out->size = 8;
        layout_out->align = 8;
        return true;
    }
    if (v3_type_text_strip_one_pointer_suffix(stripped, inner, sizeof(inner))) {
        layout_out->size = 8;
        layout_out->align = 8;
        return true;
    }
    if (strcmp(stripped, "bool") == 0) {
        layout_out->size = 1;
        layout_out->align = 1;
        return true;
    }
    if (strcmp(stripped, "int8") == 0 ||
        strcmp(stripped, "uint8") == 0) {
        layout_out->size = 1;
        layout_out->align = 1;
        return true;
    }
    if (strcmp(stripped, "int16") == 0 ||
        strcmp(stripped, "uint16") == 0) {
        layout_out->size = 2;
        layout_out->align = 2;
        return true;
    }
    if (strcmp(stripped, "int32") == 0 ||
        strcmp(stripped, "int") == 0 ||
        strcmp(stripped, "uint32") == 0 ||
        strcmp(stripped, "char") == 0) {
        layout_out->size = 4;
        layout_out->align = 4;
        return true;
    }
    if (strcmp(stripped, "int64") == 0 ||
        strcmp(stripped, "uint64") == 0 ||
        strcmp(stripped, "float") == 0 ||
        strcmp(stripped, "float32") == 0 ||
        strcmp(stripped, "float64") == 0 ||
        strcmp(stripped, "ptr") == 0 ||
        strcmp(stripped, "cstring") == 0) {
        layout_out->size = 8;
        layout_out->align = 8;
        return true;
    }
    if (strcmp(stripped, "str") == 0) {
        layout_out->size = 24;
        layout_out->align = 8;
        return true;
    }
    if (strcmp(stripped, "Bytes") == 0) {
        layout_out->size = 16;
        layout_out->align = 8;
        return true;
    }
    if (strlen(stripped) > 2U && strcmp(stripped + strlen(stripped) - 2U, "[]") == 0) {
        layout_out->size = 16;
        layout_out->align = 8;
        return true;
    }
    if (v3_startswith(stripped, "Result[") && stripped[strlen(stripped) - 1U] == ']') {
        V3TypeLayoutStub value_layout;
        int32_t value_offset;
        int32_t err_offset;
        snprintf(inner, sizeof(inner), "%.*s", (int)(strlen(stripped) - 8U), stripped + 7);
        if (!v3_compute_type_layout_impl(lowering, inner, &value_layout, depth + 1U)) {
            fprintf(stderr,
                    "[cheng_v3_seed] result value layout failed type=%s inner=%s depth=%zu\n",
                    stripped,
                    inner,
                    depth);
            return false;
        }
        value_offset = v3_align_up_i32(1, value_layout.align);
        err_offset = v3_align_up_i32(value_offset + value_layout.size, 8);
        layout_out->align = value_layout.align > 8 ? value_layout.align : 8;
        layout_out->size = v3_align_up_i32(err_offset + 32, layout_out->align);
        return true;
    }
    if (v3_parse_fixed_array_type(stripped, inner, sizeof(inner), &fixed_len)) {
        V3TypeLayoutStub elem_layout;
        if (!v3_compute_type_layout_impl(lowering, inner, &elem_layout, depth + 1U)) {
            fprintf(stderr,
                    "[cheng_v3_seed] fixed array elem layout failed type=%s elem=%s len=%d depth=%zu\n",
                    stripped,
                    inner,
                    fixed_len,
                    depth);
            return false;
        }
        layout_out->align = elem_layout.align;
        layout_out->size = v3_align_up_i32(elem_layout.size * fixed_len, elem_layout.align);
        return true;
    }
    if (v3_is_internal_ref_type(stripped)) {
        layout_out->size = 8;
        layout_out->align = 8;
        return true;
    }
    if (!v3_split_qualified_type_text(stripped,
                                      owner_module,
                                      sizeof(owner_module),
                                      type_name,
                                      sizeof(type_name))) {
        fprintf(stderr,
                "[cheng_v3_seed] layout split qualified type failed type=%s depth=%zu\n",
                stripped,
                depth);
        return false;
    }
    found = v3_find_type_def_index_by_symbol(lowering, owner_module, type_name);
    if (found < 0) {
        fprintf(stderr,
                "[cheng_v3_seed] layout type def missing type=%s owner=%s name=%s depth=%zu\n",
                stripped,
                owner_module,
                type_name,
                depth);
        return false;
    }
    {
        const V3TypeDefStub *type_def = &lowering->type_defs[found];
        char type_args[CHENG_V3_MAX_TYPE_PARAMS][256];
        size_t type_arg_count = 0U;
        V3ImportAlias *type_aliases = NULL;
        size_t type_alias_count = 0U;
        bool ok = false;
        if (!v3_parse_type_instance_text(type_name,
                                         type_name,
                                         sizeof(type_name),
                                         type_args,
                                         &type_arg_count,
                                         CHENG_V3_MAX_TYPE_PARAMS)) {
            goto layout_cleanup;
        }
        if (type_def->kind == V3_TYPE_DEF_ALIAS) {
            char alias_target[256];
            if (type_def->generic_param_count > 0U) {
                type_aliases = (V3ImportAlias *)v3_xmalloc(sizeof(*type_aliases) * CHENG_V3_MAX_IMPORT_ALIASES);
                if (!v3_load_import_aliases_from_source_path(type_def->source_path,
                                                             type_aliases,
                                                             &type_alias_count,
                                                             CHENG_V3_MAX_IMPORT_ALIASES) ||
                    type_def->generic_param_count != type_arg_count ||
                    !v3_normalize_type_text_with_params(lowering,
                                                        type_def->owner_module_path,
                                                        type_aliases,
                                                        type_alias_count,
                                                        type_def->generic_param_names,
                                                        type_args,
                                                        type_arg_count,
                                                        type_def->alias_target,
                                                        alias_target,
                                                        sizeof(alias_target))) {
                    goto layout_cleanup;
                }
            } else {
                snprintf(alias_target, sizeof(alias_target), "%s", type_def->alias_target);
            }
            ok = v3_compute_type_layout_impl(lowering, alias_target, layout_out, depth + 1U);
            goto layout_cleanup;
        }
        if (type_def->generic_param_count > 0U &&
            ((type_aliases = (V3ImportAlias *)v3_xmalloc(sizeof(*type_aliases) * CHENG_V3_MAX_IMPORT_ALIASES)) == NULL ||
             !v3_load_import_aliases_from_source_path(type_def->source_path,
                                                      type_aliases,
                                                      &type_alias_count,
                                                      CHENG_V3_MAX_IMPORT_ALIASES) ||
             type_def->generic_param_count != type_arg_count)) {
            goto layout_cleanup;
        }
        layout_out->align = 1;
        layout_out->size = 0;
        for (i = 0; i < type_def->field_count; ++i) {
            V3TypeLayoutStub field_layout;
            int32_t field_align;
            char resolved_field_type[256];
            if (type_def->generic_param_count > 0U) {
                if (!v3_normalize_type_text_with_params(lowering,
                                                        type_def->owner_module_path,
                                                        type_aliases,
                                                        type_alias_count,
                                                        type_def->generic_param_names,
                                                        type_args,
                                                        type_arg_count,
                                                        type_def->fields[i].type_text,
                                                        resolved_field_type,
                                                        sizeof(resolved_field_type))) {
                    goto layout_cleanup;
                }
            } else {
                snprintf(resolved_field_type, sizeof(resolved_field_type), "%s", type_def->fields[i].type_text);
            }
            if (!v3_compute_type_layout_impl(lowering,
                                             resolved_field_type,
                                             &field_layout,
                                             depth + 1U)) {
                fprintf(stderr,
                        "[cheng_v3_seed] layout field failed type=%s field=%s field_type=%s depth=%zu\n",
                        stripped,
                        type_def->fields[i].name,
                        resolved_field_type,
                        depth);
                goto layout_cleanup;
            }
            field_align = field_layout.align > 0 ? field_layout.align : 1;
            layout_out->size = v3_align_up_i32(layout_out->size, field_align);
            layout_out->size += field_layout.size;
            if (field_align > layout_out->align) {
                layout_out->align = field_align;
            }
        }
        layout_out->size = v3_align_up_i32(layout_out->size, layout_out->align);
        ok = true;
layout_cleanup:
        free(type_aliases);
        return ok;
    }
}

static bool v3_resolve_sizeof_expr_value(const V3LoweringPlanStub *lowering,
                                         const char *owner_module_path,
                                         const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         const char *type_expr,
                                         int32_t *value_out) {
    char normalized_type[256];
    V3TypeLayoutStub layout;
    if (!lowering || !owner_module_path || !type_expr || !value_out) {
        return false;
    }
    if (!v3_normalize_type_text(lowering,
                                owner_module_path,
                                aliases,
                                alias_count,
                                type_expr,
                                normalized_type,
                                sizeof(normalized_type)) ||
        !v3_compute_type_layout_impl(lowering, normalized_type, &layout, 0U)) {
        return false;
    }
    *value_out = layout.size;
    return true;
}

static bool v3_parse_function_signature_meta(const char *line,
                                             const char *function_name,
                                             V3LoweredFunctionStub *function) {
    const char *open_paren;
    const char *close_paren = NULL;
    const char *eq;
    char header_copy[4096];
    char params[4096];
    char items[32][4096];
    char return_part[256];
    size_t item_count = 0U;
    size_t i;
    bool in_string = false;
    int32_t paren_depth = 0;
    open_paren = strchr(line, '(');
    eq = strrchr(line, '=');
    if (!open_paren || !eq || eq <= open_paren) {
        return false;
    }
    for (i = (size_t)(open_paren - line); line[i] != '\0'; ++i) {
        char ch = line[i];
        if (ch == '"' && (i == 0U || line[i - 1U] != '\\')) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            if (paren_depth == 0) {
                close_paren = line + i;
                break;
            }
        }
    }
    if (!close_paren || close_paren <= open_paren || eq <= close_paren) {
        return false;
    }
    snprintf(header_copy, sizeof(header_copy), "%s", line);
    if (!v3_startswith(v3_trim_inplace(header_copy), "fn ")) {
        return false;
    }
    if (strstr(line, function_name) == NULL) {
        return false;
    }
    function->param_count = 0U;
    function->return_type[0] = '\0';
    snprintf(function->return_abi_class, sizeof(function->return_abi_class), "%s", "void");
    snprintf(params, sizeof(params), "%.*s", (int)(close_paren - open_paren - 1), open_paren + 1);
    if (!v3_split_top_level_args(params, items, &item_count, 32U)) {
        return false;
    }
    {
        char inherited_type_text[128];
        bool inherited_is_var = false;
        inherited_type_text[0] = '\0';
        for (i = item_count; i-- > 0U;) {
            char item_copy[4096];
            char name_text[128];
            char type_text[4096];
            char value_type_text[4096];
            char *colon;
            bool param_is_var = false;
            snprintf(item_copy, sizeof(item_copy), "%s", items[i]);
            colon = strchr(item_copy, ':');
            if (item_count > 32U) {
                return false;
            }
            name_text[0] = '\0';
            type_text[0] = '\0';
            value_type_text[0] = '\0';
            if (colon) {
                *colon = '\0';
                snprintf(name_text, sizeof(name_text), "%s", item_copy);
                snprintf(type_text, sizeof(type_text), "%s", colon + 1);
                param_is_var = v3_strip_var_type_text(type_text,
                                                      value_type_text,
                                                      sizeof(value_type_text));
                if (param_is_var) {
                    v3_trim_copy_text(value_type_text,
                                      inherited_type_text,
                                      sizeof(inherited_type_text));
                } else {
                    v3_trim_copy_text(type_text,
                                      inherited_type_text,
                                      sizeof(inherited_type_text));
                }
                inherited_is_var = param_is_var;
            } else {
                snprintf(name_text, sizeof(name_text), "%s", item_copy);
                if (inherited_type_text[0] != '\0') {
                    snprintf(type_text, sizeof(type_text), "%s", inherited_type_text);
                    param_is_var = inherited_is_var;
                } else {
                    snprintf(type_text, sizeof(type_text), "%s", "unknown");
                }
            }
            v3_trim_copy_text(name_text,
                              function->param_names[i],
                              sizeof(function->param_names[i]));
            function->param_is_var[i] = param_is_var;
            v3_trim_copy_text(type_text,
                              function->param_types[i],
                              sizeof(function->param_types[i]));
            snprintf(function->param_abi_classes[i],
                     sizeof(function->param_abi_classes[i]),
                     "%s",
                     v3_type_abi_class(function->param_types[i]));
        }
        function->param_count = item_count;
    }
    return_part[0] = '\0';
    snprintf(return_part, sizeof(return_part), "%.*s", (int)(eq - close_paren - 1), close_paren + 1);
    v3_trim_copy_text(return_part, return_part, sizeof(return_part));
    if (return_part[0] != '\0' && return_part[0] == ':') {
        memmove(return_part, return_part + 1, strlen(return_part));
        v3_trim_copy_text(return_part, function->return_type, sizeof(function->return_type));
    }
    if (function->return_type[0] == '\0') {
        snprintf(function->return_type, sizeof(function->return_type), "%s", "void");
    }
    snprintf(function->return_abi_class,
             sizeof(function->return_abi_class),
             "%s",
             v3_type_abi_class(function->return_type));
    return true;
}

static void v3_lowered_function_abi_summary(const V3LoweredFunctionStub *function,
                                            char *out,
                                            size_t cap) {
    size_t i;
    if (cap <= 1U) {
        return;
    }
    out[0] = '\0';
    snprintf(out + strlen(out),
             cap - strlen(out),
             "ret=%s/%s params=",
             function->return_type[0] != '\0' ? function->return_type : "void",
             function->return_abi_class[0] != '\0' ? function->return_abi_class : "void");
    if (function->param_count <= 0U) {
        strncat(out, "-", cap - strlen(out) - 1U);
        return;
    }
    for (i = 0; i < function->param_count; ++i) {
        char chunk[256];
        if (i > 0U) {
            strncat(out, ";", cap - strlen(out) - 1U);
        }
        snprintf(chunk,
                 sizeof(chunk),
                 "%s:%s%s/%s",
                 function->param_names[i][0] != '\0' ? function->param_names[i] : "_",
                 function->param_is_var[i] ? "var " : "",
                 function->param_types[i][0] != '\0' ? function->param_types[i] : "unknown",
                 function->param_abi_classes[i][0] != '\0' ? function->param_abi_classes[i] : "unknown");
        strncat(out, chunk, cap - strlen(out) - 1U);
    }
}

static bool v3_collect_function_signature(char **lines,
                                          size_t line_count,
                                          size_t fn_line_index,
                                          char *signature_out,
                                          size_t signature_cap,
                                          size_t *signature_end_index_out) {
    size_t i;
    signature_out[0] = '\0';
    for (i = fn_line_index; i < line_count; ++i) {
        char line_copy[4096];
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0') {
            continue;
        }
        if (i > fn_line_index && v3_is_top_level_decl_start(trimmed)) {
            return false;
        }
        if (i == fn_line_index &&
            strchr(trimmed, ')') != NULL &&
            strchr(trimmed, '=') == NULL) {
            return false;
        }
        if (signature_out[0] != '\0') {
            snprintf(signature_out + strlen(signature_out),
                     signature_cap - strlen(signature_out),
                     " ");
        }
        snprintf(signature_out + strlen(signature_out),
                 signature_cap - strlen(signature_out),
                 "%s",
                 trimmed);
        if (strchr(trimmed, '=') != NULL) {
            *signature_end_index_out = i;
            return true;
        }
    }
    return false;
}

static bool v3_load_function_source_lines(const V3LoweredFunctionStub *function,
                                          char ***lines_out,
                                          char **owned_out,
                                          size_t *line_count_out,
                                          size_t *fn_line_index_out,
                                          char param_names[][128],
                                          size_t *param_count_out,
                                          char owned_path[PATH_MAX]) {
    char *owned;
    char *cursor;
    char *line;
    char **lines;
    size_t line_count = 0U;
    size_t fn_line_index = 0U;
    bool found = false;
    size_t i;
    v3_copy_text(owned_path, PATH_MAX, function->source_path);
    owned = v3_read_file(function->source_path);
    if (!owned) {
        return false;
    }
    lines = (char **)v3_xmalloc(sizeof(char *) * CHENG_V3_MAX_PLAN_FUNCTIONS);
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(lines);
            free(owned);
            return false;
        }
        lines[line_count] = line;
        line_count += 1U;
    }
    for (i = 0; i < line_count; ++i) {
        char header_copy[4096];
        char function_name[128];
        snprintf(header_copy, sizeof(header_copy), "%s", lines[i]);
        if (v3_lowering_function_name_from_line(v3_trim_inplace(header_copy),
                                                function_name,
                                                sizeof(function_name)) &&
            strcmp(function_name, function->function_name) == 0) {
            char signature_text[8192];
            size_t signature_end_index = i;
            found = true;
            if (!v3_collect_function_signature(lines,
                                               line_count,
                                               i,
                                               signature_text,
                                               sizeof(signature_text),
                                               &signature_end_index) ||
                !v3_const_parse_function_signature(signature_text,
                                                  function->function_name,
                                                  param_names,
                                                  param_count_out,
                                                  CHENG_V3_CONST_MAX_BINDINGS)) {
                found = false;
                continue;
            }
            fn_line_index = signature_end_index;
            break;
        }
    }
    if (!found) {
        free(lines);
        free(owned);
        return false;
    }
    *lines_out = lines;
    *owned_out = owned;
    *line_count_out = line_count;
    *fn_line_index_out = fn_line_index;
    return true;
}

static bool v3_const_build_source_function_stub(const V3LoweredFunctionStub *current_function,
                                                const char *symbol_text,
                                                V3LoweredFunctionStub *out) {
    char symbol_copy[PATH_MAX];
    char *sep;
    char **lines = NULL;
    char *owned_lines = NULL;
    size_t line_count = 0U;
    size_t fn_line_index = 0U;
    char param_names[CHENG_V3_CONST_MAX_BINDINGS][128];
    size_t param_count = 0U;
    char owned_path[PATH_MAX];
    if (current_function == NULL ||
        symbol_text == NULL ||
        symbol_text[0] == '\0' ||
        out == NULL ||
        current_function->source_path[0] == '\0' ||
        current_function->owner_module_path[0] == '\0') {
        return false;
    }
    snprintf(symbol_copy, sizeof(symbol_copy), "%s", symbol_text);
    sep = strstr(symbol_copy, "::");
    if (sep == NULL) {
        return false;
    }
    *sep = '\0';
    if (strcmp(symbol_copy, current_function->owner_module_path) != 0) {
        return false;
    }
    memset(out, 0, sizeof(*out));
    snprintf(out->source_path, sizeof(out->source_path), "%s", current_function->source_path);
    snprintf(out->owner_module_path, sizeof(out->owner_module_path), "%s", current_function->owner_module_path);
    snprintf(out->function_name, sizeof(out->function_name), "%s", sep + 2);
    snprintf(out->symbol_text, sizeof(out->symbol_text), "%s", symbol_text);
    if (!v3_load_function_source_lines(out,
                                       &lines,
                                       &owned_lines,
                                       &line_count,
                                       &fn_line_index,
                                       param_names,
                                       &param_count,
                                       owned_path)) {
        return false;
    }
    free(lines);
    free(owned_lines);
    return true;
}

static bool v3_const_eval_expr(const V3LoweringPlanStub *lowering,
                               const V3LoweredFunctionStub *current_function,
                               const V3ImportAlias *aliases,
                               size_t alias_count,
                               V3ConstEnv *env,
                               const char *expr_text,
                               V3ConstValue *out,
                               size_t depth);

static bool v3_const_eval_function(const V3LoweringPlanStub *lowering,
                                   const V3LoweredFunctionStub *function,
                                   const V3ConstValue *args,
                                   size_t arg_count,
                                   V3ConstValue *out,
                                   V3ConstEntryProgram *entry_program,
                                   size_t depth);

static bool v3_const_value_eq(const V3ConstValue *lhs,
                              const V3ConstValue *rhs,
                              bool *out) {
    double lhs_f64 = 0.0;
    double rhs_f64 = 0.0;
    if (lhs->kind != rhs->kind) {
        if (v3_const_value_as_f64(lhs, &lhs_f64) &&
            v3_const_value_as_f64(rhs, &rhs_f64)) {
            *out = lhs_f64 == rhs_f64;
            return true;
        }
        *out = false;
        return true;
    }
    switch (lhs->kind) {
        case V3_CONST_BOOL:
            *out = lhs->bool_value == rhs->bool_value;
            return true;
        case V3_CONST_I32:
            *out = lhs->i32_value == rhs->i32_value;
            return true;
        case V3_CONST_F64:
            *out = lhs->f64_value == rhs->f64_value;
            return true;
        case V3_CONST_STR:
        case V3_CONST_SYMBOL:
            *out = strcmp(lhs->text_value ? lhs->text_value : "",
                          rhs->text_value ? rhs->text_value : "") == 0;
            return true;
        default:
            return false;
    }
}

static bool v3_const_record_new_from_named_args(const char args[][4096],
                                                size_t arg_count,
                                                const V3LoweringPlanStub *lowering,
                                                const V3LoweredFunctionStub *current_function,
                                                const V3ImportAlias *aliases,
                                                size_t alias_count,
                                                V3ConstEnv *env,
                                                V3ConstValue *out,
                                                size_t depth) {
    size_t i;
    V3ConstRecord *record = (V3ConstRecord *)v3_xmalloc(sizeof(V3ConstRecord));
    memset(record, 0, sizeof(*record));
    for (i = 0; i < arg_count; ++i) {
        int32_t colon = v3_find_top_level_binary_op(args[i], ":");
        char field_name[128];
        char expr[4096];
        if (colon <= 0 || record->field_count >= CHENG_V3_CONST_MAX_FIELDS) {
            v3_const_record_free(record);
            return false;
        }
        snprintf(field_name, sizeof(field_name), "%.*s", colon, args[i]);
        snprintf(expr, sizeof(expr), "%s", args[i] + colon + 1);
        v3_trim_copy_text(field_name, field_name, sizeof(field_name));
        v3_trim_copy_text(expr, expr, sizeof(expr));
        snprintf(record->field_names[record->field_count],
                 sizeof(record->field_names[record->field_count]),
                 "%s",
                 field_name);
        v3_const_value_init(&record->field_values[record->field_count]);
        if (!v3_const_eval_expr(lowering,
                                current_function,
                                aliases,
                                alias_count,
                                env,
                                expr,
                                &record->field_values[record->field_count],
                                depth + 1U)) {
            v3_const_record_free(record);
            return false;
        }
        record->field_count += 1U;
    }
    v3_const_value_free(out);
    out->kind = V3_CONST_RECORD;
    out->record_value = record;
    return true;
}

static bool v3_const_eval_intrinsic_call(const char *callee,
                                         const char args[][4096],
                                         size_t arg_count,
                                         const V3LoweringPlanStub *lowering,
                                         const V3LoweredFunctionStub *current_function,
                                         const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         V3ConstEnv *env,
                                         V3ConstValue *out,
                                         size_t depth) {
    V3ConstValue arg0;
    V3ConstValue arg1;
    char buffer[PATH_MAX];
    int32_t arg0_i32 = 0;
    bool arg0_truthy = false;
    v3_const_value_init(&arg0);
    v3_const_value_init(&arg1);
    if (strcmp(callee, "len") == 0 && arg_count == 1U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U)) {
            goto fail;
        }
        if (arg0.kind != V3_CONST_STR) {
            goto fail;
        }
        v3_const_value_set_i32(out, (int32_t)strlen(arg0.text_value ? arg0.text_value : ""));
        goto ok;
    }
    if (strcmp(callee, "int32") == 0 && arg_count == 1U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U)) {
            goto fail;
        }
        if (v3_const_value_as_i32(&arg0, &arg0_i32)) {
            v3_const_value_set_i32(out, arg0_i32);
            goto ok;
        }
        goto fail;
    }
    if ((strcmp(callee, "int64") == 0 ||
         strcmp(callee, "uint32") == 0 ||
         strcmp(callee, "uint64") == 0) && arg_count == 1U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U) ||
            !v3_const_value_as_i32(&arg0, &arg0_i32)) {
            goto fail;
        }
        v3_const_value_set_i32(out, arg0_i32);
        goto ok;
    }
    if ((strcmp(callee, "float32") == 0 ||
         strcmp(callee, "float64") == 0) && arg_count == 1U) {
        double arg0_f64 = 0.0;
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U) ||
            !v3_const_value_as_f64(&arg0, &arg0_f64)) {
            goto fail;
        }
        if (strcmp(callee, "float32") == 0) {
            arg0_f64 = (double)((float)arg0_f64);
        }
        v3_const_value_set_f64(out, arg0_f64);
        goto ok;
    }
    if (strcmp(callee, "bool") == 0 && arg_count == 1U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U) ||
            !v3_const_value_truthy(&arg0, &arg0_truthy)) {
            goto fail;
        }
        v3_const_value_set_bool(out, arg0_truthy);
        goto ok;
    }
    if (strcmp(callee, "std/strutils::strip") == 0 && arg_count == 1U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U)) {
            goto fail;
        }
        if (arg0.kind != V3_CONST_STR) {
            goto fail;
        }
        v3_const_str_strip_ascii(arg0.text_value ? arg0.text_value : "", buffer, sizeof(buffer));
        v3_const_value_set_str_kind(out, V3_CONST_STR, buffer);
        goto ok;
    }
    if (strcmp(callee, "std/os::isAbsolute") == 0 && arg_count == 1U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U)) {
            goto fail;
        }
        if (arg0.kind != V3_CONST_STR) {
            goto fail;
        }
        v3_const_value_set_bool(out, v3_const_os_is_absolute(arg0.text_value ? arg0.text_value : ""));
        goto ok;
    }
    if (strcmp(callee, "std/os::joinPath") == 0 && arg_count == 2U) {
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[1], &arg1, depth + 1U)) {
            goto fail;
        }
        if (arg0.kind != V3_CONST_STR || arg1.kind != V3_CONST_STR) {
            goto fail;
        }
        v3_const_os_join_path(arg0.text_value ? arg0.text_value : "",
                              arg1.text_value ? arg1.text_value : "",
                              buffer,
                              sizeof(buffer));
        v3_const_value_set_str_kind(out, V3_CONST_STR, buffer);
        goto ok;
    }
    if (strcmp(callee, "std/os::getEnvDefault") == 0 && arg_count == 2U) {
        const char *env_value;
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[1], &arg1, depth + 1U)) {
            goto fail;
        }
        if (arg0.kind != V3_CONST_STR || arg1.kind != V3_CONST_STR) {
            goto fail;
        }
        env_value = getenv(arg0.text_value ? arg0.text_value : "");
        v3_const_value_set_str_kind(out,
                                    V3_CONST_STR,
                                    env_value != NULL ? env_value
                                                      : (arg1.text_value ? arg1.text_value : ""));
        goto ok;
    }
    if (strcmp(callee, "std/os::fileExists") == 0 && arg_count == 1U) {
        struct stat st;
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, args[0], &arg0, depth + 1U)) {
            goto fail;
        }
        if (arg0.kind != V3_CONST_STR) {
            goto fail;
        }
        v3_const_value_set_bool(out,
                                stat(arg0.text_value ? arg0.text_value : "", &st) == 0 &&
                                    !S_ISDIR(st.st_mode));
        goto ok;
    }
fail:
    v3_const_value_free(&arg0);
    v3_const_value_free(&arg1);
    return false;
ok:
    v3_const_value_free(&arg0);
    v3_const_value_free(&arg1);
    return true;
}

static bool v3_consteval_source_callee_is_importc_puts(const char *source_path,
                                                       const char *callee) {
    char *owned = NULL;
    char *cursor = NULL;
    char pending_symbol[128];
    if (source_path == NULL || source_path[0] == '\0' ||
        callee == NULL || callee[0] == '\0') {
        return false;
    }
    owned = v3_read_file(source_path);
    if (owned == NULL) {
        return false;
    }
    pending_symbol[0] = '\0';
    cursor = owned;
    while (cursor != NULL) {
        char *line = strsep(&cursor, "\n");
        char line_copy[4096];
        char function_name[128];
        char *trimmed;
        if (line == NULL) {
            break;
        }
        snprintf(line_copy, sizeof(line_copy), "%s", line);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0') {
            continue;
        }
        if (v3_importc_symbol_from_annotation(trimmed, pending_symbol, sizeof(pending_symbol))) {
            continue;
        }
        function_name[0] = '\0';
        if (v3_importc_function_name_from_line(trimmed, function_name, sizeof(function_name))) {
            if (strcmp(function_name, callee) == 0) {
                free(owned);
                return strcmp(function_name, "puts") == 0 ||
                       strcmp(function_name, "c_puts") == 0;
            }
            pending_symbol[0] = '\0';
            continue;
        }
        if (pending_symbol[0] != '\0' &&
            v3_lowering_function_name_from_line(trimmed, function_name, sizeof(function_name))) {
            if (strcmp(function_name, callee) == 0) {
                bool is_puts = strcmp(pending_symbol, "puts") == 0 ||
                               strcmp(pending_symbol, "c_puts") == 0;
                free(owned);
                return is_puts;
            }
            pending_symbol[0] = '\0';
            continue;
        }
        pending_symbol[0] = '\0';
    }
    free(owned);
    return false;
}

static bool v3_consteval_callee_is_puts_like(const V3LoweredFunctionStub *function,
                                             const char *callee) {
    if (callee == NULL || callee[0] == '\0') {
        return false;
    }
    if (strcmp(callee, "puts") == 0 || strcmp(callee, "c_puts") == 0) {
        return true;
    }
    if (function == NULL) {
        return false;
    }
    return v3_consteval_source_callee_is_importc_puts(function->source_path, callee);
}

static bool v3_const_resolve_call_symbol(const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         const V3LoweredFunctionStub *current_function,
                                         const char *callee,
                                         char *symbol_text,
                                         size_t symbol_cap) {
    if (!symbol_text || symbol_cap == 0U) {
        return false;
    }
    symbol_text[0] = '\0';
    if (current_function == NULL || callee == NULL || callee[0] == '\0') {
        return false;
    }
    if (strstr(callee, "::") != NULL) {
        snprintf(symbol_text, symbol_cap, "%s", callee);
        return true;
    }
    if (strchr(callee, '.') != NULL) {
        char callee_copy[PATH_MAX];
        char *dot;
        const char *module_path;
        snprintf(callee_copy, sizeof(callee_copy), "%s", callee);
        dot = strchr(callee_copy, '.');
        *dot = '\0';
        module_path = v3_alias_module_path(aliases, alias_count, callee_copy);
        if (module_path == NULL) {
            return false;
        }
        snprintf(symbol_text, symbol_cap, "%s::%s", module_path, dot + 1);
        return true;
    }
    snprintf(symbol_text,
             symbol_cap,
             "%s::%s",
             current_function->owner_module_path,
             callee);
    return true;
}

static bool v3_const_expr_is_wrapped_parens(const char *expr) {
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    size_t len;
    size_t i;
    if (expr == NULL) {
        return false;
    }
    len = strlen(expr);
    if (len < 2U || expr[0] != '(' || expr[len - 1U] != ')') {
        return false;
    }
    for (i = 0U; i < len; ++i) {
        char ch = expr[i];
        if (ch == '"' && (i == 0U || expr[i - 1U] != '\\')) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
        } else if (ch == ')') {
            paren_depth -= 1;
        } else if (ch == '[') {
            bracket_depth += 1;
        } else if (ch == ']') {
            bracket_depth -= 1;
        } else if (ch == '{') {
            brace_depth += 1;
        } else if (ch == '}') {
            brace_depth -= 1;
        }
        if (paren_depth == 0 &&
            bracket_depth == 0 &&
            brace_depth == 0 &&
            i + 1U < len) {
            return false;
        }
        if (paren_depth < 0 || bracket_depth < 0 || brace_depth < 0) {
            return false;
        }
    }
    return !in_string &&
           paren_depth == 0 &&
           bracket_depth == 0 &&
           brace_depth == 0;
}

static bool v3_const_split_binary_expr(const char *expr,
                                       const char *op,
                                       bool use_last,
                                       char *left_out,
                                       size_t left_cap,
                                       char *right_out,
                                       size_t right_cap) {
    int32_t op_index = use_last
                           ? v3_find_top_level_binary_op_last(expr, op)
                           : v3_find_top_level_binary_op(expr, op);
    size_t op_len = strlen(op);
    if (op_index <= 0) {
        return false;
    }
    snprintf(left_out, left_cap, "%.*s", op_index, expr);
    snprintf(right_out, right_cap, "%s", expr + op_index + op_len);
    v3_trim_copy_text(left_out, left_out, left_cap);
    v3_trim_copy_text(right_out, right_out, right_cap);
    return left_out[0] != '\0' && right_out[0] != '\0';
}

static bool v3_const_parse_i32_literal_text(const char *text, int32_t *out_value) {
    char *end = NULL;
    long parsed;
    if (text == NULL || text[0] == '\0') {
        return false;
    }
    if (!((text[0] >= '0' && text[0] <= '9') ||
          (text[0] == '-' && text[1] >= '0' && text[1] <= '9'))) {
        return false;
    }
    parsed = strtol(text, &end, 10);
    if (end == NULL || *end != '\0' || parsed < INT32_MIN || parsed > INT32_MAX) {
        return false;
    }
    if (out_value != NULL) {
        *out_value = (int32_t)parsed;
    }
    return true;
}

static bool v3_const_parse_f64_literal_text(const char *text, double *out_value) {
    char *end = NULL;
    double parsed;
    bool saw_float_marker = false;
    size_t i;
    if (text == NULL || text[0] == '\0') {
        return false;
    }
    for (i = 0; text[i] != '\0'; ++i) {
        if (text[i] == '.' || text[i] == 'e' || text[i] == 'E') {
            saw_float_marker = true;
            break;
        }
    }
    if (!saw_float_marker) {
        return false;
    }
    parsed = strtod(text, &end);
    if (end == NULL || *end != '\0') {
        return false;
    }
    if (out_value != NULL) {
        *out_value = parsed;
    }
    return true;
}

static bool v3_const_value_set_zero_for_type(const char *type_text, V3ConstValue *out) {
    char trimmed[256];
    if (type_text == NULL || type_text[0] == '\0') {
        return false;
    }
    v3_trim_copy_text(type_text, trimmed, sizeof(trimmed));
    if (strcmp(trimmed, "bool") == 0) {
        return v3_const_value_set_bool(out, false);
    }
    if (strcmp(trimmed, "int32") == 0 ||
        strcmp(trimmed, "int64") == 0 ||
        strcmp(trimmed, "uint32") == 0 ||
        strcmp(trimmed, "uint64") == 0) {
        return v3_const_value_set_i32(out, 0);
    }
    if (strcmp(trimmed, "float32") == 0 ||
        strcmp(trimmed, "float64") == 0) {
        return v3_const_value_set_f64(out, 0.0);
    }
    if (strcmp(trimmed, "str") == 0 || strcmp(trimmed, "cstring") == 0) {
        return v3_const_value_set_str_kind(out, V3_CONST_STR, "");
    }
    return false;
}

static bool v3_const_eval_expr(const V3LoweringPlanStub *lowering,
                               const V3LoweredFunctionStub *current_function,
                               const V3ImportAlias *aliases,
                               size_t alias_count,
                               V3ConstEnv *env,
                               const char *expr_text,
                               V3ConstValue *out,
                               size_t depth) {
    char expr[8192];
    char left[4096];
    char right[4096];
    char binary_op[4];
    int32_t literal_i32 = 0;
    double literal_f64 = 0.0;
    if (depth > 64U) {
        return false;
    }
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    while (v3_const_expr_is_wrapped_parens(expr)) {
        char inner[8192];
        snprintf(inner, sizeof(inner), "%.*s", (int)(strlen(expr) - 2U), expr + 1);
        v3_trim_copy_text(inner, expr, sizeof(expr));
        if (expr[0] == '\0') {
            return false;
        }
    }
    if (expr[0] == '"' && expr[strlen(expr) - 1U] == '"') {
        char literal[8192];
        snprintf(literal, sizeof(literal), "%.*s", (int)(strlen(expr) - 2U), expr + 1);
        return v3_const_value_set_str_kind(out, V3_CONST_STR, literal);
    }
    if (strcmp(expr, "true") == 0) {
        return v3_const_value_set_bool(out, true);
    }
    if (strcmp(expr, "false") == 0) {
        return v3_const_value_set_bool(out, false);
    }
    if (v3_const_parse_i32_literal_text(expr, &literal_i32)) {
        return v3_const_value_set_i32(out, literal_i32);
    }
    if (v3_const_parse_f64_literal_text(expr, &literal_f64)) {
        return v3_const_value_set_f64(out, literal_f64);
    }
    if (v3_parse_ternary_expr(expr, left, sizeof(left), right, sizeof(right), expr, sizeof(expr))) {
        V3ConstValue cond;
        bool cond_truthy = false;
        v3_const_value_init(&cond);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &cond, depth + 1U) ||
            !v3_const_value_truthy(&cond, &cond_truthy)) {
            v3_const_value_free(&cond);
            return false;
        }
        v3_const_value_free(&cond);
        return v3_const_eval_expr(lowering,
                                  current_function,
                                  aliases,
                                  alias_count,
                                  env,
                                  cond_truthy ? right : expr,
                                  out,
                                  depth + 1U);
    }
    if (v3_const_split_binary_expr(expr, "||", true, left, sizeof(left), right, sizeof(right))) {
        V3ConstValue lhs;
        bool lhs_truthy = false;
        v3_const_value_init(&lhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_value_truthy(&lhs, &lhs_truthy)) {
            v3_const_value_free(&lhs);
            return false;
        }
        if (lhs_truthy) {
            v3_const_value_set_bool(out, true);
            v3_const_value_free(&lhs);
            return true;
        }
        v3_const_value_free(&lhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &lhs, depth + 1U) ||
            !v3_const_value_truthy(&lhs, &lhs_truthy)) {
            v3_const_value_free(&lhs);
            return false;
        }
        v3_const_value_set_bool(out, lhs_truthy);
        v3_const_value_free(&lhs);
        return true;
    }
    if (v3_const_split_binary_expr(expr, "&&", true, left, sizeof(left), right, sizeof(right))) {
        V3ConstValue lhs;
        bool lhs_truthy = false;
        v3_const_value_init(&lhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_value_truthy(&lhs, &lhs_truthy)) {
            v3_const_value_free(&lhs);
            return false;
        }
        if (!lhs_truthy) {
            v3_const_value_set_bool(out, false);
            v3_const_value_free(&lhs);
            return true;
        }
        v3_const_value_free(&lhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &lhs, depth + 1U) ||
            !v3_const_value_truthy(&lhs, &lhs_truthy)) {
            v3_const_value_free(&lhs);
            return false;
        }
        v3_const_value_set_bool(out, lhs_truthy);
        v3_const_value_free(&lhs);
        return true;
    }
    if (v3_const_split_binary_expr(expr, "==", false, left, sizeof(left), right, sizeof(right))) {
        V3ConstValue lhs;
        V3ConstValue rhs;
        bool eq = false;
        v3_const_value_init(&lhs);
        v3_const_value_init(&rhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &rhs, depth + 1U) ||
            !v3_const_value_eq(&lhs, &rhs, &eq)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        v3_const_value_free(&lhs);
        v3_const_value_free(&rhs);
        return v3_const_value_set_bool(out, eq);
    }
    if (v3_const_split_binary_expr(expr, "!=", false, left, sizeof(left), right, sizeof(right))) {
        V3ConstValue lhs;
        V3ConstValue rhs;
        bool eq = false;
        v3_const_value_init(&lhs);
        v3_const_value_init(&rhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &rhs, depth + 1U) ||
            !v3_const_value_eq(&lhs, &rhs, &eq)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        v3_const_value_free(&lhs);
        v3_const_value_free(&rhs);
        return v3_const_value_set_bool(out, !eq);
    }
    binary_op[0] = '\0';
    if (v3_const_split_binary_expr(expr, "<=", false, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "<=");
    } else if (v3_const_split_binary_expr(expr, ">=", false, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", ">=");
    } else if (v3_const_split_binary_expr(expr, "<", false, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "<");
    } else if (v3_const_split_binary_expr(expr, ">", false, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", ">");
    }
    if (binary_op[0] != '\0') {
        V3ConstValue lhs;
        V3ConstValue rhs;
        bool result = false;
        int32_t lhs_i32 = 0;
        int32_t rhs_i32 = 0;
        double lhs_f64 = 0.0;
        double rhs_f64 = 0.0;
        bool use_float = false;
        v3_const_value_init(&lhs);
        v3_const_value_init(&rhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &rhs, depth + 1U)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        use_float = lhs.kind == V3_CONST_F64 || rhs.kind == V3_CONST_F64;
        if (use_float) {
            if (!v3_const_value_as_f64(&lhs, &lhs_f64) ||
                !v3_const_value_as_f64(&rhs, &rhs_f64)) {
                v3_const_value_free(&lhs);
                v3_const_value_free(&rhs);
                return false;
            }
            if (strcmp(binary_op, "<=") == 0) {
                result = lhs_f64 <= rhs_f64;
            } else if (strcmp(binary_op, ">=") == 0) {
                result = lhs_f64 >= rhs_f64;
            } else if (strcmp(binary_op, "<") == 0) {
                result = lhs_f64 < rhs_f64;
            } else {
                result = lhs_f64 > rhs_f64;
            }
        } else if (!v3_const_value_as_i32(&lhs, &lhs_i32) ||
                   !v3_const_value_as_i32(&rhs, &rhs_i32)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        } else if (strcmp(binary_op, "<=") == 0) {
            result = lhs_i32 <= rhs_i32;
        } else if (strcmp(binary_op, ">=") == 0) {
            result = lhs_i32 >= rhs_i32;
        } else if (strcmp(binary_op, "<") == 0) {
            result = lhs_i32 < rhs_i32;
        } else {
            result = lhs_i32 > rhs_i32;
        }
        v3_const_value_set_bool(out, result);
        v3_const_value_free(&lhs);
        v3_const_value_free(&rhs);
        return true;
    }
    if (v3_const_split_binary_expr(expr, "+", true, left, sizeof(left), right, sizeof(right))) {
        V3ConstValue lhs;
        V3ConstValue rhs;
        int32_t lhs_i32 = 0;
        int32_t rhs_i32 = 0;
        double lhs_f64 = 0.0;
        double rhs_f64 = 0.0;
        v3_const_value_init(&lhs);
        v3_const_value_init(&rhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &rhs, depth + 1U)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        if (v3_const_value_as_i32(&lhs, &lhs_i32) &&
            v3_const_value_as_i32(&rhs, &rhs_i32)) {
            v3_const_value_set_i32(out, lhs_i32 + rhs_i32);
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return true;
        }
        if ((lhs.kind == V3_CONST_F64 || rhs.kind == V3_CONST_F64) &&
            v3_const_value_as_f64(&lhs, &lhs_f64) &&
            v3_const_value_as_f64(&rhs, &rhs_f64)) {
            v3_const_value_set_f64(out, lhs_f64 + rhs_f64);
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return true;
        }
        if ((lhs.kind == V3_CONST_STR || lhs.kind == V3_CONST_SYMBOL) &&
            (rhs.kind == V3_CONST_STR || rhs.kind == V3_CONST_SYMBOL)) {
            char joined[8192];
            snprintf(joined,
                     sizeof(joined),
                     "%s%s",
                     lhs.text_value ? lhs.text_value : "",
                     rhs.text_value ? rhs.text_value : "");
            v3_const_value_set_str_kind(out, V3_CONST_STR, joined);
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return true;
        }
        v3_const_value_free(&lhs);
        v3_const_value_free(&rhs);
        return false;
    }
    binary_op[0] = '\0';
    if (v3_const_split_binary_expr(expr, "-", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "-");
    } else if (v3_const_split_binary_expr(expr, "*", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "*");
    } else if (v3_const_split_binary_expr(expr, "/", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "/");
    } else if (v3_const_split_binary_expr(expr, "%", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "%");
    }
    if (binary_op[0] != '\0') {
        V3ConstValue lhs;
        V3ConstValue rhs;
        int32_t value = 0;
        int32_t lhs_i32 = 0;
        int32_t rhs_i32 = 0;
        double lhs_f64 = 0.0;
        double rhs_f64 = 0.0;
        bool use_float = false;
        v3_const_value_init(&lhs);
        v3_const_value_init(&rhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &rhs, depth + 1U)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        use_float = lhs.kind == V3_CONST_F64 || rhs.kind == V3_CONST_F64;
        if (use_float) {
            if (!v3_const_value_as_f64(&lhs, &lhs_f64) ||
                !v3_const_value_as_f64(&rhs, &rhs_f64)) {
                v3_const_value_free(&lhs);
                v3_const_value_free(&rhs);
                return false;
            }
            if (strcmp(binary_op, "%") == 0 || rhs_f64 == 0.0) {
                v3_const_value_free(&lhs);
                v3_const_value_free(&rhs);
                return false;
            }
            if (strcmp(binary_op, "-") == 0) {
                v3_const_value_set_f64(out, lhs_f64 - rhs_f64);
            } else if (strcmp(binary_op, "*") == 0) {
                v3_const_value_set_f64(out, lhs_f64 * rhs_f64);
            } else {
                v3_const_value_set_f64(out, lhs_f64 / rhs_f64);
            }
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return true;
        }
        if (!v3_const_value_as_i32(&lhs, &lhs_i32) ||
            !v3_const_value_as_i32(&rhs, &rhs_i32)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        if (strcmp(binary_op, "-") == 0) {
            value = lhs_i32 - rhs_i32;
        } else if (strcmp(binary_op, "*") == 0) {
            value = lhs_i32 * rhs_i32;
        } else if (strcmp(binary_op, "/") == 0) {
            if (rhs_i32 == 0) {
                v3_const_value_free(&lhs);
                v3_const_value_free(&rhs);
                return false;
            }
            value = lhs_i32 / rhs_i32;
        } else {
            if (rhs_i32 == 0) {
                v3_const_value_free(&lhs);
                v3_const_value_free(&rhs);
                return false;
            }
            value = lhs_i32 % rhs_i32;
        }
        v3_const_value_set_i32(out, value);
        v3_const_value_free(&lhs);
        v3_const_value_free(&rhs);
        return true;
    }
    binary_op[0] = '\0';
    if (v3_const_split_binary_expr(expr, "<<", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "<<");
    } else if (v3_const_split_binary_expr(expr, ">>", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", ">>");
    } else if (v3_const_split_binary_expr(expr, "|", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "|");
    } else if (v3_const_split_binary_expr(expr, "^", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "^");
    } else if (v3_const_split_binary_expr(expr, "&", true, left, sizeof(left), right, sizeof(right))) {
        snprintf(binary_op, sizeof(binary_op), "%s", "&");
    }
    if (binary_op[0] != '\0') {
        V3ConstValue lhs;
        V3ConstValue rhs;
        int32_t lhs_i32 = 0;
        int32_t rhs_i32 = 0;
        int32_t value = 0;
        v3_const_value_init(&lhs);
        v3_const_value_init(&rhs);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, left, &lhs, depth + 1U) ||
            !v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, right, &rhs, depth + 1U) ||
            !v3_const_value_as_i32(&lhs, &lhs_i32) ||
            !v3_const_value_as_i32(&rhs, &rhs_i32)) {
            v3_const_value_free(&lhs);
            v3_const_value_free(&rhs);
            return false;
        }
        if (strcmp(binary_op, "<<") == 0) {
            value = lhs_i32 << (rhs_i32 & 31);
        } else if (strcmp(binary_op, ">>") == 0) {
            value = lhs_i32 >> (rhs_i32 & 31);
        } else if (strcmp(binary_op, "|") == 0) {
            value = lhs_i32 | rhs_i32;
        } else if (strcmp(binary_op, "^") == 0) {
            value = lhs_i32 ^ rhs_i32;
        } else {
            value = lhs_i32 & rhs_i32;
        }
        v3_const_value_set_i32(out, value);
        v3_const_value_free(&lhs);
        v3_const_value_free(&rhs);
        return true;
    }
    if (expr[0] == '!') {
        V3ConstValue inner;
        bool truthy = false;
        v3_const_value_init(&inner);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, expr + 1, &inner, depth + 1U) ||
            !v3_const_value_truthy(&inner, &truthy)) {
            v3_const_value_free(&inner);
            return false;
        }
        v3_const_value_set_bool(out, !truthy);
        v3_const_value_free(&inner);
        return true;
    }
    if (expr[0] == '~') {
        V3ConstValue inner;
        int32_t inner_i32 = 0;
        v3_const_value_init(&inner);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, expr + 1, &inner, depth + 1U) ||
            !v3_const_value_as_i32(&inner, &inner_i32)) {
            v3_const_value_free(&inner);
            return false;
        }
        v3_const_value_set_i32(out, ~inner_i32);
        v3_const_value_free(&inner);
        return true;
    }
    if (expr[0] == '-') {
        V3ConstValue inner;
        v3_const_value_init(&inner);
        if (!v3_const_eval_expr(lowering, current_function, aliases, alias_count, env, expr + 1, &inner, depth + 1U)) {
            v3_const_value_free(&inner);
            return false;
        }
        if (inner.kind == V3_CONST_F64) {
            v3_const_value_set_f64(out, -inner.f64_value);
        } else if (inner.kind == V3_CONST_I32) {
            v3_const_value_set_i32(out, -inner.i32_value);
        } else {
            v3_const_value_free(&inner);
            return false;
        }
        v3_const_value_free(&inner);
        return true;
    }
    if (expr[strlen(expr) - 1U] == ')') {
        char callee[PATH_MAX];
        char (*args)[4096] = NULL;
        size_t arg_count = 0U;
        bool has_named_fields = false;
        size_t i;
        args = (char (*)[4096])v3_xmalloc(sizeof(*args) * 32U);
        if (v3_parse_call_text(expr, callee, sizeof(callee), args, &arg_count, 32U)) {
            for (i = 0; i < arg_count; ++i) {
                if (v3_find_top_level_binary_op(args[i], ":") > 0) {
                    has_named_fields = true;
                    break;
                }
            }
            if (has_named_fields && callee[0] >= 'A' && callee[0] <= 'Z') {
                bool ok = v3_const_record_new_from_named_args(args,
                                                              arg_count,
                                                              lowering,
                                                              current_function,
                                                              aliases,
                                                              alias_count,
                                                              env,
                                                              out,
                                                              depth + 1U);
                free(args);
                return ok;
            }
            if (v3_is_intrinsic_call_name(callee)) {
                bool ok = v3_const_eval_intrinsic_call(callee,
                                                       args,
                                                       arg_count,
                                                       lowering,
                                                       current_function,
                                                       aliases,
                                                       alias_count,
                                                       env,
                                                       out,
                                                       depth + 1U);
                free(args);
                return ok;
            }
            {
                char symbol_text[PATH_MAX];
                int32_t function_index;
                V3ConstValue arg_values[32];
                size_t arg_index;
                char callee_symbol[PATH_MAX];
                V3LoweredFunctionStub source_function;
                const V3LoweredFunctionStub *target_function = NULL;
                bool intrinsic_ok = false;
                for (arg_index = 0; arg_index < arg_count; ++arg_index) {
                    v3_const_value_init(&arg_values[arg_index]);
                }
                if (strchr(callee, '.') != NULL) {
                    char alias_text[128];
                    char function_name[128];
                    char callee_copy[PATH_MAX];
                    char *dot;
                    snprintf(callee_copy, sizeof(callee_copy), "%s", callee);
                    dot = strchr(callee_copy, '.');
                    *dot = '\0';
                    snprintf(alias_text, sizeof(alias_text), "%s", callee_copy);
                    snprintf(function_name, sizeof(function_name), "%s", dot + 1);
                    {
                        const char *module_path = v3_alias_module_path(aliases, alias_count, alias_text);
                        if (module_path) {
                            snprintf(callee_symbol, sizeof(callee_symbol), "%s::%s", module_path, function_name);
                            if (v3_is_intrinsic_module_call(module_path, function_name)) {
                                intrinsic_ok = v3_const_eval_intrinsic_call(callee_symbol,
                                                                            args,
                                                                            arg_count,
                                                                            lowering,
                                                                            current_function,
                                                                            aliases,
                                                                            alias_count,
                                                                            env,
                                                                            out,
                                                                            depth + 1U);
                            }
                        }
                    }
                }
                if (intrinsic_ok) {
                    for (arg_index = 0; arg_index < arg_count; ++arg_index) {
                        v3_const_value_free(&arg_values[arg_index]);
                    }
                    free(args);
                    return true;
                }
                if (!v3_const_resolve_call_symbol(aliases,
                                                  alias_count,
                                                  current_function,
                                                  callee,
                                                  symbol_text,
                                                  sizeof(symbol_text))) {
                    for (arg_index = 0; arg_index < arg_count; ++arg_index) {
                        v3_const_value_free(&arg_values[arg_index]);
                    }
                    free(args);
                    return false;
                }
                function_index = v3_find_lowered_function_index_by_symbol(lowering, symbol_text);
                if (function_index >= 0) {
                    target_function = &lowering->functions[function_index];
                } else if (v3_const_build_source_function_stub(current_function,
                                                               symbol_text,
                                                               &source_function)) {
                    target_function = &source_function;
                } else {
                    for (arg_index = 0; arg_index < arg_count; ++arg_index) {
                        v3_const_value_free(&arg_values[arg_index]);
                    }
                    free(args);
                    return false;
                }
                for (arg_index = 0; arg_index < arg_count; ++arg_index) {
                    if (!v3_const_eval_expr(lowering,
                                            current_function,
                                            aliases,
                                            alias_count,
                                            env,
                                            args[arg_index],
                                            &arg_values[arg_index],
                                            depth + 1U)) {
                        size_t j;
                        for (j = 0; j < arg_count; ++j) {
                            v3_const_value_free(&arg_values[j]);
                        }
                        free(args);
                        return false;
                    }
                }
                if (!v3_const_eval_function(lowering,
                                            target_function,
                                            arg_values,
                                            arg_count,
                                            out,
                                            NULL,
                                            depth + 1U)) {
                    size_t j;
                    for (j = 0; j < arg_count; ++j) {
                        v3_const_value_free(&arg_values[j]);
                    }
                    free(args);
                    return false;
                }
                for (arg_index = 0; arg_index < arg_count; ++arg_index) {
                    v3_const_value_free(&arg_values[arg_index]);
                }
                free(args);
                return true;
            }
        }
        free(args);
    }
    if (strchr(expr, '.') != NULL) {
        char chain[16][128];
        size_t chain_len = 0U;
        const char *start = expr;
        const char *cursor = expr;
        V3ConstValue current;
        v3_const_value_init(&current);
        while (1) {
            if (*cursor == '.' || *cursor == '\0') {
                if (chain_len >= 16U) {
                    return false;
                }
                snprintf(chain[chain_len], sizeof(chain[chain_len]), "%.*s", (int)(cursor - start), start);
                v3_trim_copy_text(chain[chain_len], chain[chain_len], sizeof(chain[chain_len]));
                chain_len += 1U;
                if (*cursor == '\0') {
                    break;
                }
                start = cursor + 1;
            }
            cursor++;
        }
        {
            const V3ConstValue *binding = v3_const_env_get(env, chain[0]);
            size_t i;
            if (!binding) {
                v3_const_value_free(&current);
                return false;
            }
            if (!v3_const_value_clone(binding, &current)) {
                return false;
            }
            for (i = 1; i < chain_len; ++i) {
                const V3ConstValue *field = v3_const_record_field(&current, chain[i]);
                V3ConstValue next;
                if (!field) {
                    v3_const_value_free(&current);
                    return false;
                }
                v3_const_value_init(&next);
                if (!v3_const_value_clone(field, &next)) {
                    v3_const_value_free(&current);
                    return false;
                }
                v3_const_value_free(&current);
                current = next;
            }
            if (!v3_const_value_clone(&current, out)) {
                v3_const_value_free(&current);
                return false;
            }
            v3_const_value_free(&current);
            return true;
        }
    }
    {
        const V3ConstValue *binding = v3_const_env_get(env, expr);
        if (binding) {
            return v3_const_value_clone(binding, out);
        }
    }
    return v3_const_value_set_str_kind(out,
                                       (expr[0] >= 'A' && expr[0] <= 'Z') ? V3_CONST_SYMBOL : V3_CONST_STR,
                                       expr);
}

static bool v3_const_parse_binding_name(const char *statement,
                                        const char *prefix,
                                        char *name_out,
                                        size_t name_cap,
                                        char *expr_out,
                                        size_t expr_cap) {
    const char *cursor = statement + strlen(prefix);
    const char *eq = strchr(cursor, '=');
    char name_part[256];
    if (!eq) {
        return false;
    }
    snprintf(name_part, sizeof(name_part), "%.*s", (int)(eq - cursor), cursor);
    v3_trim_copy_text(name_part, name_part, sizeof(name_part));
    if (strchr(name_part, ':') != NULL) {
        *strchr(name_part, ':') = '\0';
    }
    v3_trim_copy_text(name_part, name_out, name_cap);
    snprintf(expr_out, expr_cap, "%s", eq + 1);
    v3_trim_copy_text(expr_out, expr_out, expr_cap);
    return name_out[0] != '\0';
}

static bool v3_const_env_load_top_level_vars(const V3LoweringPlanStub *lowering,
                                             const V3LoweredFunctionStub *function,
                                             const V3ImportAlias *aliases,
                                             size_t alias_count,
                                             char **lines,
                                             size_t line_count,
                                             V3ConstEnv *env,
                                             size_t depth) {
    bool in_var_block = false;
    size_t i;
    for (i = 0; i < line_count; ++i) {
        char line_copy[4096];
        char name[128];
        char raw_type[256];
        char expr[4096];
        bool has_init = false;
        int32_t indent;
        char *trimmed;
        const char *decl = NULL;
        V3ConstValue bound;
        bool have_value = false;
        v3_const_value_init(&bound);
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        indent = v3_line_indent(lines[i]);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            v3_const_value_free(&bound);
            continue;
        }
        if (indent <= 0 && strcmp(trimmed, "var") == 0) {
            in_var_block = true;
            v3_const_value_free(&bound);
            continue;
        }
        if (indent <= 0 && !v3_startswith(trimmed, "var ")) {
            in_var_block = false;
        }
        if (indent <= 0 && v3_startswith(trimmed, "var ")) {
            decl = trimmed + 4;
        } else if (indent > 0 && in_var_block) {
            decl = trimmed;
        }
        if (decl == NULL ||
            !v3_parse_top_level_var_binding_text(decl,
                                                 name,
                                                 sizeof(name),
                                                 raw_type,
                                                 sizeof(raw_type),
                                                 &has_init,
                                                 expr,
                                                 sizeof(expr))) {
            v3_const_value_free(&bound);
            continue;
        }
        if (has_init) {
            have_value = v3_const_eval_expr(lowering,
                                            function,
                                            aliases,
                                            alias_count,
                                            env,
                                            expr,
                                            &bound,
                                            depth + 1U);
        } else if (raw_type[0] != '\0') {
            have_value = v3_const_value_set_zero_for_type(raw_type, &bound);
        }
        if (have_value) {
            if (!v3_const_env_set(env, name, &bound)) {
                v3_const_value_free(&bound);
                return false;
            }
        }
        v3_const_value_free(&bound);
    }
    return true;
}

static bool v3_const_skip_nested_block(char **lines,
                                       size_t line_count,
                                       size_t *index_io,
                                       int32_t parent_indent) {
    while (*index_io < line_count) {
        char raw_copy[4096];
        char *trimmed;
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
        trimmed = v3_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            *index_io += 1U;
            continue;
        }
        if (v3_line_indent(lines[*index_io]) <= parent_indent) {
            return true;
        }
        *index_io += 1U;
    }
    return true;
}

static bool v3_const_record_entry_echo(V3ConstEntryProgram *entry_program,
                                       const V3ConstValue *value) {
    if (entry_program == NULL ||
        value == NULL ||
        value->kind != V3_CONST_STR ||
        entry_program->echo_count >= CHENG_V3_CONST_MAX_ECHOS) {
        return false;
    }
    snprintf(entry_program->echo_texts[entry_program->echo_count].text,
             sizeof(entry_program->echo_texts[entry_program->echo_count].text),
             "%s",
             value->text_value ? value->text_value : "");
    entry_program->echo_count += 1U;
    return true;
}

static bool v3_const_skip_following_if_branches(char **lines,
                                                size_t line_count,
                                                size_t *index_io,
                                                int32_t parent_indent) {
    while (*index_io < line_count) {
        char raw_copy[4096];
        char *trimmed;
        int32_t indent;
        size_t branch_header_index = *index_io;
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
        trimmed = v3_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            *index_io += 1U;
            continue;
        }
        indent = v3_line_indent(lines[*index_io]);
        if (indent != parent_indent ||
            !(strcmp(trimmed, "else:") == 0 ||
              (v3_startswith(trimmed, "elif ") && trimmed[strlen(trimmed) - 1U] == ':'))) {
            return true;
        }
        *index_io = branch_header_index + 1U;
        if (!v3_const_skip_nested_block(lines, line_count, index_io, parent_indent)) {
            return false;
        }
    }
    return true;
}

static bool v3_const_eval_call_statement(const V3LoweringPlanStub *lowering,
                                         const V3LoweredFunctionStub *function,
                                         const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         V3ConstEnv *env,
                                         const char *statement,
                                         V3ConstEntryProgram *entry_program,
                                         size_t depth) {
    char callee[PATH_MAX];
    char args_text[32][4096];
    size_t arg_count = 0U;
    V3ConstValue value;
    v3_const_value_init(&value);
    if (!v3_parse_call_text(statement, callee, sizeof(callee), args_text, &arg_count, 32U)) {
        v3_const_value_free(&value);
        return false;
    }
    if (strcmp(callee, "echo") == 0) {
        bool ok = arg_count == 1U &&
                  v3_const_eval_expr(lowering,
                                     function,
                                     aliases,
                                     alias_count,
                                     env,
                                     args_text[0],
                                     &value,
                                     depth + 1U) &&
                  v3_const_record_entry_echo(entry_program, &value);
        v3_const_value_free(&value);
        return ok;
    }
    if (v3_consteval_callee_is_puts_like(function, callee)) {
        bool ok = arg_count == 1U &&
                  v3_const_eval_expr(lowering,
                                     function,
                                     aliases,
                                     alias_count,
                                     env,
                                     args_text[0],
                                     &value,
                                     depth + 1U) &&
                  v3_const_record_entry_echo(entry_program, &value);
        v3_const_value_free(&value);
        return ok;
    }
    if (!v3_const_eval_expr(lowering,
                            function,
                            aliases,
                            alias_count,
                            env,
                            statement,
                            &value,
                            depth + 1U)) {
        v3_const_value_free(&value);
        return false;
    }
    v3_const_value_free(&value);
    return true;
}

static bool v3_const_eval_block(const V3LoweringPlanStub *lowering,
                                const V3LoweredFunctionStub *function,
                                const V3ImportAlias *aliases,
                                size_t alias_count,
                                V3ConstEnv *env,
                                char **lines,
                                size_t line_count,
                                size_t *index_io,
                                int32_t parent_indent,
                                V3ConstValue *out,
                                bool *returned,
                                V3ConstEntryProgram *entry_program,
                                bool *loop_break,
                                bool *loop_continue,
                                size_t depth);

static bool v3_const_eval_inline_statement(const V3LoweringPlanStub *lowering,
                                           const V3LoweredFunctionStub *function,
                                           const V3ImportAlias *aliases,
                                           size_t alias_count,
                                           V3ConstEnv *env,
                                           const char *statement,
                                           V3ConstValue *out,
                                           bool *returned,
                                           V3ConstEntryProgram *entry_program,
                                           bool *loop_break,
                                           bool *loop_continue,
                                           size_t depth) {
    char line_storage[8192];
    char *inline_lines[1];
    size_t inline_index = 0U;
    if (statement == NULL || statement[0] == '\0') {
        return true;
    }
    snprintf(line_storage, sizeof(line_storage), "%s", statement);
    inline_lines[0] = line_storage;
    return v3_const_eval_block(lowering,
                               function,
                               aliases,
                               alias_count,
                               env,
                               inline_lines,
                               1U,
                               &inline_index,
                               -1,
                               out,
                               returned,
                               entry_program,
                               loop_break,
                               loop_continue,
                               depth + 1U);
}

static bool v3_const_eval_block(const V3LoweringPlanStub *lowering,
                                const V3LoweredFunctionStub *function,
                                const V3ImportAlias *aliases,
                                size_t alias_count,
                                V3ConstEnv *env,
                                char **lines,
                                size_t line_count,
                                size_t *index_io,
                                int32_t parent_indent,
                                V3ConstValue *out,
                                bool *returned,
                                V3ConstEntryProgram *entry_program,
                                bool *loop_break,
                                bool *loop_continue,
                                size_t depth) {
    while (*index_io < line_count) {
        char statement[8192];
        char raw_copy[4096];
        char *trimmed;
        int32_t indent;
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
        trimmed = v3_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            *index_io += 1U;
            continue;
        }
        indent = v3_line_indent(lines[*index_io]);
        if (indent <= parent_indent ||
            (indent <= 0 && v3_is_top_level_decl_start(trimmed))) {
            return true;
        }
        if (!v3_collect_statement_from_lines(lines, line_count, index_io, statement, sizeof(statement))) {
            return false;
        }
        if (v3_startswith(statement, "let ") || v3_startswith(statement, "var ")) {
            char name[128];
            char expr[4096];
            V3ConstValue bound;
            v3_const_value_init(&bound);
            if (!v3_const_parse_binding_name(statement,
                                             v3_startswith(statement, "let ") ? "let " : "var ",
                                             name,
                                             sizeof(name),
                                             expr,
                                             sizeof(expr)) ||
                !v3_const_eval_expr(lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    env,
                                    expr,
                                    &bound,
                                    depth + 1U) ||
                !v3_const_env_set(env, name, &bound)) {
                v3_const_value_free(&bound);
                return false;
            }
            v3_const_value_free(&bound);
            continue;
        }
        if (v3_startswith(statement, "if ") || v3_startswith(statement, "elif ")) {
            size_t body_start = *index_io;
            char inline_stmt[8192];
            char cond_text[4096];
            V3ConstValue cond;
            bool cond_truthy = false;
            v3_const_value_init(&cond);
            inline_stmt[0] = '\0';
            if (!(v3_startswith(statement, "if ") ?
                      v3_parse_if_header(statement,
                                         cond_text,
                                         sizeof(cond_text),
                                         inline_stmt,
                                         sizeof(inline_stmt)) :
                      v3_parse_elif_header(statement,
                                           cond_text,
                                           sizeof(cond_text),
                                           inline_stmt,
                                           sizeof(inline_stmt)))) {
                v3_const_value_free(&cond);
                return false;
            }
            if (!v3_const_eval_expr(lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    env,
                                    cond_text,
                                    &cond,
                                    depth + 1U) ||
                !v3_const_value_truthy(&cond, &cond_truthy)) {
                v3_const_value_free(&cond);
                return false;
            }
            if (cond_truthy) {
                size_t branch_index = body_start;
                if (!((inline_stmt[0] != '\0' &&
                       v3_const_eval_inline_statement(lowering,
                                                      function,
                                                      aliases,
                                                      alias_count,
                                                      env,
                                                      inline_stmt,
                                                      out,
                                                      returned,
                                                      entry_program,
                                                      loop_break,
                                                      loop_continue,
                                                      depth + 1U)) ||
                      (inline_stmt[0] == '\0' &&
                       v3_const_eval_block(lowering,
                                           function,
                                           aliases,
                                           alias_count,
                                           env,
                                           lines,
                                           line_count,
                                           &branch_index,
                                           indent,
                                           out,
                                           returned,
                                           entry_program,
                                           loop_break,
                                           loop_continue,
                                           depth + 1U))) ||
                    !v3_const_skip_following_if_branches(lines,
                                                         line_count,
                                                         &branch_index,
                                                         indent)) {
                    v3_const_value_free(&cond);
                    return false;
                }
                *index_io = branch_index;
                v3_const_value_free(&cond);
                if (*returned || (loop_break != NULL && *loop_break) ||
                    (loop_continue != NULL && *loop_continue)) {
                    return true;
                }
                continue;
            }
            if (inline_stmt[0] == '\0' &&
                !v3_const_skip_nested_block(lines, line_count, index_io, indent)) {
                v3_const_value_free(&cond);
                return false;
            }
            v3_const_value_free(&cond);
            continue;
        }
        if (v3_startswith(statement, "else")) {
            size_t branch_index = *index_io;
            char inline_stmt[8192];
            inline_stmt[0] = '\0';
            if (!v3_parse_else_header(statement, inline_stmt, sizeof(inline_stmt))) {
                return false;
            }
            if (!((inline_stmt[0] != '\0' &&
                   v3_const_eval_inline_statement(lowering,
                                                  function,
                                                  aliases,
                                                  alias_count,
                                                  env,
                                                  inline_stmt,
                                                  out,
                                                  returned,
                                                  entry_program,
                                                  loop_break,
                                                  loop_continue,
                                                  depth + 1U)) ||
                  (inline_stmt[0] == '\0' &&
                   v3_const_eval_block(lowering,
                                       function,
                                       aliases,
                                       alias_count,
                                       env,
                                       lines,
                                       line_count,
                                       &branch_index,
                                       indent,
                                       out,
                                       returned,
                                       entry_program,
                                       loop_break,
                                       loop_continue,
                                       depth + 1U)))) {
                return false;
            }
            *index_io = branch_index;
            if (*returned || (loop_break != NULL && *loop_break) ||
                (loop_continue != NULL && *loop_continue)) {
                return true;
            }
            continue;
        }
        if (v3_startswith(statement, "while ")) {
            char cond_text[4096];
            char inline_stmt[8192];
            size_t body_start = *index_io;
            size_t body_end = body_start;
            size_t iter_count = 0U;
            inline_stmt[0] = '\0';
            if (!v3_parse_while_header(statement,
                                       cond_text,
                                       sizeof(cond_text),
                                       inline_stmt,
                                       sizeof(inline_stmt))) {
                return false;
            }
            if (inline_stmt[0] == '\0' &&
                !v3_const_skip_nested_block(lines, line_count, &body_end, indent)) {
                return false;
            }
            while (true) {
                V3ConstValue cond;
                bool cond_truthy = false;
                bool broke = false;
                bool continued = false;
                v3_const_value_init(&cond);
                if (!v3_const_eval_expr(lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        env,
                                        cond_text,
                                        &cond,
                                        depth + 1U) ||
                    !v3_const_value_truthy(&cond, &cond_truthy)) {
                    v3_const_value_free(&cond);
                    return false;
                }
                if (!cond_truthy) {
                    v3_const_value_free(&cond);
                    break;
                }
                v3_const_value_free(&cond);
                iter_count += 1U;
                if (iter_count > CHENG_V3_CONST_MAX_LOOP_ITERS) {
                    return false;
                }
                if (inline_stmt[0] != '\0') {
                    if (!v3_const_eval_inline_statement(lowering,
                                                        function,
                                                        aliases,
                                                        alias_count,
                                                        env,
                                                        inline_stmt,
                                                        out,
                                                        returned,
                                                        entry_program,
                                                        &broke,
                                                        &continued,
                                                        depth + 1U)) {
                        return false;
                    }
                } else {
                    size_t loop_body_index = body_start;
                    if (!v3_const_eval_block(lowering,
                                             function,
                                             aliases,
                                             alias_count,
                                             env,
                                             lines,
                                             line_count,
                                             &loop_body_index,
                                             indent,
                                             out,
                                             returned,
                                             entry_program,
                                             &broke,
                                             &continued,
                                             depth + 1U)) {
                        return false;
                    }
                }
                if (*returned) {
                    *index_io = body_end;
                    return true;
                }
                if (broke) {
                    break;
                }
                if (continued) {
                    continue;
                }
            }
            *index_io = body_end;
            continue;
        }
        if (v3_startswith(statement, "for ")) {
            char iter_name[128];
            char start_expr[4096];
            char end_expr[4096];
            char inline_stmt[8192];
            bool end_inclusive = false;
            size_t body_start = *index_io;
            size_t body_end = body_start;
            int32_t start_i32 = 0;
            int32_t end_i32 = 0;
            int32_t iter_value;
            V3ConstValue start_value;
            V3ConstValue end_value;
            v3_const_value_init(&start_value);
            v3_const_value_init(&end_value);
            if (!v3_parse_for_header(statement,
                                     iter_name,
                                     sizeof(iter_name),
                                     start_expr,
                                     sizeof(start_expr),
                                     end_expr,
                                     sizeof(end_expr),
                                     &end_inclusive,
                                     inline_stmt,
                                     sizeof(inline_stmt)) ||
                !v3_const_eval_expr(lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    env,
                                    start_expr,
                                    &start_value,
                                    depth + 1U) ||
                !v3_const_eval_expr(lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    env,
                                    end_expr,
                                    &end_value,
                                    depth + 1U) ||
                !v3_const_value_as_i32(&start_value, &start_i32) ||
                !v3_const_value_as_i32(&end_value, &end_i32)) {
                v3_const_value_free(&start_value);
                v3_const_value_free(&end_value);
                return false;
            }
            v3_const_value_free(&start_value);
            v3_const_value_free(&end_value);
            if (inline_stmt[0] == '\0' &&
                !v3_const_skip_nested_block(lines, line_count, &body_end, indent)) {
                return false;
            }
            for (iter_value = start_i32;
                 end_inclusive ? (iter_value <= end_i32) : (iter_value < end_i32);
                 iter_value += 1) {
                V3ConstValue iter_const;
                bool broke = false;
                bool continued = false;
                v3_const_value_init(&iter_const);
                v3_const_value_set_i32(&iter_const, iter_value);
                if (!v3_const_env_set(env, iter_name, &iter_const)) {
                    v3_const_value_free(&iter_const);
                    return false;
                }
                v3_const_value_free(&iter_const);
                if (inline_stmt[0] != '\0') {
                    if (!v3_const_eval_inline_statement(lowering,
                                                        function,
                                                        aliases,
                                                        alias_count,
                                                        env,
                                                        inline_stmt,
                                                        out,
                                                        returned,
                                                        entry_program,
                                                        &broke,
                                                        &continued,
                                                        depth + 1U)) {
                        return false;
                    }
                } else {
                    size_t loop_body_index = body_start;
                    if (!v3_const_eval_block(lowering,
                                             function,
                                             aliases,
                                             alias_count,
                                             env,
                                             lines,
                                             line_count,
                                             &loop_body_index,
                                             indent,
                                             out,
                                             returned,
                                             entry_program,
                                             &broke,
                                             &continued,
                                             depth + 1U)) {
                        return false;
                    }
                }
                if (*returned) {
                    *index_io = body_end;
                    return true;
                }
                if (broke) {
                    break;
                }
                if (continued) {
                    continue;
                }
            }
            *index_io = body_end;
            continue;
        }
        if (v3_startswith(statement, "assert(")) {
            char callee[PATH_MAX];
            char args_text[32][4096];
            size_t statement_arg_count = 0U;
            V3ConstValue cond;
            bool cond_truthy = false;
            v3_const_value_init(&cond);
            if (!v3_parse_call_text(statement, callee, sizeof(callee), args_text, &statement_arg_count, 32U) ||
                strcmp(callee, "assert") != 0 ||
                statement_arg_count < 1U ||
                !v3_const_eval_expr(lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    env,
                                    args_text[0],
                                    &cond,
                                    depth + 1U) ||
                !v3_const_value_truthy(&cond, &cond_truthy) ||
                !cond_truthy) {
                v3_const_value_free(&cond);
                return false;
            }
            v3_const_value_free(&cond);
            continue;
        }
        if (strcmp(statement, "break") == 0) {
            if (loop_break == NULL) {
                return false;
            }
            *loop_break = true;
            return true;
        }
        if (strcmp(statement, "continue") == 0) {
            if (loop_continue == NULL) {
                return false;
            }
            *loop_continue = true;
            return true;
        }
        if (v3_startswith(statement, "return ")) {
            if (!v3_const_eval_expr(lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    env,
                                    statement + 7,
                                    out,
                                    depth + 1U)) {
                return false;
            }
            *returned = true;
            return true;
        }
        {
            char lhs[4096];
            char rhs[4096];
            if (v3_parse_assignment_meta(statement, lhs, sizeof(lhs), rhs, sizeof(rhs))) {
                V3ConstValue bound;
                v3_const_value_init(&bound);
                if (v3_const_env_get(env, lhs) == NULL ||
                    !v3_const_eval_expr(lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        env,
                                        rhs,
                                        &bound,
                                        depth + 1U) ||
                    !v3_const_env_set(env, lhs, &bound)) {
                    v3_const_value_free(&bound);
                    return false;
                }
                v3_const_value_free(&bound);
                continue;
            }
        }
        {
            char callee[PATH_MAX];
            char args_text[32][4096];
            size_t arg_count = 0U;
            if (!v3_parse_call_text(statement, callee, sizeof(callee), args_text, &arg_count, 32U)) {
                return false;
            }
            if (!v3_const_eval_call_statement(lowering,
                                              function,
                                              aliases,
                                              alias_count,
                                              env,
                                              statement,
                                              entry_program,
                                              depth + 1U)) {
                return false;
            }
            continue;
        }
    }
    return true;
}

static bool v3_const_eval_function(const V3LoweringPlanStub *lowering,
                                   const V3LoweredFunctionStub *function,
                                   const V3ConstValue *args,
                                   size_t arg_count,
                                   V3ConstValue *out,
                                   V3ConstEntryProgram *entry_program,
                                   size_t depth) {
    char **lines = NULL;
    char *owned_lines = NULL;
    size_t line_count = 0U;
    size_t fn_line_index = 0U;
    char (*param_names)[128] = NULL;
    size_t param_count = 0U;
    char source_path[PATH_MAX];
    V3ImportAlias *aliases = NULL;
    size_t alias_count = 0U;
    V3ConstEnv env;
    bool ok = false;
    bool returned = false;
    size_t block_index;
    size_t i;
    memset(&env, 0, sizeof(env));
    if (depth > 64U) {
        return false;
    }
    param_names = (char (*)[128])v3_xmalloc(sizeof(*param_names) * CHENG_V3_CONST_MAX_BINDINGS);
    aliases = (V3ImportAlias *)v3_xmalloc(sizeof(*aliases) * CHENG_V3_MAX_IMPORT_ALIASES);
    if (!v3_load_function_source_lines(function,
                                       &lines,
                                       &owned_lines,
                                       &line_count,
                                       &fn_line_index,
                                       param_names,
                                       &param_count,
                                       source_path)) {
        free(param_names);
        free(aliases);
        return false;
    }
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    if (!v3_const_env_load_top_level_vars(lowering,
                                          function,
                                          aliases,
                                          alias_count,
                                          lines,
                                          line_count,
                                          &env,
                                          depth + 1U)) {
        goto cleanup;
    }
    if (param_count != arg_count) {
        goto cleanup;
    }
    for (i = 0; i < arg_count; ++i) {
        if (!v3_const_env_set(&env, param_names[i], &args[i])) {
            goto cleanup;
        }
    }
    block_index = fn_line_index + 1U;
    ok = v3_const_eval_block(lowering,
                             function,
                             aliases,
                             alias_count,
                             &env,
                             lines,
                             line_count,
                             &block_index,
                             0,
                             out,
                             &returned,
                             entry_program,
                             NULL,
                             NULL,
                             depth + 1U) &&
         returned;
cleanup:
    v3_const_env_free(&env);
    free(lines);
    free(owned_lines);
    free(param_names);
    free(aliases);
    return ok;
}

static bool v3_try_consteval_entry_program(const V3SystemLinkPlanStub *plan,
                                           const V3LoweringPlanStub *lowering,
                                           V3ConstEntryProgram *program) {
    const V3LoweredFunctionStub *entry_function = v3_find_entry_lowered_function(lowering);
    V3ConstValue result;
    (void)plan;
    if (!entry_function) {
        return false;
    }
    memset(program, 0, sizeof(*program));
    v3_const_value_init(&result);
    if (!v3_const_eval_function(lowering,
                                entry_function,
                                NULL,
                                0U,
                                &result,
                                program,
                                0U) ||
        result.kind != V3_CONST_I32) {
        v3_const_value_free(&result);
        memset(program, 0, sizeof(*program));
        return false;
    }
    program->ready = true;
    program->return_code = result.i32_value;
    v3_const_value_free(&result);
    return true;
}

static bool v3_parent_dir(const char *path, char *out, size_t cap) {
    const char *slash;
    size_t len;
    if (!path || *path == '\0') {
        out[0] = '\0';
        return false;
    }
    slash = strrchr(path, '/');
    if (!slash) {
        out[0] = '\0';
        return false;
    }
    len = (size_t)(slash - path);
    if (len <= 0U || len >= cap) {
        out[0] = '\0';
        return false;
    }
    memcpy(out, path, len);
    out[len] = '\0';
    return true;
}

static void v3_join_path(char *out, size_t cap, const char *a, const char *b) {
    if (!a || *a == '\0') {
        v3_copy_text(out, cap, b ? b : "");
        return;
    }
    if (!b || *b == '\0') {
        v3_copy_text(out, cap, a);
        return;
    }
    if (b[0] == '/') {
        v3_copy_text(out, cap, b);
        return;
    }
    if (a[strlen(a) - 1U] == '/') {
        snprintf(out, cap, "%s%s", a, b);
        return;
    }
    snprintf(out, cap, "%s/%s", a, b);
}

static void v3_strip_ext(char *text) {
    char *dot = strrchr(text, '.');
    if (dot) {
        *dot = '\0';
    }
}

static void v3_contract_workspace_root(const V3BootstrapContract *contract, char *out, size_t cap) {
    char bootstrap_dir[PATH_MAX];
    char package_root[PATH_MAX];
    if (!v3_parent_dir(contract->source_path, bootstrap_dir, sizeof(bootstrap_dir)) ||
        !v3_parent_dir(bootstrap_dir, package_root, sizeof(package_root)) ||
        !v3_parent_dir(package_root, out, cap)) {
        out[0] = '\0';
    }
}

static void v3_contract_package_root(const V3BootstrapContract *contract, char *out, size_t cap) {
    char bootstrap_dir[PATH_MAX];
    if (!v3_parent_dir(contract->source_path, bootstrap_dir, sizeof(bootstrap_dir)) ||
        !v3_parent_dir(bootstrap_dir, out, cap)) {
        out[0] = '\0';
    }
}

static void v3_resolve_contract_path(const V3BootstrapContract *contract,
                                     const char *key,
                                     char *out,
                                     size_t cap) {
    char workspace_root[PATH_MAX];
    const char *value = v3_contract_get(contract, key);
    v3_contract_workspace_root(contract, workspace_root, sizeof(workspace_root));
    v3_join_path(out, cap, workspace_root, value ? value : "");
}

static void v3_default_package_root(const V3BootstrapContract *contract, char *out, size_t cap) {
    v3_contract_package_root(contract, out, cap);
}

static void v3_workspace_root_from_package_root(const char *package_root, char *out, size_t cap) {
    const char *slash = strrchr(package_root, '/');
    if (slash && strcmp(slash + 1, "v3") == 0) {
        v3_parent_dir(package_root, out, cap);
        return;
    }
    v3_copy_text(out, cap, package_root);
}

static void v3_package_id_from_root(const char *package_root, char *out, size_t cap) {
    const char *slash = strrchr(package_root, '/');
    const char *base = slash ? slash + 1 : package_root;
    if (strcmp(base, "v3") == 0) {
        v3_copy_text(out, cap, "cheng/v3");
        return;
    }
    snprintf(out, cap, "cheng/%s", base);
}

static bool v3_path_exists_nonempty(const char *path) {
    struct stat st;
    if (!path || *path == '\0') {
        return false;
    }
    if (stat(path, &st) != 0) {
        return false;
    }
    return S_ISREG(st.st_mode) && st.st_size > 0;
}

static bool v3_plan_paths_contains(const V3PlanPath *items, size_t len, const char *path) {
    size_t i;
    for (i = 0; i < len; ++i) {
        if (v3_streq(items[i].text, path)) {
            return true;
        }
    }
    return false;
}

static void v3_plan_add_reason(V3SystemLinkPlanStub *plan, const char *reason) {
    if (plan->missing_reason_count >= CHENG_V3_MAX_PLAN_REASONS) {
        return;
    }
    snprintf(plan->missing_reasons[plan->missing_reason_count],
             sizeof(plan->missing_reasons[plan->missing_reason_count]),
             "%s",
             reason);
    plan->missing_reason_count += 1U;
}

