static bool v3_plan_reasons_contains(char reasons[CHENG_V3_MAX_PLAN_REASONS][128],
                                     size_t reason_count,
                                     const char *reason) {
    size_t i;
    for (i = 0; i < reason_count; ++i) {
        if (strcmp(reasons[i], reason) == 0) {
            return true;
        }
    }
    return false;
}

static void v3_plan_add_path(V3PlanPath *items, size_t *len, size_t cap, const char *path) {
    if (*len >= cap) {
        return;
    }
    snprintf(items[*len].text, sizeof(items[*len].text), "%s", path);
    *len += 1U;
}

static bool v3_plan_import_edge_exists(const V3SystemLinkPlanStub *plan,
                                       const V3PlanImportEdge *edge) {
    size_t i;
    for (i = 0U; i < plan->import_edge_count; ++i) {
        if (v3_streq(plan->import_edges[i].owner_module_path, edge->owner_module_path) &&
            v3_streq(plan->import_edges[i].target_module_path, edge->target_module_path) &&
            v3_streq(plan->import_edges[i].target_source_path, edge->target_source_path) &&
            plan->import_edges[i].resolved == edge->resolved) {
            return true;
        }
    }
    return false;
}

static void v3_populate_runtime_requirements(V3SystemLinkPlanStub *plan) {
    if (!v3_streq(plan->emit_kind, "exe")) {
        return;
    }
    if (!v3_target_needs_native_runtime_providers(plan->target_triple)) {
        v3_plan_add_path(plan->runtime_targets,
                         &plan->runtime_target_count,
                         CHENG_V3_MAX_RUNTIME_TARGETS,
                         "runtime/compiler.program_wasm_entry");
        return;
    }
    if (v3_streq(plan->module_kind, "compiler_control_plane")) {
        v3_plan_add_path(plan->runtime_targets,
                         &plan->runtime_target_count,
                         CHENG_V3_MAX_RUNTIME_TARGETS,
                         "runtime/compiler.tooling_argv_entry");
    } else {
        v3_plan_add_path(plan->runtime_targets,
                         &plan->runtime_target_count,
                         CHENG_V3_MAX_RUNTIME_TARGETS,
                         "runtime/compiler.program_argv_entry");
    }
    if (!v3_target_requires_native_provider_modules(plan->target_triple)) {
        return;
    }
    v3_plan_add_path(plan->provider_modules,
                     &plan->provider_module_count,
                     CHENG_V3_MAX_PROVIDER_MODULES,
                     "runtime/compiler_runtime_v3");
    v3_plan_add_path(plan->provider_modules,
                     &plan->provider_module_count,
                     CHENG_V3_MAX_PROVIDER_MODULES,
                     "runtime/core_runtime_v3");
    v3_plan_add_path(plan->provider_modules,
                     &plan->provider_module_count,
                     CHENG_V3_MAX_PROVIDER_MODULES,
                     "runtime/program_support_v3");
}

static void v3_source_path_to_module_path(const char *workspace_root,
                                          const char *package_root,
                                          const char *package_id,
                                          const char *source_path,
                                          char *out,
                                          size_t cap) {
    char prefix[PATH_MAX];
    char rel[PATH_MAX];
    char stem[PATH_MAX];
    const char *last_slash;
    snprintf(prefix, sizeof(prefix), "%s/src/", package_root);
    if (v3_startswith(source_path, prefix)) {
        snprintf(rel, sizeof(rel), "%s", source_path + strlen(prefix));
        v3_strip_ext(rel);
        snprintf(out, cap, "%s/%s", package_id, rel);
        return;
    }
    snprintf(prefix, sizeof(prefix), "%s/src/std/", workspace_root);
    if (v3_startswith(source_path, prefix)) {
        snprintf(rel, sizeof(rel), "%s", source_path + strlen(prefix));
        v3_strip_ext(rel);
        snprintf(out, cap, "std/%s", rel);
        return;
    }
    last_slash = strrchr(source_path, '/');
    snprintf(stem, sizeof(stem), "%s", last_slash ? last_slash + 1 : source_path);
    v3_strip_ext(stem);
    v3_copy_text(out, cap, stem);
}

static void v3_module_path_to_source_path(const char *workspace_root,
                                          const char *package_root,
                                          const char *package_id,
                                          const char *module_path,
                                          char *out,
                                          size_t cap) {
    out[0] = '\0';
    if (v3_startswith(module_path, "std/")) {
        char rel[PATH_MAX];
        snprintf(rel, sizeof(rel), "src/%s.cheng", module_path);
        v3_join_path(out, cap, workspace_root, rel);
        return;
    }
    if (v3_startswith(module_path, "core/")) {
        char rel[PATH_MAX];
        snprintf(rel, sizeof(rel), "src/%s.cheng", module_path);
        v3_join_path(out, cap, workspace_root, rel);
        return;
    }
    if (v3_streq(module_path, package_id) ||
        (v3_startswith(module_path, package_id) && module_path[strlen(package_id)] == '/')) {
        const char *tail = module_path + strlen(package_id);
        char rel[PATH_MAX];
        if (*tail == '/') {
            tail++;
        }
        snprintf(rel, sizeof(rel), "src/%s.cheng", tail);
        v3_join_path(out, cap, package_root, rel);
        return;
    }
}

static bool v3_source_has_top_level(const char *text) {
    char *owned = v3_strdup(text);
    char *cursor = owned;
    char *line;
    bool out = false;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        char *trimmed = v3_trim_inplace(line);
        if (v3_startswith(trimmed, "import ") ||
            v3_startswith(trimmed, "type") ||
            v3_startswith(trimmed, "fn ") ||
            v3_startswith(trimmed, "iterator ") ||
            v3_startswith(trimmed, "const ") ||
            v3_startswith(trimmed, "let ") ||
            v3_startswith(trimmed, "var ")) {
            out = true;
            break;
        }
    }
    free(owned);
    return out;
}

static bool v3_source_has_main(const char *text) {
    char *owned = v3_strdup(text);
    char *cursor = owned;
    char *line;
    bool out = false;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        char *trimmed = v3_trim_inplace(line);
        if (v3_startswith(trimmed, "fn main(")) {
            out = true;
            break;
        }
    }
    free(owned);
    return out;
}

static bool v3_parse_import_edges(const char *workspace_root,
                                  const char *package_root,
                                  const char *package_id,
                                  const char *owner_module_path,
                                  const char *text,
                                  V3PlanImportEdge *edges,
                                  size_t *edge_len,
                                  size_t edge_cap) {
    char *owned = v3_strdup(text);
    char *cursor = owned;
    char *line;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        char *trimmed = v3_trim_inplace(line);
        char *token;
        if (!v3_startswith(trimmed, "import ")) {
            continue;
        }
        token = trimmed + strlen("import ");
        while (*token != '\0' && isspace((unsigned char)*token)) {
            token++;
        }
        if (*token == '\0') {
            free(owned);
            return false;
        }
        {
            char module_path[PATH_MAX];
            char *stop = token;
            while (*stop != '\0' && !isspace((unsigned char)*stop)) {
                stop++;
            }
            if (*stop != '\0') {
                *stop = '\0';
            }
            snprintf(module_path, sizeof(module_path), "%s", token);
            if (*edge_len >= edge_cap) {
                free(owned);
                return false;
            }
            snprintf(edges[*edge_len].owner_module_path, sizeof(edges[*edge_len].owner_module_path), "%s", owner_module_path);
            snprintf(edges[*edge_len].target_module_path, sizeof(edges[*edge_len].target_module_path), "%s", module_path);
            v3_module_path_to_source_path(workspace_root,
                                          package_root,
                                          package_id,
                                          module_path,
                                          edges[*edge_len].target_source_path,
                                          sizeof(edges[*edge_len].target_source_path));
            edges[*edge_len].resolved = v3_path_exists_nonempty(edges[*edge_len].target_source_path);
            *edge_len += 1U;
        }
    }
    free(owned);
    return true;
}

static bool v3_ident_start_char(char ch) {
    return (ch >= 'a' && ch <= 'z') ||
           (ch >= 'A' && ch <= 'Z') ||
           ch == '_';
}

static bool v3_ident_char(char ch) {
    return v3_ident_start_char(ch) ||
           (ch >= '0' && ch <= '9');
}

static const char *v3_module_default_alias(const char *module_path) {
    const char *slash = strrchr(module_path, '/');
    return slash ? slash + 1 : module_path;
}

static void v3_parse_import_aliases_from_lines(char **lines,
                                               size_t line_count,
                                               V3ImportAlias *aliases,
                                               size_t *alias_count,
                                               size_t alias_cap) {
    size_t i;
    *alias_count = 0U;
    for (i = 0; i < line_count; ++i) {
        char *trimmed = v3_trim_inplace(lines[i]);
        char *cursor;
        char module_path[PATH_MAX];
        char alias_text[128];
        char *space;
        if (!v3_startswith(trimmed, "import ")) {
            continue;
        }
        cursor = trimmed + strlen("import ");
        while (*cursor != '\0' && isspace((unsigned char)*cursor)) {
            cursor++;
        }
        if (*cursor == '\0') {
            continue;
        }
        if (strchr(cursor, '[') != NULL) {
            continue;
        }
        space = cursor;
        while (*space != '\0' && !isspace((unsigned char)*space)) {
            space++;
        }
        if (space == cursor) {
            continue;
        }
        snprintf(module_path, sizeof(module_path), "%.*s", (int)(space - cursor), cursor);
        snprintf(alias_text, sizeof(alias_text), "%s", v3_module_default_alias(module_path));
        while (*space != '\0' && isspace((unsigned char)*space)) {
            space++;
        }
        if (v3_startswith(space, "as ")) {
            char *alias_cursor = space + 3;
            char *alias_stop = alias_cursor;
            while (*alias_cursor != '\0' && isspace((unsigned char)*alias_cursor)) {
                alias_cursor++;
            }
            alias_stop = alias_cursor;
            while (*alias_stop != '\0' && !isspace((unsigned char)*alias_stop)) {
                alias_stop++;
            }
            if (alias_stop > alias_cursor) {
                snprintf(alias_text, sizeof(alias_text), "%.*s", (int)(alias_stop - alias_cursor), alias_cursor);
            }
        }
        if (*alias_count >= alias_cap) {
            return;
        }
        snprintf(aliases[*alias_count].alias_text, sizeof(aliases[*alias_count].alias_text), "%s", alias_text);
        snprintf(aliases[*alias_count].module_path, sizeof(aliases[*alias_count].module_path), "%s", module_path);
        *alias_count += 1U;
    }
}

static bool v3_load_import_aliases_from_source_path(const char *source_path,
                                                    V3ImportAlias *aliases,
                                                    size_t *alias_count,
                                                    size_t alias_cap) {
    char *owned;
    char *cursor;
    char *line;
    char *lines[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t line_count = 0U;
    owned = v3_read_file(source_path);
    if (!owned) {
        return false;
    }
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(owned);
            return false;
        }
        lines[line_count++] = line;
    }
    v3_parse_import_aliases_from_lines(lines, line_count, aliases, alias_count, alias_cap);
    free(owned);
    return true;
}

static const char *v3_alias_module_path(const V3ImportAlias *aliases,
                                        size_t alias_count,
                                        const char *alias_text) {
    size_t i;
    for (i = 0; i < alias_count; ++i) {
        if (strcmp(aliases[i].alias_text, alias_text) == 0) {
            return aliases[i].module_path;
        }
    }
    return NULL;
}

static bool v3_is_intrinsic_call_name(const char *name) {
    static const char *NAMES[] = {
        "assert",
        "echo",
        "len",
        "IsOk",
        "IsErr",
        "Value",
        "Error",
        "ErrorText",
        "ErrorInfoOf",
        "int",
        "int8",
        "int16",
        "int32",
        "int64",
        "uint8",
        "uint16",
        "uint32",
        "uint64",
        "bool",
        "char",
        "float",
        "float32",
        "float64",
        "str",
        "cstring",
        "ptr",
        "new"
    };
    size_t i;
    for (i = 0; i < sizeof(NAMES) / sizeof(NAMES[0]); ++i) {
        if (strcmp(NAMES[i], name) == 0) {
            return true;
        }
    }
    return false;
}

static bool v3_is_intrinsic_module_call(const char *module_path, const char *function_name) {
    if (strcmp(module_path, "std/os") == 0 &&
        (strcmp(function_name, "isAbsolute") == 0 ||
         strcmp(function_name, "joinPath") == 0 ||
         strcmp(function_name, "getEnvDefault") == 0 ||
         strcmp(function_name, "fileExists") == 0)) {
        return true;
    }
    if (strcmp(module_path, "std/strutils") == 0 &&
        strcmp(function_name, "strip") == 0) {
        return true;
    }
    return false;
}

static bool v3_resolve_intrinsic_module_call_target(const char *module_path,
                                                    const V3SystemLinkPlanStub *plan,
                                                    const char *function_name,
                                                    V3AsmCallTarget *target) {
    memset(target, 0, sizeof(*target));
    target->external = true;
    if (strcmp(module_path, "std/strutils") == 0 &&
        strcmp(function_name, "strip") == 0) {
        snprintf(target->callee_name, sizeof(target->callee_name), "%s", "strip");
        v3_copy_target_symbol_name(plan,
                                   "cheng_v3_str_strip_bridge",
                                   target->symbol_name,
                                   sizeof(target->symbol_name));
        snprintf(target->return_type, sizeof(target->return_type), "%s", "str");
        snprintf(target->return_abi_class, sizeof(target->return_abi_class), "%s", "composite");
        target->param_count = 1U;
        snprintf(target->param_types[0], sizeof(target->param_types[0]), "%s", "str");
        snprintf(target->param_abi_classes[0], sizeof(target->param_abi_classes[0]), "%s", "composite");
        return true;
    }
    if (strcmp(module_path, "std/os") == 0 &&
        strcmp(function_name, "isAbsolute") == 0) {
        snprintf(target->callee_name, sizeof(target->callee_name), "%s", "isAbsolute");
        v3_copy_target_symbol_name(plan,
                                   "cheng_v3_os_is_absolute_bridge",
                                   target->symbol_name,
                                   sizeof(target->symbol_name));
        snprintf(target->return_type, sizeof(target->return_type), "%s", "bool");
        snprintf(target->return_abi_class, sizeof(target->return_abi_class), "%s", "bool");
        target->param_count = 1U;
        snprintf(target->param_types[0], sizeof(target->param_types[0]), "%s", "str");
        snprintf(target->param_abi_classes[0], sizeof(target->param_abi_classes[0]), "%s", "composite");
        return true;
    }
    if (strcmp(module_path, "std/os") == 0 &&
        strcmp(function_name, "joinPath") == 0) {
        snprintf(target->callee_name, sizeof(target->callee_name), "%s", "joinPath");
        v3_copy_target_symbol_name(plan,
                                   "cheng_v3_os_join_path_bridge",
                                   target->symbol_name,
                                   sizeof(target->symbol_name));
        snprintf(target->return_type, sizeof(target->return_type), "%s", "str");
        snprintf(target->return_abi_class, sizeof(target->return_abi_class), "%s", "composite");
        target->param_count = 2U;
        snprintf(target->param_types[0], sizeof(target->param_types[0]), "%s", "str");
        snprintf(target->param_types[1], sizeof(target->param_types[1]), "%s", "str");
        snprintf(target->param_abi_classes[0], sizeof(target->param_abi_classes[0]), "%s", "composite");
        snprintf(target->param_abi_classes[1], sizeof(target->param_abi_classes[1]), "%s", "composite");
        return true;
    }
    return false;
}

static bool v3_is_builtin_statement_call_name(const char *callee) {
    if (!callee || *callee == '\0') {
        return false;
    }
    return strcmp(callee, "add") == 0 ||
           strcmp(callee, "assert") == 0 ||
           strcmp(callee, "echo") == 0 ||
           strcmp(callee, "panic") == 0 ||
           strcmp(callee, "system.panic") == 0 ||
           strcmp(callee, "store") == 0;
}

static void v3_lowered_function_add_callee(V3LoweredFunctionStub *function,
                                           const char *symbol_text) {
    size_t i;
    if (!symbol_text || *symbol_text == '\0') {
        return;
    }
    for (i = 0; i < function->callee_count; ++i) {
        if (strcmp(function->callee_symbols[i].text, symbol_text) == 0) {
            return;
        }
    }
    if (function->callee_count >= CHENG_V3_MAX_CALLEES) {
        return;
    }
    snprintf(function->callee_symbols[function->callee_count].text,
             sizeof(function->callee_symbols[function->callee_count].text),
             "%s",
             symbol_text);
    function->callee_count += 1U;
}

static void v3_lowered_function_add_all_callees_by_name(const V3LoweringPlanStub *lowering,
                                                        V3LoweredFunctionStub *function,
                                                        const char *function_name) {
    size_t i;
    if (!function_name || *function_name == '\0') {
        return;
    }
    for (i = 0; i < lowering->function_count; ++i) {
        if (strcmp(lowering->functions[i].function_name, function_name) == 0) {
            v3_lowered_function_add_callee(function, lowering->functions[i].symbol_text);
        }
    }
}

static int32_t v3_find_lowered_function_index_by_symbol_scan(const V3LoweringPlanStub *lowering,
                                                             const char *symbol_text) {
    size_t i;
    for (i = 0; i < lowering->function_count; ++i) {
        if (strcmp(lowering->functions[i].symbol_text, symbol_text) == 0) {
            return (int32_t)i;
        }
    }
    return -1;
}

static size_t v3_count_lowered_functions_by_module_and_name(const V3LoweringPlanStub *lowering,
                                                            const char *module_path,
                                                            const char *function_name) {
    size_t i;
    size_t count = 0U;
    for (i = 0; i < lowering->function_count; ++i) {
        if (strcmp(lowering->functions[i].owner_module_path, module_path) == 0 &&
            strcmp(lowering->functions[i].function_name, function_name) == 0) {
            count += 1U;
        }
    }
    return count;
}

static size_t v3_count_lowered_functions_by_name(const V3LoweringPlanStub *lowering,
                                                 const char *function_name) {
    size_t i;
    size_t count = 0U;
    for (i = 0; i < lowering->function_count; ++i) {
        if (strcmp(lowering->functions[i].function_name, function_name) == 0) {
            count += 1U;
        }
    }
    return count;
}

static int32_t v3_find_unique_lowered_function_index_by_name(const V3LoweringPlanStub *lowering,
                                                             const char *function_name) {
    size_t i;
    int32_t found = -1;
    for (i = 0; i < lowering->function_count; ++i) {
        if (strcmp(lowering->functions[i].function_name, function_name) == 0) {
            if (found >= 0) {
                return -2;
            }
            found = (int32_t)i;
        }
    }
    return found;
}

static bool v3_resolve_bare_call_symbol(const V3LoweringPlanStub *lowering,
                                        const char *owner_module_path,
                                        const V3ImportAlias *aliases,
                                        size_t alias_count,
                                        const char *function_name,
                                        char *out,
                                        size_t cap) {
    size_t i;
    size_t match_count = 0U;
    char candidate[PATH_MAX];
    if (!lowering || !owner_module_path || !function_name || !out || cap == 0U) {
        return false;
    }
    if (owner_module_path[0] == '\0' || function_name[0] == '\0') {
        out[0] = '\0';
        return false;
    }
    if (v3_count_lowered_functions_by_module_and_name(lowering, owner_module_path, function_name) == 1U) {
        snprintf(candidate, sizeof(candidate), "%s::%s", owner_module_path, function_name);
        snprintf(out, cap, "%s", candidate);
        return true;
    }
    out[0] = '\0';
    (void)aliases;
    (void)alias_count;
    if (match_count == 1U) {
        return true;
    }
    if (v3_count_lowered_functions_by_name(lowering, function_name) == 1U) {
        int32_t global_index = v3_find_unique_lowered_function_index_by_name(lowering, function_name);
        if (global_index >= 0 && lowering->functions[global_index].symbol_text[0] != '\0') {
            snprintf(out, cap, "%s", lowering->functions[global_index].symbol_text);
            return true;
        }
    }
    return false;
}

static void v3_strip_trailing_type_args_text(const char *text, char *out, size_t cap) {
    char trimmed[PATH_MAX];
    int32_t depth = 0;
    int32_t open_index = -1;
    size_t i;
    size_t len;
    v3_trim_copy_text(text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    for (i = 0; i < len; ++i) {
        if (trimmed[i] == '[') {
            if (depth == 0) {
                open_index = (int32_t)i;
            }
            depth += 1;
            continue;
        }
        if (trimmed[i] == ']') {
            if (depth > 0) {
                depth -= 1;
            }
            continue;
        }
    }
    if (open_index > 0 && len > 0U && trimmed[len - 1U] == ']' && depth == 0) {
        snprintf(out, cap, "%.*s", open_index, trimmed);
        v3_trim_copy_text(out, out, cap);
        return;
    }
    v3_copy_text(out, cap, trimmed);
}

static bool v3_extract_trailing_type_arg_text(const char *text, char *out, size_t cap) {
    char trimmed[PATH_MAX];
    int32_t depth = 0;
    int32_t open_index = -1;
    size_t i;
    size_t len;
    v3_trim_copy_text(text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    for (i = 0; i < len; ++i) {
        if (trimmed[i] == '[') {
            if (depth == 0) {
                open_index = (int32_t)i;
            }
            depth += 1;
            continue;
        }
        if (trimmed[i] == ']') {
            if (depth == 0) {
                return false;
            }
            depth -= 1;
            continue;
        }
    }
    if (open_index <= 0 || len <= (size_t)open_index + 1U || trimmed[len - 1U] != ']' || depth != 0) {
        return false;
    }
    snprintf(out, cap, "%.*s", (int)(len - (size_t)open_index - 2U), trimmed + open_index + 1);
    v3_trim_copy_text(out, out, cap);
    return out[0] != '\0';
}

static V3ResultIntrinsicKind v3_result_intrinsic_kind_from_name(const char *function_name) {
    if (strcmp(function_name, "IsOk") == 0) {
        return V3_RESULT_INTRINSIC_IS_OK;
    }
    if (strcmp(function_name, "IsErr") == 0) {
        return V3_RESULT_INTRINSIC_IS_ERR;
    }
    if (strcmp(function_name, "Value") == 0) {
        return V3_RESULT_INTRINSIC_VALUE;
    }
    if (strcmp(function_name, "Error") == 0) {
        return V3_RESULT_INTRINSIC_ERROR;
    }
    if (strcmp(function_name, "ErrorText") == 0) {
        return V3_RESULT_INTRINSIC_ERROR_TEXT;
    }
    if (strcmp(function_name, "ErrorInfoOf") == 0) {
        return V3_RESULT_INTRINSIC_ERROR_INFO_OF;
    }
    if (strcmp(function_name, "Ok") == 0) {
        return V3_RESULT_INTRINSIC_OK;
    }
    if (strcmp(function_name, "Err") == 0) {
        return V3_RESULT_INTRINSIC_ERR;
    }
    if (strcmp(function_name, "ErrCode") == 0) {
        return V3_RESULT_INTRINSIC_ERR_CODE;
    }
    if (strcmp(function_name, "ErrInfo") == 0) {
        return V3_RESULT_INTRINSIC_ERR_INFO;
    }
    return V3_RESULT_INTRINSIC_NONE;
}

static V3ResultIntrinsicKind v3_resolve_result_intrinsic_kind(const V3LoweringPlanStub *lowering,
                                                              const char *owner_module_path,
                                                              const V3ImportAlias *aliases,
                                                              size_t alias_count,
                                                              const char *callee) {
    char stripped[PATH_MAX];
    char resolved_symbol[PATH_MAX];
    char module_or_alias[PATH_MAX];
    char function_name[128];
    char direct[PATH_MAX];
    char *dot;
    char *scope;
    V3ResultIntrinsicKind kind;
    v3_strip_trailing_type_args_text(callee, stripped, sizeof(stripped));
    if (stripped[0] == '\0') {
        return V3_RESULT_INTRINSIC_NONE;
    }
    snprintf(direct, sizeof(direct), "%s", stripped);
    scope = strrchr(direct, ':');
    if (scope && scope != direct && scope[-1] == ':') {
        scope[-1] = '\0';
        kind = v3_result_intrinsic_kind_from_name(scope + 1);
        if (kind != V3_RESULT_INTRINSIC_NONE && strcmp(direct, "std/result") == 0) {
            return kind;
        }
        return V3_RESULT_INTRINSIC_NONE;
    }
    snprintf(module_or_alias, sizeof(module_or_alias), "%s", stripped);
    dot = strchr(module_or_alias, '.');
    if (dot) {
        const char *module_path;
        *dot = '\0';
        snprintf(function_name, sizeof(function_name), "%s", dot + 1);
        kind = v3_result_intrinsic_kind_from_name(function_name);
        if (kind == V3_RESULT_INTRINSIC_NONE) {
            return V3_RESULT_INTRINSIC_NONE;
        }
        module_path = v3_alias_module_path(aliases, alias_count, module_or_alias);
        if (module_path && strcmp(module_path, "std/result") == 0) {
            return kind;
        }
        return V3_RESULT_INTRINSIC_NONE;
    }
    kind = v3_result_intrinsic_kind_from_name(stripped);
    if (kind == V3_RESULT_INTRINSIC_NONE) {
        return V3_RESULT_INTRINSIC_NONE;
    }
    (void)lowering;
    (void)owner_module_path;
    (void)aliases;
    (void)alias_count;
    resolved_symbol[0] = '\0';
    return kind;
}

static void v3_collect_calls_from_text_resolved(const char *expr_text,
                                                const char *owner_module_path,
                                                const V3ImportAlias *aliases,
                                                size_t alias_count,
                                                const V3LoweringPlanStub *lowering,
                                                V3LoweredFunctionStub *function) {
    const char *cursor = expr_text;
    bool in_string = false;
    while (*cursor != '\0') {
        if (*cursor == '"') {
            in_string = !in_string;
            cursor++;
            continue;
        }
        if (in_string) {
            cursor++;
            continue;
        }
        if (v3_ident_start_char(*cursor)) {
            const char *start = cursor;
            const char *stop = cursor + 1;
            char token[PATH_MAX];
            char resolved_symbol[PATH_MAX];
            const char *lookahead;
            while (*stop != '\0') {
                if (*stop == '.') {
                    if (!v3_ident_start_char(stop[1])) {
                        break;
                    }
                    stop++;
                    while (v3_ident_char(*stop)) {
                        stop++;
                    }
                    continue;
                }
                if (!v3_ident_char(*stop)) {
                    break;
                }
                stop++;
            }
            snprintf(token, sizeof(token), "%.*s", (int)(stop - start), start);
            lookahead = stop;
            while (*lookahead != '\0' && isspace((unsigned char)*lookahead)) {
                lookahead++;
            }
            if (*lookahead == '(') {
                if (v3_is_builtin_statement_call_name(token)) {
                    cursor = stop;
                    continue;
                }
                char *dot = strchr(token, '.');
                V3ResultIntrinsicKind result_kind =
                    v3_resolve_result_intrinsic_kind(lowering,
                                                     owner_module_path,
                                                     aliases,
                                                     alias_count,
                                                     token);
                if (dot) {
                    char alias_text[128];
                    char function_name[128];
                    const char *module_path;
                    snprintf(alias_text, sizeof(alias_text), "%.*s", (int)(dot - token), token);
                    snprintf(function_name, sizeof(function_name), "%s", dot + 1);
                    module_path = v3_alias_module_path(aliases, alias_count, alias_text);
                    if (module_path &&
                        !v3_is_intrinsic_module_call(module_path, function_name) &&
                        v3_result_intrinsic_kind_from_name(function_name) == V3_RESULT_INTRINSIC_NONE &&
                        v3_count_lowered_functions_by_module_and_name(lowering, module_path, function_name) == 1U) {
                        snprintf(resolved_symbol, sizeof(resolved_symbol), "%s::%s", module_path, function_name);
                        if (v3_find_lowered_function_index_by_symbol_scan(lowering, resolved_symbol) >= 0) {
                            v3_lowered_function_add_callee(function, resolved_symbol);
                        }
                    }
                } else if (!v3_is_intrinsic_call_name(token) &&
                           result_kind == V3_RESULT_INTRINSIC_NONE &&
                           v3_resolve_bare_call_symbol(lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       token,
                                                       resolved_symbol,
                                                       sizeof(resolved_symbol))) {
                    v3_lowered_function_add_callee(function, resolved_symbol);
                } else if (!v3_is_intrinsic_call_name(token) &&
                           result_kind == V3_RESULT_INTRINSIC_NONE) {
                    v3_lowered_function_add_all_callees_by_name(lowering, function, token);
                }
            } else if (*lookahead != '\0' &&
                       (v3_ident_start_char(*lookahead) ||
                        isdigit((unsigned char)*lookahead) ||
                        *lookahead == '"' ||
                        *lookahead == '-' ||
                        *lookahead == '!' ||
                        *lookahead == '[')) {
                if (v3_is_builtin_statement_call_name(token)) {
                    cursor = stop;
                    continue;
                }
                char *dot = strchr(token, '.');
                V3ResultIntrinsicKind result_kind =
                    v3_resolve_result_intrinsic_kind(lowering,
                                                     owner_module_path,
                                                     aliases,
                                                     alias_count,
                                                     token);
                if (dot) {
                    char alias_text[128];
                    char function_name[128];
                    const char *module_path;
                    snprintf(alias_text, sizeof(alias_text), "%.*s", (int)(dot - token), token);
                    snprintf(function_name, sizeof(function_name), "%s", dot + 1);
                    module_path = v3_alias_module_path(aliases, alias_count, alias_text);
                    if (module_path &&
                        !v3_is_intrinsic_module_call(module_path, function_name) &&
                        v3_result_intrinsic_kind_from_name(function_name) == V3_RESULT_INTRINSIC_NONE &&
                        v3_count_lowered_functions_by_module_and_name(lowering, module_path, function_name) == 1U) {
                        snprintf(resolved_symbol, sizeof(resolved_symbol), "%s::%s", module_path, function_name);
                        if (v3_find_lowered_function_index_by_symbol_scan(lowering, resolved_symbol) >= 0) {
                            v3_lowered_function_add_callee(function, resolved_symbol);
                        }
                    }
                } else if (!v3_is_intrinsic_call_name(token) &&
                           result_kind == V3_RESULT_INTRINSIC_NONE &&
                           v3_resolve_bare_call_symbol(lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       token,
                                                       resolved_symbol,
                                                       sizeof(resolved_symbol))) {
                    v3_lowered_function_add_callee(function, resolved_symbol);
                } else if (!v3_is_intrinsic_call_name(token) &&
                           result_kind == V3_RESULT_INTRINSIC_NONE) {
                    v3_lowered_function_add_all_callees_by_name(lowering, function, token);
                }
            }
            cursor = stop;
            continue;
        }
        cursor++;
    }
}

static bool v3_lowering_function_name_from_line(char *trimmed, char *out, size_t cap) {
    char *token;
    char *stop;
    out[0] = '\0';
    if (!v3_startswith(trimmed, "fn ")) {
        return false;
    }
    token = trimmed + 3;
    while (*token != '\0' && isspace((unsigned char)*token)) {
        token++;
    }
    if (*token == '\0') {
        return false;
    }
    stop = token;
    while (*stop != '\0' &&
           *stop != '(' &&
           *stop != ' ' &&
           *stop != '\t') {
        stop++;
    }
    if (stop == token) {
        return false;
    }
    *stop = '\0';
    snprintf(out, cap, "%s", token);
    return true;
}

static bool v3_importc_function_name_from_line(char *trimmed, char *out, size_t cap) {
    char *token;
    char *stop;
    out[0] = '\0';
    if (!v3_startswith(trimmed, "importc fn ")) {
        return false;
    }
    token = trimmed + 10;
    while (*token != '\0' && isspace((unsigned char)*token)) {
        token++;
    }
    if (*token == '\0') {
        return false;
    }
    stop = token;
    while (*stop != '\0' &&
           *stop != '(' &&
           *stop != ' ' &&
           *stop != '\t') {
        stop++;
    }
    if (stop == token) {
        return false;
    }
    *stop = '\0';
    snprintf(out, cap, "%s", token);
    return true;
}

static bool v3_importc_symbol_from_annotation(char *trimmed, char *out, size_t cap) {
    char *open_quote;
    char *close_quote;
    if (!v3_startswith(trimmed, "@importc(")) {
        return false;
    }
    out[0] = '\0';
    open_quote = strchr(trimmed, '"');
    if (open_quote == NULL) {
        return false;
    }
    close_quote = strchr(open_quote + 1, '"');
    if (close_quote == NULL || close_quote == open_quote + 1) {
        return false;
    }
    *close_quote = '\0';
    snprintf(out, cap, "%s", open_quote + 1);
    return true;
}

static bool v3_exportc_symbol_from_annotation(char *trimmed, char *out, size_t cap) {
    char *open_quote;
    char *close_quote;
    if (!v3_startswith(trimmed, "@exportc(") &&
        !v3_startswith(trimmed, "@ exportc(")) {
        return false;
    }
    out[0] = '\0';
    open_quote = strchr(trimmed, '"');
    if (open_quote == NULL) {
        return false;
    }
    close_quote = strchr(open_quote + 1, '"');
    if (close_quote == NULL || close_quote == open_quote + 1) {
        return false;
    }
    *close_quote = '\0';
    snprintf(out, cap, "%s", open_quote + 1);
    return true;
}

static bool v3_parse_importc_signature_meta(const char *line,
                                            const char *function_name,
                                            V3LoweredFunctionStub *function) {
    char line_copy[4096];
    char fake_signature[4096];
    char *trimmed;
    snprintf(line_copy, sizeof(line_copy), "%s", line);
    trimmed = v3_trim_inplace(line_copy);
    if (v3_startswith(trimmed, "importc fn ")) {
        snprintf(fake_signature, sizeof(fake_signature), "%s = 0", trimmed + 8);
        return v3_parse_function_signature_meta(fake_signature, function_name, function);
    }
    if (!v3_startswith(trimmed, "fn ")) {
        return false;
    }
    snprintf(fake_signature, sizeof(fake_signature), "%s = 0", trimmed);
    return v3_parse_function_signature_meta(fake_signature, function_name, function);
}

static bool v3_resolve_importc_call_target_from_source_path(const V3SystemLinkPlanStub *plan,
                                                            const V3LoweringPlanStub *lowering,
                                                            const char *source_path,
                                                            const char *callee,
                                                            V3AsmCallTarget *target) {
    char *owned = NULL;
    char owner_module_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    V3LoweredFunctionStub probe;
    char pending_symbol[PATH_MAX];
    char pending_annotation_name[128];
    if (source_path == NULL || source_path[0] == '\0' ||
        callee == NULL || callee[0] == '\0' ||
        target == NULL) {
        return false;
    }
    owned = v3_read_file(source_path);
    if (owned == NULL) {
        return false;
    }
    pending_symbol[0] = '\0';
    pending_annotation_name[0] = '\0';
    v3_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    if (!v3_load_import_aliases_from_source_path(source_path,
                                                 aliases,
                                                 &alias_count,
                                                 CHENG_V3_MAX_IMPORT_ALIASES)) {
        free(owned);
        return false;
    }
    {
        char *cursor = owned;
        char *line = NULL;
        while ((line = strsep(&cursor, "\n")) != NULL) {
        char line_copy[4096];
        char signature_copy[4096];
        char function_name[128];
        char *trimmed;
        char *signature_trimmed;
        size_t i;
        bool matched = false;
        snprintf(line_copy, sizeof(line_copy), "%s", line);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0') {
            continue;
        }
        if (v3_importc_symbol_from_annotation(trimmed, pending_symbol, sizeof(pending_symbol))) {
            pending_annotation_name[0] = '\0';
            continue;
        }
        function_name[0] = '\0';
        if (v3_importc_function_name_from_line(trimmed, function_name, sizeof(function_name))) {
            matched = true;
            snprintf(pending_annotation_name, sizeof(pending_annotation_name), "%s", function_name);
        } else if (pending_symbol[0] != '\0' &&
                   v3_lowering_function_name_from_line(trimmed, function_name, sizeof(function_name))) {
            matched = true;
            snprintf(pending_annotation_name, sizeof(pending_annotation_name), "%s", function_name);
        } else {
            pending_symbol[0] = '\0';
            pending_annotation_name[0] = '\0';
            continue;
        }
        if (!matched || strcmp(function_name, callee) != 0) {
            if (pending_symbol[0] != '\0' && strcmp(function_name, pending_annotation_name) == 0) {
                continue;
            }
            pending_symbol[0] = '\0';
            pending_annotation_name[0] = '\0';
            continue;
        }
        {
            const char *symbol_name = function_name;
            memset(&probe, 0, sizeof(probe));
            snprintf(signature_copy, sizeof(signature_copy), "%s", line);
            signature_trimmed = v3_trim_inplace(signature_copy);
            if (!v3_parse_importc_signature_meta(signature_trimmed, function_name, &probe)) {
                free(owned);
                return false;
            }
            if (pending_symbol[0] != '\0' && v3_startswith(trimmed, "fn ")) {
                symbol_name = pending_symbol;
            }
            memset(target, 0, sizeof(*target));
            target->external = true;
            snprintf(target->callee_name, sizeof(target->callee_name), "%s", function_name);
            v3_copy_target_symbol_name(plan, symbol_name, target->symbol_name, sizeof(target->symbol_name));
            {
                char normalized_type[256];
                if (probe.return_type[0] != '\0' &&
                    strcmp(probe.return_type, "void") != 0 &&
                    v3_normalize_type_text(lowering,
                                           owner_module_path,
                                           aliases,
                                           alias_count,
                                           probe.return_type,
                                           normalized_type,
                                           sizeof(normalized_type))) {
                    snprintf(target->return_type, sizeof(target->return_type), "%s", normalized_type);
                    snprintf(target->return_abi_class,
                             sizeof(target->return_abi_class),
                             "%s",
                             v3_type_abi_class(target->return_type));
                } else {
                    snprintf(target->return_type, sizeof(target->return_type), "%s", probe.return_type);
                    snprintf(target->return_abi_class, sizeof(target->return_abi_class), "%s", probe.return_abi_class);
                }
            }
            target->param_count = probe.param_count;
            for (i = 0; i < probe.param_count && i < CHENG_V3_MAX_CALL_ARGS; ++i) {
                char normalized_type[256];
                if (probe.param_types[i][0] != '\0' &&
                    v3_normalize_type_text(lowering,
                                           owner_module_path,
                                           aliases,
                                           alias_count,
                                           probe.param_types[i],
                                           normalized_type,
                                           sizeof(normalized_type))) {
                    snprintf(target->param_types[i], sizeof(target->param_types[i]), "%s", normalized_type);
                    snprintf(target->param_abi_classes[i],
                             sizeof(target->param_abi_classes[i]),
                             "%s",
                             v3_type_abi_class(target->param_types[i]));
                } else {
                    snprintf(target->param_types[i], sizeof(target->param_types[i]), "%s", probe.param_types[i]);
                    snprintf(target->param_abi_classes[i], sizeof(target->param_abi_classes[i]), "%s", probe.param_abi_classes[i]);
                }
                target->param_is_var[i] = probe.param_is_var[i];
            }
            free(owned);
            return true;
        }
        }
    }
    free(owned);
    return false;
}

static bool v3_lowering_parse_return_call_noarg_i32(const char *trimmed,
                                                    char *target_name,
                                                    size_t cap) {
    const char *prefix = "return ";
    const char *call;
    const char *open_paren;
    size_t name_len;
    size_t i;
    if (!v3_startswith(trimmed, prefix)) {
        return false;
    }
    call = trimmed + strlen(prefix);
    open_paren = strchr(call, '(');
    if (!open_paren || strcmp(open_paren, "()") != 0) {
        return false;
    }
    name_len = (size_t)(open_paren - call);
    if (name_len <= 0U || name_len + 1U > cap) {
        return false;
    }
    memcpy(target_name, call, name_len);
    target_name[name_len] = '\0';
    v3_trim_copy_text(target_name, target_name, cap);
    if (target_name[0] == '\0') {
        return false;
    }
    for (i = 0; target_name[i] != '\0'; ++i) {
        unsigned char ch = (unsigned char)target_name[i];
        if (!(isalnum(ch) || ch == '_' || ch == '.' || ch == ':')) {
            return false;
        }
    }
    return true;
}

static bool v3_lowering_parse_return_call_arg0_i32(const char *trimmed,
                                                   char *target_name,
                                                   size_t target_cap,
                                                   char *arg_name,
                                                   size_t arg_cap) {
    const char *prefix = "return ";
    const char *call;
    const char *open_paren;
    const char *close_paren;
    size_t name_len;
    size_t arg_len;
    size_t i;
    if (!v3_startswith(trimmed, prefix)) {
        return false;
    }
    call = trimmed + strlen(prefix);
    open_paren = strchr(call, '(');
    close_paren = strrchr(call, ')');
    if (open_paren == NULL || close_paren == NULL || close_paren <= open_paren || close_paren[1] != '\0') {
        return false;
    }
    if (strcmp(open_paren, "()") == 0) {
        return false;
    }
    name_len = (size_t)(open_paren - call);
    arg_len = (size_t)(close_paren - open_paren - 1);
    if (name_len == 0U || name_len + 1U > target_cap || arg_len == 0U || arg_len + 1U > arg_cap) {
        return false;
    }
    memcpy(target_name, call, name_len);
    target_name[name_len] = '\0';
    memcpy(arg_name, open_paren + 1, arg_len);
    arg_name[arg_len] = '\0';
    v3_trim_copy_text(target_name, target_name, target_cap);
    v3_trim_copy_text(arg_name, arg_name, arg_cap);
    if (target_name[0] == '\0' || arg_name[0] == '\0' || strchr(arg_name, ',') != NULL) {
        return false;
    }
    for (i = 0; target_name[i] != '\0'; ++i) {
        unsigned char ch = (unsigned char)target_name[i];
        if (!(isalnum(ch) || ch == '_' || ch == '.' || ch == ':')) {
            return false;
        }
    }
    for (i = 0; arg_name[i] != '\0'; ++i) {
        unsigned char ch = (unsigned char)arg_name[i];
        if (!(isalnum(ch) || ch == '_')) {
            return false;
        }
    }
    return true;
}

static bool v3_lowering_parse_return_call_params_i32(const char *trimmed,
                                                     char *target_name,
                                                     size_t target_cap,
                                                     char arg_names[4][128],
                                                     size_t *arg_count_out) {
    const char *prefix = "return ";
    const char *call;
    const char *open_paren;
    const char *close_paren;
    char args_copy[512];
    char *cursor = NULL;
    char *piece = NULL;
    size_t name_len;
    size_t arg_count = 0U;
    size_t i;
    if (arg_count_out != NULL) {
        *arg_count_out = 0U;
    }
    if (!v3_startswith(trimmed, prefix)) {
        return false;
    }
    call = trimmed + strlen(prefix);
    open_paren = strchr(call, '(');
    close_paren = strrchr(call, ')');
    if (open_paren == NULL || close_paren == NULL || close_paren <= open_paren || close_paren[1] != '\0') {
        return false;
    }
    if (strcmp(open_paren, "()") == 0) {
        return false;
    }
    name_len = (size_t)(open_paren - call);
    if (name_len == 0U || name_len + 1U > target_cap) {
        return false;
    }
    memcpy(target_name, call, name_len);
    target_name[name_len] = '\0';
    v3_trim_copy_text(target_name, target_name, target_cap);
    if (target_name[0] == '\0') {
        return false;
    }
    for (i = 0; target_name[i] != '\0'; ++i) {
        unsigned char ch = (unsigned char)target_name[i];
        if (!(isalnum(ch) || ch == '_' || ch == '.' || ch == ':')) {
            return false;
        }
    }
    snprintf(args_copy, sizeof(args_copy), "%.*s", (int)(close_paren - open_paren - 1), open_paren + 1);
    cursor = args_copy;
    while ((piece = strsep(&cursor, ",")) != NULL) {
        char trimmed_arg[128];
        size_t j;
        v3_trim_copy_text(piece, trimmed_arg, sizeof(trimmed_arg));
        if (trimmed_arg[0] == '\0') {
            return false;
        }
        if (arg_count >= 4U) {
            return false;
        }
        for (j = 0; trimmed_arg[j] != '\0'; ++j) {
            unsigned char ch = (unsigned char)trimmed_arg[j];
            if (!(isalnum(ch) || ch == '_')) {
                return false;
            }
        }
        snprintf(arg_names[arg_count], 128, "%s", trimmed_arg);
        arg_count += 1U;
    }
    if (arg_count < 2U) {
        return false;
    }
    if (arg_count_out != NULL) {
        *arg_count_out = arg_count;
    }
    return true;
}

static size_t v3_function_body_last_line_number(char **lines,
                                                size_t line_count,
                                                size_t signature_end_index) {
    size_t i;
    size_t out = 0U;
    for (i = signature_end_index + 1U; i < line_count; ++i) {
        char line_copy[4096];
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            continue;
        }
        if (v3_line_indent(lines[i]) <= 0 && v3_is_top_level_decl_start(trimmed)) {
            break;
        }
        out = i + 1U;
    }
    return out;
}

static void v3_lowering_classify_single_statement(const char *trimmed,
                                                  char *body_kind,
                                                  size_t body_kind_cap,
                                                  char *call_target,
                                                  size_t call_target_cap,
                                                  size_t *call_arg_count_out,
                                                  char *call_arg0_name,
                                                  size_t call_arg0_name_cap,
                                                  char call_arg_names[4][128]) {
    char call_name[128];
    char call_arg_name[128];
    char call_arg_names_local[4][128];
    size_t call_arg_count = 0U;
    call_target[0] = '\0';
    if (call_arg_count_out != NULL) {
        *call_arg_count_out = 0U;
    }
    call_arg0_name[0] = '\0';
    memset(call_arg_names, 0, sizeof(char) * 4U * 128U);
    if (strcmp(trimmed, "return 0") == 0) {
        snprintf(body_kind, body_kind_cap, "%s", "return_zero_i32");
        return;
    }
    if (v3_lowering_parse_return_call_noarg_i32(trimmed, call_name, sizeof(call_name))) {
        snprintf(body_kind, body_kind_cap, "%s", "return_call_noarg_i32");
        snprintf(call_target, call_target_cap, "%s", call_name);
        return;
    }
    if (v3_lowering_parse_return_call_arg0_i32(trimmed,
                                               call_name,
                                               sizeof(call_name),
                                               call_arg_name,
                                               sizeof(call_arg_name))) {
        snprintf(body_kind, body_kind_cap, "%s", "return_call_arg0_i32");
        snprintf(call_target, call_target_cap, "%s", call_name);
        snprintf(call_arg0_name, call_arg0_name_cap, "%s", call_arg_name);
        if (call_arg_count_out != NULL) {
            *call_arg_count_out = 1U;
        }
        snprintf(call_arg_names[0], 128, "%s", call_arg_name);
        return;
    }
    if (v3_lowering_parse_return_call_params_i32(trimmed,
                                                 call_name,
                                                 sizeof(call_name),
                                                 call_arg_names_local,
                                                 &call_arg_count)) {
        size_t arg_index;
        snprintf(body_kind, body_kind_cap, "%s", "return_call_params_i32");
        snprintf(call_target, call_target_cap, "%s", call_name);
        if (call_arg_count_out != NULL) {
            *call_arg_count_out = call_arg_count;
        }
        snprintf(call_arg0_name, call_arg0_name_cap, "%s", call_arg_names_local[0]);
        for (arg_index = 0U; arg_index < call_arg_count && arg_index < 4U; ++arg_index) {
            snprintf(call_arg_names[arg_index], 128, "%s", call_arg_names_local[arg_index]);
        }
        return;
    }
    if (v3_startswith(trimmed, "return ")) {
        snprintf(body_kind, body_kind_cap, "%s", "return_expr");
        return;
    }
    if (v3_startswith(trimmed, "var ")) {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_var");
        return;
    }
    if (v3_startswith(trimmed, "let ")) {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_let");
        return;
    }
    if (v3_startswith(trimmed, "if ")) {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_if");
        return;
    }
    if (v3_startswith(trimmed, "for ")) {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_for");
        return;
    }
    if (v3_startswith(trimmed, "while ")) {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_while");
        return;
    }
    if (v3_startswith(trimmed, "case ")) {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_case");
        return;
    }
    if (strchr(trimmed, '(') != NULL && trimmed[strlen(trimmed) - 1U] == ')') {
        snprintf(body_kind, body_kind_cap, "%s", "stmt_call");
        return;
    }
    snprintf(body_kind, body_kind_cap, "%s", "unsupported");
}

static void v3_lowering_function_body_kind(char **lines,
                                           size_t line_count,
                                           size_t signature_end_index,
                                           char *body_kind,
                                           size_t body_kind_cap,
                                           char *call_target,
                                           size_t call_target_cap,
                                           size_t *call_arg_count_out,
                                           char *call_arg0_name,
                                           size_t call_arg0_name_cap,
                                           char call_arg_names[4][128],
                                           char *first_body_line,
                                           size_t first_body_line_cap,
                                           size_t *body_first_line_number_out,
                                           size_t *body_last_line_number_out) {
    size_t i;
    bool saw_body_line = false;
    char signature_copy[8192];
    char *signature_trimmed;
    char *eq;
    snprintf(body_kind, body_kind_cap, "%s", "unsupported");
    call_target[0] = '\0';
    if (call_arg_count_out != NULL) {
        *call_arg_count_out = 0U;
    }
    call_arg0_name[0] = '\0';
    memset(call_arg_names, 0, sizeof(char) * 4U * 128U);
    first_body_line[0] = '\0';
    if (body_first_line_number_out != NULL) {
        *body_first_line_number_out = 0U;
    }
    if (body_last_line_number_out != NULL) {
        *body_last_line_number_out = 0U;
    }
    snprintf(signature_copy, sizeof(signature_copy), "%s", lines[signature_end_index]);
    signature_trimmed = v3_trim_inplace(signature_copy);
    eq = strrchr(signature_trimmed, '=');
    if (eq != NULL) {
        char inline_body[8192];
        v3_trim_copy_text(eq + 1, inline_body, sizeof(inline_body));
        if (inline_body[0] != '\0') {
            if (body_first_line_number_out != NULL) {
                *body_first_line_number_out = signature_end_index + 1U;
            }
            if (body_last_line_number_out != NULL) {
                *body_last_line_number_out = signature_end_index + 1U;
            }
            snprintf(first_body_line, first_body_line_cap, "%s", inline_body);
            v3_lowering_classify_single_statement(inline_body,
                                                  body_kind,
                                                  body_kind_cap,
                                                  call_target,
                                                  call_target_cap,
                                                  call_arg_count_out,
                                                  call_arg0_name,
                                                  call_arg0_name_cap,
                                                  call_arg_names);
            if (strcmp(body_kind, "stmt_call") == 0 || strcmp(body_kind, "unsupported") == 0) {
                snprintf(body_kind, body_kind_cap, "%s", "return_expr");
            }
            return;
        }
    }
    for (i = signature_end_index + 1U; i < line_count; ++i) {
        char line_copy[4096];
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        trimmed = v3_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            continue;
        }
        if (v3_line_indent(lines[i]) <= 0 && v3_is_top_level_decl_start(trimmed)) {
            break;
        }
        if (body_first_line_number_out != NULL && *body_first_line_number_out == 0U) {
            *body_first_line_number_out = i + 1U;
        }
        if (body_last_line_number_out != NULL) {
            *body_last_line_number_out = i + 1U;
        }
        if (saw_body_line) {
            snprintf(body_kind, body_kind_cap, "%s", "unsupported");
            call_target[0] = '\0';
            return;
        }
        saw_body_line = true;
        snprintf(first_body_line, first_body_line_cap, "%s", trimmed);
        v3_lowering_classify_single_statement(trimmed,
                                              body_kind,
                                              body_kind_cap,
                                              call_target,
                                              call_target_cap,
                                              call_arg_count_out,
                                              call_arg0_name,
                                              call_arg0_name_cap,
                                              call_arg_names);
        return;
    }
}

static bool v3_collect_lowering_functions_from_source(const V3SystemLinkPlanStub *plan,
                                                      const char *source_path,
                                                      V3LoweringPlanStub *lowering) {
    char owner_module_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    char pending_export_symbol[PATH_MAX];
    char *owned;
    char *cursor;
    char *line;
    char *lines[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t line_count = 0U;
    size_t i;
    v3_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    owned = v3_read_file(source_path);
    if (!owned) {
        return false;
    }
    pending_export_symbol[0] = '\0';
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(owned);
            fprintf(stderr, "[cheng_v3_seed] lowering source line inventory too large\n");
            return false;
        }
        lines[line_count++] = line;
    }
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    for (i = 0; i < line_count; ++i) {
        char function_name[128];
        char signature_text[8192];
        char line_copy[4096];
        size_t signature_end_index = 0U;
        size_t body_statement_count = 0U;
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        trimmed = v3_trim_inplace(line_copy);
        if (v3_exportc_symbol_from_annotation(trimmed,
                                              pending_export_symbol,
                                              sizeof(pending_export_symbol))) {
            continue;
        }
        if (!v3_lowering_function_name_from_line(trimmed, function_name, sizeof(function_name))) {
            if (trimmed[0] != '\0' && trimmed[0] != '#') {
                pending_export_symbol[0] = '\0';
            }
            continue;
        }
        if (!v3_collect_function_signature(lines,
                                           line_count,
                                           i,
                                           signature_text,
                                           sizeof(signature_text),
                                           &signature_end_index)) {
            continue;
        }
        if (lowering->function_count >= CHENG_V3_MAX_PLAN_FUNCTIONS) {
            free(owned);
            fprintf(stderr, "[cheng_v3_seed] lowering function inventory too large\n");
            return false;
        }
        snprintf(lowering->functions[lowering->function_count].source_path,
                 sizeof(lowering->functions[lowering->function_count].source_path),
                 "%s",
                 source_path);
        snprintf(lowering->functions[lowering->function_count].owner_module_path,
                 sizeof(lowering->functions[lowering->function_count].owner_module_path),
                 "%s",
                 owner_module_path);
        snprintf(lowering->functions[lowering->function_count].function_name,
                 sizeof(lowering->functions[lowering->function_count].function_name),
                 "%s",
                 function_name);
        snprintf(lowering->functions[lowering->function_count].symbol_text,
                 sizeof(lowering->functions[lowering->function_count].symbol_text),
                 "%s::%s",
                 owner_module_path,
                 function_name);
        if (pending_export_symbol[0] != '\0') {
            snprintf(lowering->functions[lowering->function_count].export_symbol_name,
                     sizeof(lowering->functions[lowering->function_count].export_symbol_name),
                     "%s",
                     pending_export_symbol);
        }
        pending_export_symbol[0] = '\0';
        lowering->functions[lowering->function_count].signature_line_number = i + 1U;
        if (!v3_parse_function_signature_meta(signature_text,
                                              function_name,
                                              &lowering->functions[lowering->function_count])) {
            free(owned);
            fprintf(stderr, "[cheng_v3_seed] malformed function signature metadata\n");
            return false;
        }
        for (size_t param_i = 0; param_i < lowering->functions[lowering->function_count].param_count; ++param_i) {
            char normalized_type[128];
            if (v3_normalize_type_text(lowering,
                                       owner_module_path,
                                       aliases,
                                       alias_count,
                                       lowering->functions[lowering->function_count].param_types[param_i],
                                       normalized_type,
                                       sizeof(normalized_type))) {
                snprintf(lowering->functions[lowering->function_count].param_types[param_i],
                         sizeof(lowering->functions[lowering->function_count].param_types[param_i]),
                         "%s",
                         normalized_type);
            }
            snprintf(lowering->functions[lowering->function_count].param_abi_classes[param_i],
                     sizeof(lowering->functions[lowering->function_count].param_abi_classes[param_i]),
                     "%s",
                     v3_type_abi_class(lowering->functions[lowering->function_count].param_types[param_i]));
        }
        {
            char normalized_return_type[128];
            if (v3_normalize_type_text(lowering,
                                       owner_module_path,
                                       aliases,
                                       alias_count,
                                       lowering->functions[lowering->function_count].return_type,
                                       normalized_return_type,
                                       sizeof(normalized_return_type))) {
                snprintf(lowering->functions[lowering->function_count].return_type,
                         sizeof(lowering->functions[lowering->function_count].return_type),
                         "%s",
                         normalized_return_type);
            }
            snprintf(lowering->functions[lowering->function_count].return_abi_class,
                     sizeof(lowering->functions[lowering->function_count].return_abi_class),
                     "%s",
                     v3_type_abi_class(lowering->functions[lowering->function_count].return_type));
        }
        v3_lowering_function_body_kind(lines,
                                       line_count,
                                       signature_end_index,
                                       lowering->functions[lowering->function_count].body_kind,
                                       sizeof(lowering->functions[lowering->function_count].body_kind),
                                       lowering->functions[lowering->function_count].body_call_target,
                                       sizeof(lowering->functions[lowering->function_count].body_call_target),
                                       &lowering->functions[lowering->function_count].body_call_arg_count,
                                       lowering->functions[lowering->function_count].body_call_arg0_name,
                                       sizeof(lowering->functions[lowering->function_count].body_call_arg0_name),
                                       lowering->functions[lowering->function_count].body_call_arg_names,
                                       lowering->functions[lowering->function_count].first_body_line,
                                       sizeof(lowering->functions[lowering->function_count].first_body_line),
                                       &lowering->functions[lowering->function_count].body_first_line_number,
                                       &lowering->functions[lowering->function_count].body_last_line_number);
        if (strcmp(lowering->functions[lowering->function_count].body_kind, "return_call_noarg_i32") == 0 &&
            (lowering->functions[lowering->function_count].param_count != 0U ||
             strcmp(lowering->functions[lowering->function_count].return_abi_class, "i32") != 0)) {
            snprintf(lowering->functions[lowering->function_count].body_kind,
                     sizeof(lowering->functions[lowering->function_count].body_kind),
                     "%s",
                     "return_expr");
        }
        if (strcmp(lowering->functions[lowering->function_count].body_kind, "return_call_arg0_i32") == 0 &&
            (lowering->functions[lowering->function_count].param_count != 1U ||
             strcmp(lowering->functions[lowering->function_count].param_abi_classes[0], "i32") != 0 ||
             strcmp(lowering->functions[lowering->function_count].return_abi_class, "i32") != 0)) {
            snprintf(lowering->functions[lowering->function_count].body_kind,
                     sizeof(lowering->functions[lowering->function_count].body_kind),
                     "%s",
                     "return_expr");
        }
        if (strcmp(lowering->functions[lowering->function_count].body_kind, "return_call_params_i32") == 0) {
            bool params_ok = lowering->functions[lowering->function_count].body_call_arg_count >= 2U &&
                             lowering->functions[lowering->function_count].body_call_arg_count <= 4U &&
                             lowering->functions[lowering->function_count].param_count ==
                               lowering->functions[lowering->function_count].body_call_arg_count &&
                             strcmp(lowering->functions[lowering->function_count].return_abi_class, "i32") == 0;
            size_t param_index;
            for (param_index = 0U; params_ok &&
                                  param_index < lowering->functions[lowering->function_count].body_call_arg_count;
                 ++param_index) {
                if (strcmp(lowering->functions[lowering->function_count].param_abi_classes[param_index], "i32") != 0 ||
                    strcmp(lowering->functions[lowering->function_count].body_call_arg_names[param_index],
                           lowering->functions[lowering->function_count].param_names[param_index]) != 0) {
                    params_ok = false;
                }
            }
            if (!params_ok) {
                snprintf(lowering->functions[lowering->function_count].body_kind,
                         sizeof(lowering->functions[lowering->function_count].body_kind),
                         "%s",
                         "return_expr");
            }
        }
        lowering->functions[lowering->function_count].body_last_line_number =
            v3_function_body_last_line_number(lines, line_count, signature_end_index);
        body_statement_count =
            v3_count_function_body_statements(lines, line_count, signature_end_index);
        if (strcmp(lowering->functions[lowering->function_count].return_abi_class, "void") != 0) {
            if (body_statement_count == 1U &&
                strcmp(lowering->functions[lowering->function_count].body_kind, "stmt_call") == 0) {
                snprintf(lowering->functions[lowering->function_count].body_kind,
                         sizeof(lowering->functions[lowering->function_count].body_kind),
                         "%s",
                         "return_expr");
            } else if (body_statement_count == 1U &&
                       strcmp(lowering->functions[lowering->function_count].body_kind, "unsupported") == 0 &&
                       lowering->functions[lowering->function_count].first_body_line[0] != '\0' &&
                       !v3_startswith(lowering->functions[lowering->function_count].first_body_line, "if ") &&
                       !v3_startswith(lowering->functions[lowering->function_count].first_body_line, "for ") &&
                       !v3_startswith(lowering->functions[lowering->function_count].first_body_line, "while ") &&
                       !v3_startswith(lowering->functions[lowering->function_count].first_body_line, "case ") &&
                       !v3_startswith(lowering->functions[lowering->function_count].first_body_line, "of ")) {
                snprintf(lowering->functions[lowering->function_count].body_kind,
                         sizeof(lowering->functions[lowering->function_count].body_kind),
                         "%s",
                         "return_expr");
            }
        }
        lowering->functions[lowering->function_count].is_entry =
            v3_streq(source_path, plan->entry_path) &&
            v3_streq(function_name, plan->entry_symbol);
        lowering->functions[lowering->function_count].reachable = false;
        lowering->functions[lowering->function_count].callee_count = 0U;
        lowering->function_count += 1U;
    }
    free(owned);
    return true;
}

static int32_t v3_find_lowered_function_index_by_symbol(const V3LoweringPlanStub *lowering,
                                                        const char *symbol_text) {
    return v3_find_lowered_function_index_by_symbol_scan(lowering, symbol_text);
}

static bool v3_refresh_function_callees(const V3LoweringPlanStub *lowering,
                                        V3LoweredFunctionStub *function) {
    char **lines = NULL;
    char *owned_lines = NULL;
    size_t line_count = 0U;
    size_t fn_line_index = 0U;
    char param_names[CHENG_V3_CONST_MAX_BINDINGS][128];
    size_t param_count = 0U;
    char owned_path[PATH_MAX];
    V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    size_t body_line_index;
    if (!v3_load_function_source_lines(function,
                                       &lines,
                                       &owned_lines,
                                       &line_count,
                                       &fn_line_index,
                                       param_names,
                                       &param_count,
                                       owned_path)) {
        return false;
    }
    (void)param_names;
    (void)param_count;
    v3_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_V3_MAX_IMPORT_ALIASES);
    function->callee_count = 0U;
    {
        char signature_copy[8192];
        char *eq;
        snprintf(signature_copy, sizeof(signature_copy), "%s", lines[fn_line_index]);
        eq = strrchr(signature_copy, '=');
        if (eq != NULL) {
            char inline_body[8192];
            v3_trim_copy_text(eq + 1, inline_body, sizeof(inline_body));
            if (inline_body[0] != '\0') {
                v3_collect_calls_from_text_resolved(inline_body,
                                                    function->owner_module_path,
                                                    aliases,
                                                    alias_count,
                                                    lowering,
                                                    function);
            }
        }
    }
    for (body_line_index = fn_line_index + 1U; body_line_index < line_count; ++body_line_index) {
        char line_copy[4096];
        char *body_trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[body_line_index]);
        body_trimmed = v3_trim_inplace(line_copy);
        if (*body_trimmed == '\0') {
            continue;
        }
        if (v3_line_indent(lines[body_line_index]) <= 0 &&
            v3_is_top_level_decl_start(body_trimmed)) {
            break;
        }
        v3_collect_calls_from_text_resolved(body_trimmed,
                                            function->owner_module_path,
                                            aliases,
                                            alias_count,
                                            lowering,
                                            function);
    }
    free(lines);
    free(owned_lines);
    return true;
}

static bool v3_refresh_lowering_callees(V3LoweringPlanStub *lowering) {
    size_t i;
    for (i = 0; i < lowering->function_count; ++i) {
        if (!v3_refresh_function_callees(lowering, &lowering->functions[i])) {
            return false;
        }
    }
    return true;
}

static bool v3_load_source_lines(const char *source_path,
                                 char ***lines_out,
                                 char **owned_out,
                                 size_t *line_count_out);
static bool v3_parse_top_level_var_binding_text(const char *statement,
                                                char *name_out,
                                                size_t name_cap,
                                                char *type_out,
                                                size_t type_cap,
                                                bool *has_init_out,
                                                char *expr_out,
                                                size_t expr_cap);

static bool v3_seed_reachable_from_module_inits(const V3SystemLinkPlanStub *plan,
                                                V3LoweringPlanStub *lowering,
                                                int32_t *queue,
                                                size_t *queue_tail_io) {
    size_t source_index;
    for (source_index = 0; source_index < plan->source_closure_count; ++source_index) {
        const char *source_path = plan->source_closure_paths[source_index].text;
        char owner_module_path[PATH_MAX];
        char **lines = NULL;
        char *owned = NULL;
        size_t line_count = 0U;
        V3ImportAlias aliases[CHENG_V3_MAX_IMPORT_ALIASES];
        size_t alias_count = 0U;
        bool in_var_block = false;
        size_t line_index;
        V3LoweredFunctionStub synthetic_function;
        if (!v3_load_source_lines(source_path, &lines, &owned, &line_count)) {
            return false;
        }
        v3_source_path_to_module_path(plan->workspace_root,
                                      plan->package_root,
                                      plan->package_id,
                                      source_path,
                                      owner_module_path,
                                      sizeof(owner_module_path));
        v3_parse_import_aliases_from_lines(lines,
                                           line_count,
                                           aliases,
                                           &alias_count,
                                           CHENG_V3_MAX_IMPORT_ALIASES);
        memset(&synthetic_function, 0, sizeof(synthetic_function));
        snprintf(synthetic_function.source_path, sizeof(synthetic_function.source_path), "%s", source_path);
        snprintf(synthetic_function.owner_module_path,
                 sizeof(synthetic_function.owner_module_path),
                 "%s",
                 owner_module_path);
        snprintf(synthetic_function.function_name,
                 sizeof(synthetic_function.function_name),
                 "%s",
                 "__v3_module_init");
        snprintf(synthetic_function.symbol_text,
                 sizeof(synthetic_function.symbol_text),
                 "%s::__v3_module_init",
                 owner_module_path);
        for (line_index = 0; line_index < line_count; ++line_index) {
            char line_copy[4096];
            char name[128];
            char raw_type[256];
            char expr[4096];
            bool has_init = false;
            int32_t indent;
            char *trimmed;
            size_t callee_index;
            snprintf(line_copy, sizeof(line_copy), "%s", lines[line_index]);
            indent = v3_line_indent(line_copy);
            trimmed = v3_trim_inplace(line_copy);
            if (*trimmed == '\0' || *trimmed == '#') {
                continue;
            }
            if (indent <= 0 && strcmp(trimmed, "var") == 0) {
                in_var_block = true;
                continue;
            }
            if (indent <= 0 && !v3_startswith(trimmed, "var ")) {
                in_var_block = false;
            }
            if (indent <= 0 && v3_startswith(trimmed, "var ")) {
                trimmed += 4;
            } else if (!in_var_block || indent <= 0) {
                continue;
            }
            if (!v3_parse_top_level_var_binding_text(trimmed,
                                                     name,
                                                     sizeof(name),
                                                     raw_type,
                                                     sizeof(raw_type),
                                                     &has_init,
                                                     expr,
                                                     sizeof(expr)) ||
                !has_init) {
                continue;
            }
            synthetic_function.callee_count = 0U;
            v3_collect_calls_from_text_resolved(expr,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                lowering,
                                                &synthetic_function);
            for (callee_index = 0; callee_index < synthetic_function.callee_count; ++callee_index) {
                int32_t found =
                    v3_find_lowered_function_index_by_symbol(lowering,
                                                             synthetic_function.callee_symbols[callee_index].text);
                if (found >= 0 && !lowering->functions[found].reachable) {
                    lowering->functions[found].reachable = true;
                    queue[(*queue_tail_io)++] = found;
                }
            }
        }
        free(lines);
        free(owned);
    }
    return true;
}

static void v3_prune_lowering_to_reachable(const V3SystemLinkPlanStub *plan,
                                           V3LoweringPlanStub *lowering) {
    int32_t queue[CHENG_V3_MAX_PLAN_FUNCTIONS];
    size_t queue_head = 0U;
    size_t queue_tail = 0U;
    size_t i;
    size_t write_index = 0U;
    bool saw_entry = false;
    bool seeded_shared_roots = false;
    bool seeded_object_roots = false;
    if (v3_target_is_wasm32_unknown_unknown(plan->target_triple)) {
        return;
    }
    for (i = 0; i < lowering->function_count; ++i) {
        lowering->functions[i].reachable = false;
        if (lowering->functions[i].is_entry) {
            lowering->functions[i].reachable = true;
            queue[queue_tail++] = (int32_t)i;
            saw_entry = true;
        }
    }
    if (!saw_entry && v3_streq(plan->emit_kind, "shared") && plan->entry_path[0] != '\0') {
        for (i = 0; i < lowering->function_count; ++i) {
            if (!v3_streq(lowering->functions[i].source_path, plan->entry_path)) {
                continue;
            }
            lowering->functions[i].reachable = true;
            queue[queue_tail++] = (int32_t)i;
            seeded_shared_roots = true;
        }
    }
    if (!saw_entry && !seeded_shared_roots &&
        v3_streq(plan->emit_kind, "obj") && plan->entry_path[0] != '\0') {
        for (i = 0; i < lowering->function_count; ++i) {
            if (!v3_streq(lowering->functions[i].source_path, plan->entry_path)) {
                continue;
            }
            lowering->functions[i].reachable = true;
            queue[queue_tail++] = (int32_t)i;
            seeded_object_roots = true;
        }
    }
    if (!saw_entry && !seeded_shared_roots && !seeded_object_roots) {
        return;
    }
    if (!v3_seed_reachable_from_module_inits(plan, lowering, queue, &queue_tail)) {
        return;
    }
    while (queue_head < queue_tail) {
        const V3LoweredFunctionStub *function = &lowering->functions[queue[queue_head++]];
        size_t callee_index;
        for (callee_index = 0; callee_index < function->callee_count; ++callee_index) {
            int32_t found = v3_find_lowered_function_index_by_symbol(lowering,
                                                                     function->callee_symbols[callee_index].text);
            if (found >= 0 && !lowering->functions[found].reachable) {
                lowering->functions[found].reachable = true;
                queue[queue_tail++] = found;
            }
        }
    }
    for (i = 0; i < lowering->function_count; ++i) {
        if (!lowering->functions[i].reachable) {
            continue;
        }
        if (write_index != i) {
            lowering->functions[write_index] = lowering->functions[i];
        }
        write_index += 1U;
    }
    lowering->function_count = write_index;
}

static bool v3_build_lowering_plan_stub(const V3SystemLinkPlanStub *plan,
                                        V3LoweringPlanStub *lowering) {
    size_t i;
    bool saw_entry = false;
    memset(lowering, 0, sizeof(*lowering));
    for (i = 0; i < plan->source_closure_count; ++i) {
        if (!v3_collect_top_level_consts_from_source(plan,
                                                     plan->source_closure_paths[i].text,
                                                     lowering)) {
            return false;
        }
    }
    for (i = 0; i < plan->source_closure_count; ++i) {
        if (!v3_collect_type_defs_from_source(plan,
                                              plan->source_closure_paths[i].text,
                                              lowering)) {
            return false;
        }
    }
    for (i = 0; i < plan->source_closure_count; ++i) {
        if (!v3_refresh_type_defs_from_source(plan,
                                              plan->source_closure_paths[i].text,
                                              lowering)) {
            return false;
        }
    }
    for (i = 0; i < plan->source_closure_count; ++i) {
        if (!v3_collect_lowering_functions_from_source(plan,
                                                       plan->source_closure_paths[i].text,
                                                       lowering)) {
            return false;
        }
    }
    for (i = 0; i < plan->source_closure_count; ++i) {
        if (!v3_refresh_function_abis_from_source(plan,
                                                  plan->source_closure_paths[i].text,
                                                  lowering)) {
            return false;
        }
    }
    if (lowering->function_count <= 0U) {
        v3_lowering_add_reason(lowering, "lowering_functions_missing");
        return true;
    }
    if (plan->entry_symbol[0] != '\0') {
        for (i = 0; i < lowering->function_count; ++i) {
            if (lowering->functions[i].is_entry) {
                saw_entry = true;
                break;
            }
        }
        if (!saw_entry) {
            v3_lowering_add_reason(lowering, "lowering_entry_function_missing");
        }
    }
    if (!v3_refresh_lowering_callees(lowering)) {
        v3_lowering_add_reason(lowering, "lowering_callee_refresh_failed");
        return true;
    }
    v3_prune_lowering_to_reachable(plan, lowering);
    return true;
}

static void v3_sanitize_path_part(const char *text, char *out, size_t cap) {
    size_t i;
    size_t used = 0U;
    if (!text || cap <= 0U) {
        return;
    }
    out[0] = '\0';
    for (i = 0; text[i] != '\0' && used + 1U < cap; ++i) {
        const char ch = text[i];
        const bool digit = ch >= '0' && ch <= '9';
        const bool upper = ch >= 'A' && ch <= 'Z';
        const bool lower = ch >= 'a' && ch <= 'z';
        out[used++] = (digit || upper || lower) ? ch : '_';
    }
    out[used] = '\0';
}

static void v3_primary_symbol_name(const V3SystemLinkPlanStub *plan,
                                   const V3LoweredFunctionStub *function,
                                   char *out,
                                   size_t cap) {
    char raw[PATH_MAX];
    char sanitized[PATH_MAX];
    if (function->export_symbol_name[0] != '\0') {
        v3_copy_target_symbol_name(plan, function->export_symbol_name, out, cap);
        return;
    }
    snprintf(raw, sizeof(raw), "%s__%s", function->owner_module_path, function->function_name);
    if (cap == 0U) {
        return;
    }
    v3_sanitize_path_part(raw, sanitized, sizeof(sanitized));
    v3_copy_target_symbol_name(plan, sanitized, out, cap);
}

static void v3_runtime_entry_bridge_symbol(const V3SystemLinkPlanStub *plan,
                                           char *out,
                                           size_t cap) {
    v3_copy_target_symbol_name(plan,
                               v3_streq(plan->module_kind, "compiler_control_plane") ?
                                   "cheng_v3_tooling_argv_entry" :
                                   "cheng_v3_program_argv_entry",
                               out,
                               cap);
}

static void v3_text_append(char *out, size_t cap, const char *text);
static void v3_text_appendf(char *out, size_t cap, const char *fmt, ...);

static void v3_append_cstring_section_for_target(const V3SystemLinkPlanStub *plan,
                                                 char *out,
                                                 size_t cap) {
    if (v3_target_is_elf_aarch64(plan->target_triple) ||
        v3_target_is_linux_x86_64(plan->target_triple)) {
        v3_text_append(out, cap, ".section .rodata\n");
    } else {
        v3_text_append(out, cap, ".section __TEXT,__cstring,cstring_literals\n");
    }
}

static void v3_append_const_section_for_target(const V3SystemLinkPlanStub *plan,
                                               char *out,
                                               size_t cap) {
    if (v3_target_is_elf_aarch64(plan->target_triple) ||
        v3_target_is_linux_x86_64(plan->target_triple)) {
        v3_text_append(out, cap, ".section .data.rel.ro\n.p2align 3\n");
    } else {
        v3_text_append(out, cap, ".section __DATA_CONST,__const\n.p2align 3\n");
    }
}

static void v3_append_symbol_trailer_for_target(const V3SystemLinkPlanStub *plan,
                                                char *out,
                                                size_t cap) {
    if (v3_target_is_darwin_arm64(plan->target_triple)) {
        v3_text_append(out, cap, ".subsections_via_symbols\n");
    }
}

static bool v3_emit_symbol_address_for_target(const V3SystemLinkPlanStub *plan,
                                              char *out,
                                              size_t cap,
                                              int reg_index,
                                              const char *symbol_name) {
    bool local_label = false;
    if (plan == NULL || symbol_name == NULL || symbol_name[0] == '\0') {
        return false;
    }
    local_label = v3_startswith(symbol_name, "L_");
    if (v3_target_is_elf_aarch64(plan->target_triple)) {
        if (v3_streq(plan->emit_kind, "shared") && !local_label) {
            v3_text_appendf(out, cap,
                            "  adrp x%d, :got:%s\n"
                            "  ldr x%d, [x%d, #:got_lo12:%s]\n",
                            reg_index,
                            symbol_name,
                            reg_index,
                            reg_index,
                            symbol_name);
            return true;
        }
        v3_text_appendf(out, cap,
                        "  adrp x%d, %s\n"
                        "  add x%d, x%d, :lo12:%s\n",
                        reg_index,
                        symbol_name,
                        reg_index,
                        reg_index,
                        symbol_name);
        return true;
    }
    v3_text_appendf(out, cap,
                    "  adrp x%d, %s@PAGE\n"
                    "  add x%d, x%d, %s@PAGEOFF\n",
                    reg_index,
                    symbol_name,
                    reg_index,
                    reg_index,
                    symbol_name);
    return true;
}

static void v3_emit_call_named_symbol(const V3SystemLinkPlanStub *plan,
                                      char *out,
                                      size_t cap,
                                      const char *symbol) {
    char target_symbol[PATH_MAX];
    v3_copy_target_symbol_name(plan, symbol, target_symbol, sizeof(target_symbol));
    v3_text_appendf(out, cap, "  bl %s\n", target_symbol);
}

