static bool v3_emit_cstring_literal_label(const V3SystemLinkPlanStub *plan,
                                          const V3LoweredFunctionStub *current_function,
                                          const char *literal_text,
                                          int32_t *string_label_index_io,
                                          char *label_out,
                                          size_t label_cap,
                                          char *out,
                                          size_t cap) {
    char safe_name[128];
    char *escaped;
    int32_t label_id = 0;
    const char *label_prefix = "L_v3_strlit";
    v3_sanitize_path_part(current_function->symbol_text, safe_name, sizeof(safe_name));
    if (string_label_index_io) {
        label_id = *string_label_index_io;
        *string_label_index_io += 1;
    } else {
        label_id = v3_next_expr_label_id();
        label_prefix = "L_v3_expr_strlit";
    }
    snprintf(label_out,
             label_cap,
             "%s_%s_%d",
             label_prefix,
             safe_name,
             label_id);
    escaped = v3_c_escape(literal_text);
    if (!escaped) {
        return false;
    }
    v3_append_cstring_section_for_target(plan, out, cap);
    v3_text_appendf(out, cap,
                    "%s:\n"
                    "  .asciz \"%s\"\n"
                    ".text\n"
                    ".p2align 2\n",
                    label_out,
                    escaped);
    free(escaped);
    return true;
}

static bool v3_emit_str_literal_into_slot(const V3SystemLinkPlanStub *plan,
                                          const V3LoweredFunctionStub *current_function,
                                          const V3AsmLocalSlot *dest_slot,
                                          const char *literal_text,
                                          int32_t *string_label_index_io,
                                          char *out,
                                          size_t cap) {
    char label[128];
    if (!dest_slot || strcmp(dest_slot->type_text, "str") != 0 || dest_slot->stack_offset < 0) {
        return false;
    }
    if (!v3_emit_cstring_literal_label(plan,
                                       current_function,
                                       literal_text,
                                       string_label_index_io,
                                       label,
                                       sizeof(label),
                                       out,
                                       cap)) {
        return false;
    }
    if (!v3_emit_slot_address(out, cap, dest_slot, 15)) {
        return false;
    }
    if (!v3_emit_symbol_address_for_target(plan, out, cap, 9, label)) {
        return false;
    }
    v3_text_appendf(out, cap,
                    "  str x9, [x15, #0]\n"
                    "  mov w10, #%d\n"
                    "  str w10, [x15, #8]\n"
                    "  str wzr, [x15, #12]\n"
                    "  str wzr, [x15, #16]\n"
                    "  str wzr, [x15, #20]\n",
                    (int)strlen(literal_text));
    return true;
}

static bool v3_emit_str_literal_into_address(const V3SystemLinkPlanStub *plan,
                                             const V3LoweredFunctionStub *current_function,
                                             const char *literal_text,
                                             int dest_addr_reg,
                                             int32_t *string_label_index_io,
                                             char *out,
                                             size_t cap) {
    char label[128];
    if (!v3_emit_cstring_literal_label(plan,
                                       current_function,
                                       literal_text,
                                       string_label_index_io,
                                       label,
                                       sizeof(label),
                                       out,
                                       cap)) {
        return false;
    }
    if (!v3_emit_symbol_address_for_target(plan, out, cap, 9, label)) {
        return false;
    }
    v3_text_appendf(out, cap,
                    "  str x9, [x%d, #0]\n"
                    "  mov w10, #%d\n"
                    "  str w10, [x%d, #8]\n"
                    "  str wzr, [x%d, #12]\n"
                    "  str wzr, [x%d, #16]\n"
                    "  str wzr, [x%d, #20]\n",
                    dest_addr_reg,
                    (int)strlen(literal_text),
                    dest_addr_reg,
                    dest_addr_reg,
                    dest_addr_reg,
                    dest_addr_reg);
    return true;
}

static bool v3_emit_slot_address(char *out,
                                 size_t cap,
                                 const V3AsmLocalSlot *slot,
                                 int reg_index);
static bool v3_emit_add_address_offset(char *out,
                                       size_t cap,
                                       int dst_reg,
                                       int src_reg,
                                       int32_t offset);
static bool v3_emit_mov_imm(char *out, size_t cap, int reg_index, int64_t value);
static bool v3_emit_sp_store_reg(char *out,
                                 size_t cap,
                                 int32_t offset,
                                 const char *abi_class,
                                 int src_reg);
static bool v3_emit_sp_load_reg(char *out,
                                size_t cap,
                                int32_t offset,
                                const char *abi_class,
                                int dst_reg);

static bool v3_emit_zero_address_range(char *out,
                                       size_t cap,
                                       int addr_reg,
                                       int32_t size) {
    int32_t offset = 0;
    while (offset + 8 <= size) {
        int32_t chunk_base = offset;
        int32_t chunk_limit = size;
        if (chunk_limit - chunk_base > 32760) {
            chunk_limit = chunk_base + 32760;
        }
        if (!v3_emit_add_address_offset(out, cap, 14, addr_reg, chunk_base)) {
            return false;
        }
        while (offset + 8 <= chunk_limit) {
            v3_text_appendf(out, cap, "  str xzr, [x14, #%d]\n", offset - chunk_base);
            offset += 8;
        }
    }
    if (offset + 4 <= size) {
        if (!v3_emit_add_address_offset(out, cap, 14, addr_reg, offset)) {
            return false;
        }
        v3_text_appendf(out, cap, "  str wzr, [x14, #0]\n");
        offset += 4;
    }
    while (offset < size) {
        if (!v3_emit_add_address_offset(out, cap, 14, addr_reg, offset)) {
            return false;
        }
        v3_text_appendf(out, cap, "  strb wzr, [x14, #0]\n");
        offset += 1;
    }
    return true;
}

static bool v3_emit_zero_slot(char *out,
                              size_t cap,
                              const V3AsmLocalSlot *slot) {
    if (!slot) {
        return false;
    }
    if (!v3_emit_slot_address(out, cap, slot, 15)) {
        return false;
    }
    return v3_emit_zero_address_range(out, cap, 15, slot->stack_size);
}

static void v3_emit_load_scalar_from_address(char *out,
                                             size_t cap,
                                             int addr_reg,
                                             int32_t offset,
                                             const char *abi_class,
                                             int dst_reg) {
    if (strcmp(abi_class, "i8") == 0) {
        v3_text_appendf(out, cap, "  ldrsb x%d, [x%d, #%d]\n", dst_reg, addr_reg, offset);
    } else if (strcmp(abi_class, "u8") == 0 || strcmp(abi_class, "bool") == 0) {
        v3_text_appendf(out, cap, "  ldrb w%d, [x%d, #%d]\n", dst_reg, addr_reg, offset);
    } else if (strcmp(abi_class, "i16") == 0) {
        v3_text_appendf(out, cap, "  ldrsh x%d, [x%d, #%d]\n", dst_reg, addr_reg, offset);
    } else if (strcmp(abi_class, "u16") == 0) {
        v3_text_appendf(out, cap, "  ldrh w%d, [x%d, #%d]\n", dst_reg, addr_reg, offset);
    } else if (strcmp(abi_class, "i32") == 0) {
        v3_text_appendf(out, cap, "  ldrsw x%d, [x%d, #%d]\n", dst_reg, addr_reg, offset);
    } else {
        v3_text_appendf(out, cap, "  ldr x%d, [x%d, #%d]\n", dst_reg, addr_reg, offset);
    }
}

static void v3_emit_store_scalar_to_address(char *out,
                                            size_t cap,
                                            int addr_reg,
                                            int32_t offset,
                                            const char *abi_class,
                                            int src_reg) {
    if (strcmp(abi_class, "i8") == 0 ||
        strcmp(abi_class, "u8") == 0 ||
        strcmp(abi_class, "bool") == 0) {
        v3_text_appendf(out, cap, "  strb w%d, [x%d, #%d]\n", src_reg, addr_reg, offset);
    } else if (strcmp(abi_class, "i16") == 0 ||
               strcmp(abi_class, "u16") == 0) {
        v3_text_appendf(out, cap, "  strh w%d, [x%d, #%d]\n", src_reg, addr_reg, offset);
    } else if (strcmp(abi_class, "i32") == 0) {
        v3_text_appendf(out, cap, "  str w%d, [x%d, #%d]\n", src_reg, addr_reg, offset);
    } else {
        v3_text_appendf(out, cap, "  str x%d, [x%d, #%d]\n", src_reg, addr_reg, offset);
    }
}

static bool v3_emit_copy_address_to_address(const V3SystemLinkPlanStub *plan,
                                            char *out,
                                            size_t cap,
                                            int dst_reg,
                                            int src_reg,
                                            int32_t size) {
    if (size < 0) {
        return false;
    }
    v3_text_appendf(out, cap,
                    "  mov x0, x%d\n"
                    "  mov x1, x%d\n",
                    dst_reg,
                    src_reg);
    if (!v3_emit_mov_imm(out, cap, 2, size)) {
        return false;
    }
    v3_emit_call_named_symbol(plan, out, cap, "copyMem");
    return true;
}

static bool v3_emit_copy_slot_to_address(const V3SystemLinkPlanStub *plan,
                                         const V3LoweringPlanStub *lowering,
                                         char *out,
                                         size_t cap,
                                         const V3AsmLocalSlot *src_slot,
                                         int dst_reg) {
    V3TypeLayoutStub layout;
    char value_type[256];
    int32_t copy_size;
    int src_reg;
    if (!src_slot || src_slot->stack_size < 0) {
        return false;
    }
    if (src_slot->indirect_value) {
        if (!lowering) {
            return false;
        }
        v3_strip_var_type_text(src_slot->type_text, value_type, sizeof(value_type));
        if (!v3_compute_type_layout_impl(lowering, value_type, &layout, 0U)) {
            return false;
        }
        copy_size = layout.size;
        src_reg = dst_reg == 14 ? 15 : 14;
        if (!v3_emit_local_value_address(out, cap, src_slot, src_reg)) {
            return false;
        }
        return v3_emit_copy_address_to_address(plan, out, cap, dst_reg, src_reg, copy_size);
    }
    copy_size = src_slot->stack_size;
    src_reg = dst_reg == 14 ? 15 : 14;
    if (!v3_emit_local_value_address(out, cap, src_slot, src_reg)) {
        return false;
    }
    return v3_emit_copy_address_to_address(plan, out, cap, dst_reg, src_reg, copy_size);
}

static bool v3_emit_mov_imm(char *out, size_t cap, int reg_index, int64_t value) {
    uint64_t bits = (uint64_t)value;
    bool emitted = false;
    int shift;
    if (value >= -65535 && value <= 65535) {
        v3_text_appendf(out, cap, "  mov x%d, #%lld\n", reg_index, (long long)value);
        return true;
    }
    for (shift = 0; shift <= 48; shift += 16) {
        uint16_t part = (uint16_t)((bits >> shift) & 0xffffU);
        if (!emitted) {
            if (part == 0U && shift < 48) {
                continue;
            }
            v3_text_appendf(out,
                            cap,
                            "  movz x%d, #%u, lsl #%d\n",
                            reg_index,
                            (unsigned)part,
                            shift);
            emitted = true;
            continue;
        }
        if (part != 0U) {
            v3_text_appendf(out,
                            cap,
                            "  movk x%d, #%u, lsl #%d\n",
                            reg_index,
                            (unsigned)part,
                            shift);
        }
    }
    if (!emitted) {
        v3_text_appendf(out, cap, "  mov x%d, #0\n", reg_index);
    }
    return true;
}

static bool v3_parse_member_access_expr(const char *expr_text,
                                        char *base_out,
                                        size_t base_cap,
                                        char *field_out,
                                        size_t field_cap) {
    char expr[4096];
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t last_sep = -1;
    int32_t sep_len = 0;
    size_t i;
    size_t len;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len <= 0U) {
        return false;
    }
    for (i = 0; i < len; ++i) {
        char ch = expr[i];
        if (ch == '"' && (i == 0U || expr[i - 1U] != '\\')) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            if (paren_depth < 0) {
                return false;
            }
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            if (bracket_depth < 0) {
                return false;
            }
            continue;
        }
        if (ch == '.' && paren_depth == 0 && bracket_depth == 0) {
            last_sep = (int32_t)i;
            sep_len = 1;
            continue;
        }
        if (ch == '-' &&
            paren_depth == 0 &&
            bracket_depth == 0 &&
            i + 1U < len &&
            expr[i + 1U] == '>') {
            last_sep = (int32_t)i;
            sep_len = 2;
        }
    }
    if (in_string || paren_depth != 0 || bracket_depth != 0 || last_sep <= 0 || (size_t)last_sep + (size_t)sep_len >= len) {
        return false;
    }
    snprintf(base_out, base_cap, "%.*s", last_sep, expr);
    v3_trim_copy_text(base_out, base_out, base_cap);
    snprintf(field_out, field_cap, "%s", expr + last_sep + sep_len);
    v3_trim_copy_text(field_out, field_out, field_cap);
    if (base_out[0] == '\0' ||
        field_out[0] == '\0' ||
        strchr(field_out, '.') != NULL ||
        strstr(field_out, "->") != NULL ||
        strchr(field_out, '[') != NULL ||
        strchr(field_out, ']') != NULL ||
        strchr(field_out, '(') != NULL ||
        strchr(field_out, ')') != NULL ||
        strchr(field_out, ' ') != NULL) {
        return false;
    }
    return true;
}

static bool v3_parse_index_access_expr(const char *expr_text,
                                       char *base_out,
                                       size_t base_cap,
                                       char *index_out,
                                       size_t index_cap) {
    char expr[4096];
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t top_open = -1;
    size_t i;
    size_t len;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len < 3U || expr[len - 1U] != ']') {
        return false;
    }
    for (i = 0; i < len; ++i) {
        char ch = expr[i];
        if (ch == '"' && (i == 0 || expr[i - 1] != '\\')) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            if (paren_depth < 0) {
                return false;
            }
            continue;
        }
        if (ch == '[') {
            if (paren_depth == 0 && bracket_depth == 0) {
                top_open = (int32_t)i;
            }
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            if (bracket_depth < 0) {
                return false;
            }
            continue;
        }
    }
    if (in_string || paren_depth != 0 || bracket_depth != 0 || top_open <= 0) {
        return false;
    }
    snprintf(base_out, base_cap, "%.*s", top_open, expr);
    v3_trim_copy_text(base_out, base_out, base_cap);
    snprintf(index_out, index_cap, "%.*s", (int)(len - (size_t)top_open - 2U), expr + top_open + 1);
    v3_trim_copy_text(index_out, index_out, index_cap);
    return base_out[0] != '\0' && index_out[0] != '\0';
}

static bool v3_find_type_def_by_normalized(const V3LoweringPlanStub *lowering,
                                           const char *normalized_type,
                                           int32_t *index_out) {
    char stripped[PATH_MAX];
    char owner_module[PATH_MAX];
    char type_instance_name[128];
    char type_args[CHENG_V3_MAX_TYPE_PARAMS][256];
    size_t type_arg_count = 0U;
    if (index_out) {
        *index_out = -1;
    }
    v3_strip_internal_ref_type(normalized_type, stripped, sizeof(stripped));
    if (!v3_split_qualified_type_text(stripped,
                                      owner_module,
                                      sizeof(owner_module),
                                      type_instance_name,
                                      sizeof(type_instance_name)) ||
        !v3_parse_type_instance_text(type_instance_name,
                                     type_instance_name,
                                     sizeof(type_instance_name),
                                     type_args,
                                     &type_arg_count,
                                     CHENG_V3_MAX_TYPE_PARAMS)) {
        return false;
    }
    if (index_out) {
        *index_out = v3_find_type_def_index_by_symbol(lowering, owner_module, type_instance_name);
    }
    return index_out && *index_out >= 0;
}

static bool v3_resolve_field_meta_impl(const V3LoweringPlanStub *lowering,
                                       const char *normalized_type,
                                       const char *field_name,
                                       char *field_type_out,
                                       size_t field_type_cap,
                                       char *field_abi_out,
                                       size_t field_abi_cap,
                                       int32_t *field_offset_out,
                                       unsigned depth) {
    char pointer_base[256];
    int32_t type_index = -1;
    if (depth > 8U) {
        return false;
    }
    if (v3_type_text_strip_one_pointer_suffix(normalized_type, pointer_base, sizeof(pointer_base))) {
        return v3_resolve_field_meta_impl(lowering,
                                          pointer_base,
                                          field_name,
                                          field_type_out,
                                          field_type_cap,
                                          field_abi_out,
                                          field_abi_cap,
                                          field_offset_out,
                                          depth + 1U);
    }
    if (strcmp(normalized_type, "Bytes") == 0) {
        if (strcmp(field_name, "data") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "ptr");
            snprintf(field_abi_out, field_abi_cap, "%s", "ptr");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "len") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 8;
            return true;
        }
        return false;
    }
    if (strcmp(normalized_type, "str") == 0) {
        if (strcmp(field_name, "data") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "ptr");
            snprintf(field_abi_out, field_abi_cap, "%s", "ptr");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "len") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 8;
            return true;
        }
        if (strcmp(field_name, "storeId") == 0 || strcmp(field_name, "store_id") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 12;
            return true;
        }
        if (strcmp(field_name, "flags") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 16;
            return true;
        }
        return false;
    }
    if (strlen(normalized_type) > 2U &&
        strcmp(normalized_type + strlen(normalized_type) - 2U, "[]") == 0) {
        if (strcmp(field_name, "len") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "cap") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 4;
            return true;
        }
        if (strcmp(field_name, "buffer") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "ptr");
            snprintf(field_abi_out, field_abi_cap, "%s", "ptr");
            *field_offset_out = 8;
            return true;
        }
        return false;
    }
    if (v3_startswith(normalized_type, "Result[") && normalized_type[strlen(normalized_type) - 1U] == ']') {
        V3TypeLayoutStub value_layout;
        char value_type[256];
        int32_t value_offset;
        snprintf(value_type,
                 sizeof(value_type),
                 "%.*s",
                 (int)(strlen(normalized_type) - 8U),
                 normalized_type + 7);
        if (!v3_compute_type_layout_impl(lowering, value_type, &value_layout, depth + 1U)) {
            return false;
        }
        value_offset = v3_align_up_i32(1, value_layout.align);
        if (strcmp(field_name, "ok") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "bool");
            snprintf(field_abi_out, field_abi_cap, "%s", "bool");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "value") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", value_type);
            snprintf(field_abi_out, field_abi_cap, "%s", v3_type_abi_class(value_type));
            *field_offset_out = value_offset;
            return true;
        }
        if (strcmp(field_name, "err") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "std/result::ErrorInfo");
            snprintf(field_abi_out, field_abi_cap, "%s", "composite");
            *field_offset_out = v3_align_up_i32(value_offset + value_layout.size, 8);
            return true;
        }
        return false;
    }
    {
        char stripped[PATH_MAX];
        char owner_module[PATH_MAX];
        char type_instance_name[128];
        char type_name[128];
        char type_args[CHENG_V3_MAX_TYPE_PARAMS][256];
        size_t type_arg_count = 0U;
        V3ImportAlias *type_aliases = NULL;
        size_t type_alias_count = 0U;
        const V3TypeDefStub *type_def;
        bool ok = false;
        v3_strip_internal_ref_type(normalized_type, stripped, sizeof(stripped));
        if (!v3_split_qualified_type_text(stripped,
                                          owner_module,
                                          sizeof(owner_module),
                                          type_instance_name,
                                          sizeof(type_name)) ||
            !v3_parse_type_instance_text(type_instance_name,
                                         type_name,
                                         sizeof(type_name),
                                         type_args,
                                         &type_arg_count,
                                         CHENG_V3_MAX_TYPE_PARAMS)) {
            goto field_meta_cleanup;
        }
        type_index = v3_find_type_def_index_by_symbol(lowering, owner_module, type_instance_name);
        if (type_index < 0) {
            goto field_meta_cleanup;
        }
        type_def = &lowering->type_defs[type_index];
        if (type_def->kind == V3_TYPE_DEF_ALIAS) {
            char alias_target[256];
            if (type_def->generic_param_count > 0U) {
                type_aliases = (V3ImportAlias *)v3_xmalloc(sizeof(*type_aliases) * CHENG_V3_MAX_IMPORT_ALIASES);
                if (!v3_load_import_aliases_from_source_path(type_def->source_path,
                                                             type_aliases,
                                                             &type_alias_count,
                                                             CHENG_V3_MAX_IMPORT_ALIASES) ||
                    !v3_normalize_type_text_with_params(lowering,
                                                        type_def->owner_module_path,
                                                        type_aliases,
                                                        type_alias_count,
                                                        type_def->generic_param_names,
                                                        type_args,
                                                        type_arg_count,
                                                        type_def->alias_target,
                                                        alias_target,
                                                        sizeof(alias_target))) {
                    goto field_meta_cleanup;
                }
            } else {
                snprintf(alias_target, sizeof(alias_target), "%s", type_def->alias_target);
            }
            ok = v3_resolve_field_meta_impl(lowering,
                                            alias_target,
                                            field_name,
                                            field_type_out,
                                            field_type_cap,
                                            field_abi_out,
                                            field_abi_cap,
                                            field_offset_out,
                                            depth + 1U);
            goto field_meta_cleanup;
        }
        if (type_def->kind != V3_TYPE_DEF_RECORD) {
            goto field_meta_cleanup;
        }
        if (type_def->generic_param_count > 0U &&
            ((type_aliases = (V3ImportAlias *)v3_xmalloc(sizeof(*type_aliases) * CHENG_V3_MAX_IMPORT_ALIASES)) == NULL ||
             !v3_load_import_aliases_from_source_path(type_def->source_path,
                                                      type_aliases,
                                                      &type_alias_count,
                                                      CHENG_V3_MAX_IMPORT_ALIASES) ||
             type_def->generic_param_count != type_arg_count)) {
            goto field_meta_cleanup;
        }
        {
            int32_t offset = 0;
            int32_t i;
            for (i = 0; i < (int32_t)type_def->field_count; ++i) {
                V3TypeLayoutStub field_layout;
                int32_t field_align;
                char resolved_field_type[256];
                if (type_def->generic_param_count > 0U) {
                    if (!v3_normalize_type_text_with_params(lowering,
                                                            type_def->owner_module_path,
                                                            type_aliases,
                                                            type_alias_count,
                                                            type_def->generic_param_names,
                                                            type_args,
                                                            type_arg_count,
                                                            type_def->fields[i].type_text,
                                                            resolved_field_type,
                                                            sizeof(resolved_field_type))) {
                        goto field_meta_cleanup;
                    }
                } else {
                    snprintf(resolved_field_type, sizeof(resolved_field_type), "%s", type_def->fields[i].type_text);
                }
                if (!v3_compute_type_layout_impl(lowering,
                                                 resolved_field_type,
                                                 &field_layout,
                                                 depth + 1U)) {
                    goto field_meta_cleanup;
                }
                field_align = field_layout.align > 0 ? field_layout.align : 1;
                offset = v3_align_up_i32(offset, field_align);
                if (strcmp(type_def->fields[i].name, field_name) == 0) {
                    snprintf(field_type_out, field_type_cap, "%s", resolved_field_type);
                    snprintf(field_abi_out, field_abi_cap, "%s", v3_type_abi_class(resolved_field_type));
                    *field_offset_out = offset;
                    ok = true;
                    goto field_meta_cleanup;
                }
                offset += field_layout.size;
            }
        }
field_meta_cleanup:
        free(type_aliases);
        return ok;
    }
    return false;
}

static bool v3_resolve_field_meta(const V3LoweringPlanStub *lowering,
                                  const char *base_type_text,
                                  const char *field_name,
                                  char *field_type_out,
                                  size_t field_type_cap,
                                  char *field_abi_out,
                                  size_t field_abi_cap,
                                  int32_t *field_offset_out) {
    char normalized_type[256];
    v3_strip_var_prefix(base_type_text, normalized_type, sizeof(normalized_type));
    return v3_resolve_field_meta_impl(lowering,
                                      normalized_type,
                                      field_name,
                                      field_type_out,
                                      field_type_cap,
                                      field_abi_out,
                                      field_abi_cap,
                                      field_offset_out,
                                      0U);
}

static bool v3_resolve_field_path_expr(const V3LoweringPlanStub *lowering,
                                       const V3AsmLocalSlot *locals,
                                       size_t local_count,
                                       const char *expr_text,
                                       int32_t *base_local_index_out,
                                       char *field_type_out,
                                       size_t field_type_cap,
                                       char *field_abi_out,
                                       size_t field_abi_cap,
                                       int32_t *field_offset_out) {
    char expr[4096];
    char *segments[32];
    size_t segment_count = 0U;
    char *cursor;
    char current_type[256];
    int32_t local_index;
    int32_t total_offset = 0;
    size_t i;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0' ||
        strchr(expr, '(') != NULL ||
        strchr(expr, '[') != NULL ||
        strchr(expr, ' ') != NULL) {
        return false;
    }
    cursor = expr;
    segments[segment_count++] = cursor;
    while (*cursor != '\0') {
        if (*cursor == '.') {
            *cursor = '\0';
            if (segment_count >= 32U || cursor[1] == '\0') {
                return false;
            }
            segments[segment_count++] = cursor + 1;
        }
        cursor += 1;
    }
    if (segment_count < 2U) {
        return false;
    }
    local_index = v3_find_local_slot(locals, local_count, segments[0]);
    if (local_index < 0) {
        return false;
    }
    snprintf(current_type, sizeof(current_type), "%s", locals[local_index].type_text);
    for (i = 1; i < segment_count; ++i) {
        int32_t current_offset = 0;
        char next_type[256];
        char next_abi[32];
        if (!v3_resolve_field_meta(lowering,
                                   current_type,
                                   segments[i],
                                   next_type,
                                   sizeof(next_type),
                                   next_abi,
                                   sizeof(next_abi),
                                   &current_offset)) {
            return false;
        }
        total_offset += current_offset;
        snprintf(current_type, sizeof(current_type), "%s", next_type);
        snprintf(field_abi_out, field_abi_cap, "%s", next_abi);
    }
    if (base_local_index_out) {
        *base_local_index_out = local_index;
    }
    if (field_type_out) {
        snprintf(field_type_out, field_type_cap, "%s", current_type);
    }
    if (field_offset_out) {
        *field_offset_out = total_offset;
    }
    return true;
}

static bool v3_emit_index_access_address(const V3SystemLinkPlanStub *plan,
                                         const V3LoweringPlanStub *lowering,
                                         const V3LoweredFunctionStub *current_function,
                                         const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         const V3AsmLocalSlot *locals,
                                         size_t local_count,
                                         const char *expr_text,
                                         char *field_type_out,
                                         size_t field_type_cap,
                                         char *field_abi_out,
                                         size_t field_abi_cap,
                                         int addr_reg,
                                         int32_t call_arg_base,
                                         int32_t string_temp_base,
                                         int32_t string_temp_stride,
                                         int call_depth,
                                         char *out,
                                         size_t cap);
static bool v3_infer_expr_type(const V3SystemLinkPlanStub *plan,
                               const V3LoweringPlanStub *lowering,
                               const V3LoweredFunctionStub *current_function,
                               const V3ImportAlias *aliases,
                               size_t alias_count,
                               const V3AsmLocalSlot *locals,
                               size_t local_count,
                               const char *expr_text,
                               char *type_out,
                               size_t type_cap,
                               char *abi_out,
                               size_t abi_cap);

static bool v3_emit_field_path_address(char *out,
                                       size_t cap,
                                       const V3AsmLocalSlot *locals,
                                       size_t local_count,
                                       const V3LoweringPlanStub *lowering,
                                       const char *expr_text,
                                       char *field_type_out,
                                       size_t field_type_cap,
                                       char *field_abi_out,
                                       size_t field_abi_cap,
                                       int addr_reg) {
    char expr[4096];
    char *segments[32];
    size_t segment_count = 0U;
    char *cursor;
    char current_type[256];
    int32_t local_index;
    size_t i;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0' ||
        strchr(expr, '(') != NULL ||
        strchr(expr, '[') != NULL ||
        strchr(expr, ' ') != NULL) {
        return false;
    }
    cursor = expr;
    segments[segment_count++] = cursor;
    while (*cursor != '\0') {
        if (*cursor == '.') {
            *cursor = '\0';
            if (segment_count >= 32U || cursor[1] == '\0') {
                return false;
            }
            segments[segment_count++] = cursor + 1;
        }
        cursor += 1;
    }
    if (segment_count < 2U) {
        return false;
    }
    local_index = v3_find_local_slot(locals, local_count, segments[0]);
    if (local_index < 0 ||
        !v3_emit_local_value_address(out, cap, &locals[local_index], addr_reg)) {
        return false;
    }
    snprintf(current_type, sizeof(current_type), "%s", locals[local_index].type_text);
    for (i = 1; i < segment_count; ++i) {
        int32_t field_offset = 0;
        char next_type[256];
        char next_abi[32];
        if (v3_is_internal_ref_type(current_type)) {
            v3_text_appendf(out, cap, "  ldr x%d, [x%d]\n", addr_reg, addr_reg);
        }
        if (!v3_resolve_field_meta(lowering,
                                   current_type,
                                   segments[i],
                                   next_type,
                                   sizeof(next_type),
                                   next_abi,
                                   sizeof(next_abi),
                                   &field_offset)) {
            return false;
        }
        if (field_offset != 0 &&
            !v3_emit_add_address_offset(out, cap, addr_reg, addr_reg, field_offset)) {
            return false;
        }
        snprintf(current_type, sizeof(current_type), "%s", next_type);
        snprintf(field_abi_out, field_abi_cap, "%s", next_abi);
    }
    snprintf(field_type_out, field_type_cap, "%s", current_type);
    return true;
}

static bool v3_emit_result_field_address(const V3SystemLinkPlanStub *plan,
                                         const V3LoweringPlanStub *lowering,
                                         const V3LoweredFunctionStub *current_function,
                                         const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         const V3AsmLocalSlot *locals,
                                         size_t local_count,
                                         const char *arg_expr,
                                         const char *field_name,
                                         int addr_reg,
                                         int32_t call_arg_base,
                                         int32_t string_temp_base,
                                         int32_t string_temp_stride,
                                         int32_t *string_label_index_io,
                                         int call_depth,
                                         char *out,
                                         size_t cap,
                                         char *field_type_out,
                                         size_t field_type_cap,
                                         char *field_abi_out,
                                         size_t field_abi_cap);

static bool v3_emit_member_access_address(const V3SystemLinkPlanStub *plan,
                                          const V3LoweringPlanStub *lowering,
                                          const V3LoweredFunctionStub *current_function,
                                          const V3ImportAlias *aliases,
                                          size_t alias_count,
                                          const V3AsmLocalSlot *locals,
                                          size_t local_count,
                                          const char *expr_text,
                                          char *field_type_out,
                                          size_t field_type_cap,
                                          char *field_abi_out,
                                          size_t field_abi_cap,
                                          int addr_reg,
                                          int32_t call_arg_base,
                                          int32_t string_temp_base,
                                          int32_t string_temp_stride,
                                          int call_depth,
                                          char *out,
                                          size_t cap) {
    char base_expr[4096];
    char field_name[128];
    char base_type[256];
    char base_abi[32];
    char normalized_base_type[256];
    char nested_type[256];
    char nested_abi[32];
    char result_callee[PATH_MAX];
    char result_arg_text[4096] = {0};
    char result_args[CHENG_V3_MAX_CALL_ARGS][4096];
    size_t result_arg_count = 0U;
    int32_t field_offset = 0;
    int32_t local_index = -1;
    if (!v3_parse_member_access_expr(expr_text,
                                     base_expr,
                                     sizeof(base_expr),
                                     field_name,
                                     sizeof(field_name)) ||
        !v3_infer_expr_type(plan,
                            lowering,
                            current_function,
                            aliases,
                            alias_count,
                            locals,
                            local_count,
                            base_expr,
                            base_type,
                            sizeof(base_type),
                            base_abi,
                            sizeof(base_abi)) ||
        !v3_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                base_type,
                                normalized_base_type,
                                sizeof(normalized_base_type)) ||
        !v3_resolve_field_meta(lowering,
                               base_type,
                               field_name,
                               field_type_out,
                               field_type_cap,
                               field_abi_out,
                               field_abi_cap,
                               &field_offset)) {
        return false;
    }
    local_index = v3_find_local_slot(locals, local_count, base_expr);
    if (local_index >= 0) {
        if (!v3_emit_local_value_address(out, cap, &locals[local_index], addr_reg)) {
            return false;
        }
    } else if (v3_emit_owner_global_var_address(plan,
                                                lowering,
                                                current_function,
                                                base_expr,
                                                nested_type,
                                                sizeof(nested_type),
                                                nested_abi,
                                                sizeof(nested_abi),
                                                addr_reg,
                                                out,
                                                cap)) {
    } else if ((v3_parse_call_text(base_expr,
                                   result_callee,
                                   sizeof(result_callee),
                                   result_args,
                                   &result_arg_count,
                                   CHENG_V3_MAX_CALL_ARGS) ||
                v3_parse_prefix_single_arg_call(base_expr,
                                                result_callee,
                                                sizeof(result_callee),
                                                result_arg_text,
                                                sizeof(result_arg_text))) &&
               ((result_arg_count == 1U) || (result_arg_count == 0U && result_arg_text[0] != '\0')) &&
               v3_resolve_result_intrinsic_kind(lowering,
                                               current_function->owner_module_path,
                                               aliases,
                                               alias_count,
                                               result_callee) == V3_RESULT_INTRINSIC_VALUE) {
        if (result_arg_count == 0U) {
            snprintf(result_args[0], sizeof(result_args[0]), "%s", result_arg_text);
            result_arg_count = 1U;
        }
        if (!v3_emit_result_field_address(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          result_args[0],
                                          "value",
                                          addr_reg,
                                          call_arg_base,
                                          string_temp_base,
                                          string_temp_stride,
                                          NULL,
                                          call_depth,
                                          out,
                                          cap,
                                          nested_type,
                                          sizeof(nested_type),
                                          nested_abi,
                                          sizeof(nested_abi))) {
            return false;
        }
    } else if (!v3_emit_index_access_address(plan,
                                             lowering,
                                             current_function,
                                             aliases,
                                             alias_count,
                                             locals,
                                             local_count,
                                             base_expr,
                                             nested_type,
                                             sizeof(nested_type),
                                             nested_abi,
                                             sizeof(nested_abi),
                                             addr_reg,
                                             call_arg_base,
                                             string_temp_base,
                                             string_temp_stride,
                                             call_depth + 1,
                                             out,
                                             cap) &&
               !v3_emit_member_access_address(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              base_expr,
                                              nested_type,
                                              sizeof(nested_type),
                                              nested_abi,
                                              sizeof(nested_abi),
                                              addr_reg,
                                              call_arg_base,
                                              string_temp_base,
                                              string_temp_stride,
                                              call_depth + 1,
                                              out,
                                              cap) &&
               !v3_emit_field_path_address(out,
                                           cap,
                                           locals,
                                           local_count,
                                           lowering,
                                           base_expr,
                                           nested_type,
                                           sizeof(nested_type),
                                           nested_abi,
                                           sizeof(nested_abi),
                                           addr_reg)) {
        return false;
    }
    if (v3_is_internal_ref_type(base_type) ||
        (strcmp(base_abi, "ptr") == 0 &&
         (strcmp(normalized_base_type, "ptr") == 0 ||
          strcmp(normalized_base_type, "cstring") == 0 ||
          v3_type_text_strip_one_pointer_suffix(normalized_base_type, nested_type, sizeof(nested_type))))) {
        v3_text_appendf(out, cap, "  ldr x%d, [x%d]\n", addr_reg, addr_reg);
    }
    if (!v3_emit_add_address_offset(out, cap, addr_reg, addr_reg, field_offset)) {
        return false;
    }
    return true;
}

static bool v3_infer_expr_type(const V3SystemLinkPlanStub *plan,
                               const V3LoweringPlanStub *lowering,
                               const V3LoweredFunctionStub *current_function,
                               const V3ImportAlias *aliases,
                               size_t alias_count,
                               const V3AsmLocalSlot *locals,
                               size_t local_count,
                               const char *expr_text,
                               char *type_out,
                               size_t type_cap,
                               char *abi_out,
                               size_t abi_cap);
static bool v3_codegen_expr_scalar(const V3SystemLinkPlanStub *plan,
                                   const V3LoweringPlanStub *lowering,
                                   const V3LoweredFunctionStub *current_function,
                                   const V3ImportAlias *aliases,
                                   size_t alias_count,
                                   const V3AsmLocalSlot *locals,
                                   size_t local_count,
                                   const char *expr_text,
                                   const char *expected_abi,
                                   int target_reg,
                                   int32_t call_arg_base,
                                   int32_t string_temp_base,
                                   int32_t string_temp_stride,
                                   int call_depth,
                                   char *out,
                                   size_t cap);
static bool v3_parse_named_arg_meta(const char *arg_text,
                                    char *field_out,
                                    size_t field_cap,
                                    char *expr_out,
                                    size_t expr_cap);

static bool v3_emit_index_access_address(const V3SystemLinkPlanStub *plan,
                                         const V3LoweringPlanStub *lowering,
                                         const V3LoweredFunctionStub *current_function,
                                         const V3ImportAlias *aliases,
                                         size_t alias_count,
                                         const V3AsmLocalSlot *locals,
                                         size_t local_count,
                                         const char *expr_text,
                                         char *field_type_out,
                                         size_t field_type_cap,
                                         char *field_abi_out,
                                         size_t field_abi_cap,
                                         int addr_reg,
                                         int32_t call_arg_base,
                                         int32_t string_temp_base,
                                         int32_t string_temp_stride,
                                         int call_depth,
                                         char *out,
                                         size_t cap) {
    char expr[4096];
    char base_expr[4096];
    char index_expr[4096];
    char base_type[256];
    char base_abi[32];
    char normalized_base_type[256];
    char elem_type[256];
    char elem_abi[32];
    V3TypeLayoutStub elem_layout;
    int32_t fixed_len = 0;
    int32_t local_index;
    int32_t elem_size = 0;
    int data_offset = -1;
    bool base_is_fixed_array = false;
    int base_reg = addr_reg == 13 ? 14 : 13;
    int index_reg = 11;
    int size_reg = 12;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (!v3_parse_index_access_expr(expr, base_expr, sizeof(base_expr), index_expr, sizeof(index_expr)) ||
        !v3_infer_expr_type(plan,
                            lowering,
                            current_function,
                            aliases,
                            alias_count,
                            locals,
                            local_count,
                            base_expr,
                            base_type,
                            sizeof(base_type),
                            base_abi,
                            sizeof(base_abi)) ||
        !v3_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                base_type,
                                normalized_base_type,
                                sizeof(normalized_base_type))) {
        return false;
    }
    if (strcmp(normalized_base_type, "Bytes") == 0) {
        snprintf(elem_type, sizeof(elem_type), "%s", "int32");
        snprintf(elem_abi, sizeof(elem_abi), "%s", "i32");
        elem_size = 1;
        data_offset = 0;
    } else if (strcmp(normalized_base_type, "str") == 0) {
        snprintf(elem_type, sizeof(elem_type), "%s", "char");
        snprintf(elem_abi, sizeof(elem_abi), "%s", "i32");
        elem_size = 1;
        data_offset = 0;
    } else if (strlen(normalized_base_type) > 2U &&
               strcmp(normalized_base_type + strlen(normalized_base_type) - 2U, "[]") == 0) {
        snprintf(elem_type,
                 sizeof(elem_type),
                 "%.*s",
                 (int)(strlen(normalized_base_type) - 2U),
                 normalized_base_type);
        snprintf(elem_abi, sizeof(elem_abi), "%s", v3_type_abi_class(elem_type));
        if (!v3_compute_type_layout_impl(lowering, elem_type, &elem_layout, 0U)) {
            return false;
        }
        elem_size = elem_layout.size;
        data_offset = 8;
    } else if (v3_parse_fixed_array_type(normalized_base_type, elem_type, sizeof(elem_type), &fixed_len)) {
        base_is_fixed_array = true;
        snprintf(elem_abi, sizeof(elem_abi), "%s", v3_type_abi_class(elem_type));
        if (!v3_compute_type_layout_impl(lowering, elem_type, &elem_layout, 0U)) {
            return false;
        }
        elem_size = elem_layout.size;
    } else {
        return false;
    }
    local_index = v3_find_local_slot(locals, local_count, base_expr);
    if (local_index >= 0) {
        if (v3_abi_class_scalar_or_ptr(locals[local_index].abi_class) &&
            strcmp(normalized_base_type, "Bytes") != 0 &&
            strcmp(normalized_base_type, "str") != 0) {
            return false;
        }
        if (!v3_emit_local_value_address(out, cap, &locals[local_index], base_reg)) {
            return false;
        }
    } else {
        char nested_type[256];
        char nested_abi[32];
        if (v3_emit_owner_global_var_address(plan,
                                             lowering,
                                             current_function,
                                             base_expr,
                                             nested_type,
                                             sizeof(nested_type),
                                             nested_abi,
                                             sizeof(nested_abi),
                                             base_reg,
                                             out,
                                             cap)) {
            /* already loaded */
        } else if (!v3_emit_member_access_address(plan,
                                                  lowering,
                                                  current_function,
                                                  aliases,
                                                  alias_count,
                                                  locals,
                                                  local_count,
                                                  base_expr,
                                                  nested_type,
                                                  sizeof(nested_type),
                                                  nested_abi,
                                                  sizeof(nested_abi),
                                                  base_reg,
                                                  call_arg_base,
                                                  string_temp_base,
                                                  string_temp_stride,
                                                  call_depth + 1,
                                                  out,
                                                  cap) &&
                   !v3_emit_index_access_address(plan,
                                                 lowering,
                                                 current_function,
                                                 aliases,
                                                 alias_count,
                                                 locals,
                                                 local_count,
                                                 base_expr,
                                                 nested_type,
                                                 sizeof(nested_type),
                                                 nested_abi,
                                                 sizeof(nested_abi),
                                                 base_reg,
                                                 call_arg_base,
                                                 string_temp_base,
                                                 string_temp_stride,
                                                 call_depth + 1,
                                                 out,
                                                 cap) &&
                   !v3_emit_field_path_address(out,
                                               cap,
                                               locals,
                                               local_count,
                                               lowering,
                                               base_expr,
                                               nested_type,
                                               sizeof(nested_type),
                                               nested_abi,
                                               sizeof(nested_abi),
                                               base_reg)) {
            return false;
        }
    }
    v3_emit_address_spill_store(out, cap, call_arg_base, call_depth, base_reg);
    if (!v3_codegen_expr_scalar(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                index_expr,
                                "i64",
                                index_reg,
                                call_arg_base,
                                string_temp_base,
                                string_temp_stride,
                                call_depth + 1,
                                out,
                                cap)) {
        return false;
    }
    v3_emit_address_spill_load(out, cap, call_arg_base, call_depth, base_reg);
    if (elem_size <= 0) {
        return false;
    }
    if (base_is_fixed_array || strcmp(normalized_base_type, "Bytes") == 0 || strcmp(normalized_base_type, "str") == 0 ||
        (strlen(normalized_base_type) > 2U &&
         strcmp(normalized_base_type + strlen(normalized_base_type) - 2U, "[]") == 0)) {
        if (base_is_fixed_array) {
            if (!v3_emit_mov_imm(out, cap, size_reg, fixed_len)) {
                return false;
            }
        } else if (strcmp(normalized_base_type, "Bytes") == 0 || strcmp(normalized_base_type, "str") == 0) {
            v3_text_appendf(out, cap, "  ldrsw x%d, [x%d, #8]\n", size_reg, base_reg);
        } else {
            v3_text_appendf(out, cap, "  ldrsw x%d, [x%d]\n", size_reg, base_reg);
        }
        v3_emit_address_spill_store(out, cap, call_arg_base, call_depth, base_reg);
        v3_emit_index_spill_store(out, cap, call_arg_base, call_depth, index_reg);
        v3_text_appendf(out, cap, "  mov w0, w%d\n", size_reg);
        v3_text_appendf(out, cap, "  mov w1, w%d\n", index_reg);
        v3_emit_call_named_symbol(plan, out, cap, "cheng_bounds_check");
        v3_emit_address_spill_load(out, cap, call_arg_base, call_depth, base_reg);
        v3_emit_index_spill_load(out, cap, call_arg_base, call_depth, index_reg);
    }
    if (data_offset >= 0) {
        v3_text_appendf(out, cap, "  ldr x%d, [x%d, #%d]\n", base_reg, base_reg, data_offset);
    }
    if (elem_size != 1) {
        if (!v3_emit_mov_imm(out, cap, size_reg, elem_size)) {
            return false;
        }
        v3_text_appendf(out, cap, "  mul x%d, x%d, x%d\n", index_reg, index_reg, size_reg);
    }
    v3_text_appendf(out, cap, "  add x%d, x%d, x%d\n", addr_reg, base_reg, index_reg);
    if (field_type_out) {
        snprintf(field_type_out, field_type_cap, "%s", elem_type);
    }
    if (field_abi_out) {
        snprintf(field_abi_out, field_abi_cap, "%s", elem_abi);
    }
    return true;
}

static bool v3_infer_lvalue_expr_type(const V3SystemLinkPlanStub *plan,
                                      const V3LoweringPlanStub *lowering,
                                      const V3LoweredFunctionStub *current_function,
                                      const V3ImportAlias *aliases,
                                      size_t alias_count,
                                      const V3AsmLocalSlot *locals,
                                      size_t local_count,
                                      const char *expr_text,
                                      char *field_type_out,
                                      size_t field_type_cap,
                                      char *field_abi_out,
                                      size_t field_abi_cap) {
    char base_expr[4096];
    char field_name[128];
    char index_expr[4096];
    char base_type[256];
    char base_abi[32];
    char normalized_base_type[256];
    int32_t field_offset = 0;
    int32_t base_local_index = -1;
    int32_t fixed_len = 0;
    if (v3_parse_deref_expr(expr_text, base_expr, sizeof(base_expr)) &&
        v3_infer_expr_type(plan,
                           lowering,
                           current_function,
                           aliases,
                           alias_count,
                           locals,
                           local_count,
                           base_expr,
                           base_type,
                           sizeof(base_type),
                           base_abi,
                           sizeof(base_abi)) &&
        strcmp(base_abi, "ptr") == 0 &&
        v3_resolve_pointer_pointee_type(lowering,
                                        current_function->owner_module_path,
                                        aliases,
                                        alias_count,
                                        base_type,
                                        field_type_out,
                                        field_type_cap,
                                        field_abi_out,
                                        field_abi_cap)) {
        return true;
    }
    if (v3_resolve_field_path_expr(lowering,
                                   locals,
                                   local_count,
                                   expr_text,
                                   &base_local_index,
                                   field_type_out,
                                   field_type_cap,
                                   field_abi_out,
                                   field_abi_cap,
                                   &field_offset)) {
        return true;
    }
    base_local_index = v3_find_local_slot(locals, local_count, expr_text);
    if (base_local_index >= 0) {
        snprintf(field_type_out, field_type_cap, "%s", locals[base_local_index].type_text);
        snprintf(field_abi_out, field_abi_cap, "%s", locals[base_local_index].abi_class);
        return true;
    }
    if (v3_find_top_level_var_decl(plan,
                                   lowering,
                                   current_function->owner_module_path,
                                   expr_text,
                                   field_type_out,
                                   field_type_cap,
                                   field_abi_out,
                                   field_abi_cap)) {
        return true;
    }
    if (v3_parse_member_access_expr(expr_text,
                                    base_expr,
                                    sizeof(base_expr),
                                    field_name,
                                    sizeof(field_name)) &&
        v3_infer_expr_type(plan,
                           lowering,
                           current_function,
                           aliases,
                           alias_count,
                           locals,
                           local_count,
                           base_expr,
                           base_type,
                           sizeof(base_type),
                           base_abi,
                           sizeof(base_abi)) &&
        v3_resolve_field_meta(lowering,
                              base_type,
                              field_name,
                              field_type_out,
                              field_type_cap,
                              field_abi_out,
                              field_abi_cap,
                              &field_offset)) {
        return true;
    }
    if (!v3_parse_index_access_expr(expr_text,
                                    base_expr,
                                    sizeof(base_expr),
                                    index_expr,
                                    sizeof(index_expr)) ||
        !v3_infer_expr_type(plan,
                            lowering,
                            current_function,
                            aliases,
                            alias_count,
                            locals,
                            local_count,
                            base_expr,
                            base_type,
                            sizeof(base_type),
                            base_abi,
                            sizeof(base_abi)) ||
        !v3_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                base_type,
                                normalized_base_type,
                                sizeof(normalized_base_type))) {
        return false;
    }
    if (strcmp(normalized_base_type, "Bytes") == 0) {
        snprintf(field_type_out, field_type_cap, "%s", "int32");
        snprintf(field_abi_out, field_abi_cap, "%s", "i32");
        return true;
    }
    if (strcmp(normalized_base_type, "str") == 0) {
        snprintf(field_type_out, field_type_cap, "%s", "char");
        snprintf(field_abi_out, field_abi_cap, "%s", "i32");
        return true;
    }
    if (strlen(normalized_base_type) > 2U &&
        strcmp(normalized_base_type + strlen(normalized_base_type) - 2U, "[]") == 0) {
        snprintf(field_type_out,
                 field_type_cap,
                 "%.*s",
                 (int)(strlen(normalized_base_type) - 2U),
                 normalized_base_type);
        snprintf(field_abi_out, field_abi_cap, "%s", v3_type_abi_class(field_type_out));
        return true;
    }
    if (v3_parse_fixed_array_type(normalized_base_type,
                                  field_type_out,
                                  field_type_cap,
                                  &fixed_len)) {
        snprintf(field_abi_out, field_abi_cap, "%s", v3_type_abi_class(field_type_out));
        return true;
    }
    return false;
}

static bool v3_emit_lvalue_address(const V3SystemLinkPlanStub *plan,
                                   const V3LoweringPlanStub *lowering,
                                   const V3LoweredFunctionStub *current_function,
                                   const V3ImportAlias *aliases,
                                   size_t alias_count,
                                   const V3AsmLocalSlot *locals,
                                   size_t local_count,
                                   const char *expr_text,
                                   char *field_type_out,
                                   size_t field_type_cap,
                                   char *field_abi_out,
                                   size_t field_abi_cap,
                                   int addr_reg,
                                   int32_t call_arg_base,
                                   int32_t string_temp_base,
                                   int32_t string_temp_stride,
                                   int call_depth,
                                   char *out,
                                   size_t cap) {
    char deref_expr[4096];
    char pointer_type[256];
    char pointer_abi[32];
    if (v3_parse_deref_expr(expr_text, deref_expr, sizeof(deref_expr))) {
        int pointer_reg = addr_reg == 12 ? 11 : 12;
        if (!v3_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                deref_expr,
                                pointer_type,
                                sizeof(pointer_type),
                                pointer_abi,
                                sizeof(pointer_abi)) ||
            strcmp(pointer_abi, "ptr") != 0 ||
            !v3_resolve_pointer_pointee_type(lowering,
                                             current_function->owner_module_path,
                                             aliases,
                                             alias_count,
                                             pointer_type,
                                             field_type_out,
                                             field_type_cap,
                                             field_abi_out,
                                             field_abi_cap) ||
            !v3_codegen_expr_scalar(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    deref_expr,
                                    "ptr",
                                    pointer_reg,
                                    call_arg_base,
                                    string_temp_base,
                                    string_temp_stride,
                                    call_depth + 1,
                                    out,
                                    cap)) {
            return false;
        }
        if (pointer_reg != addr_reg) {
            v3_text_appendf(out, cap, "  mov x%d, x%d\n", addr_reg, pointer_reg);
        }
        return true;
    }
    if (v3_emit_owner_global_var_address(plan,
                                         lowering,
                                         current_function,
                                         expr_text,
                                         field_type_out,
                                         field_type_cap,
                                         field_abi_out,
                                         field_abi_cap,
                                         addr_reg,
                                         out,
                                         cap) ||
        v3_emit_member_access_address(plan,
                                      lowering,
                                      current_function,
                                      aliases,
                                      alias_count,
                                      locals,
                                      local_count,
                                      expr_text,
                                      field_type_out,
                                      field_type_cap,
                                      field_abi_out,
                                      field_abi_cap,
                                      addr_reg,
                                      call_arg_base,
                                      string_temp_base,
                                      string_temp_stride,
                                      call_depth,
                                      out,
                                      cap) ||
        v3_emit_field_path_address(out,
                                   cap,
                                   locals,
                                   local_count,
                                   lowering,
                                   expr_text,
                                   field_type_out,
                                   field_type_cap,
                                   field_abi_out,
                                   field_abi_cap,
                                   addr_reg) ||
        v3_emit_index_access_address(plan,
                                     lowering,
                                     current_function,
                                     aliases,
                                     alias_count,
                                     locals,
                                     local_count,
                                     expr_text,
                                     field_type_out,
                                     field_type_cap,
                                     field_abi_out,
                                     field_abi_cap,
                                     addr_reg,
                                     call_arg_base,
                                     string_temp_base,
                                     string_temp_stride,
                                     call_depth,
                                     out,
                                     cap)) {
        return true;
    }
    return false;
}

typedef struct {
    char expr[8192];
    char outer[8192];
    char base_name[256];
    char field_name[128];
    char index_expr[4096];
    char if_cond[4096];
    char if_true[4096];
    char if_false[4096];
    char ternary_cond[4096];
    char ternary_true[4096];
    char ternary_false[4096];
    char named_field[128];
    char named_expr[4096];
    char callee[PATH_MAX];
    char arg_text[4096];
    char args[CHENG_V3_MAX_CALL_ARGS][4096];
} V3ExprPrepScratch;

static bool v3_prepare_expr_call_state(const V3SystemLinkPlanStub *plan,
                                       const V3LoweringPlanStub *lowering,
                                       const V3LoweredFunctionStub *current_function,
                                       const V3ImportAlias *aliases,
                                       size_t alias_count,
                                       V3AsmLocalSlot *locals,
                                       size_t *local_count,
                                       size_t local_cap,
                                       int32_t *next_offset_io,
                                       const char *expr_text,
                                       int call_depth,
                                       int32_t *max_call_depth_io);

static bool v3_prepare_expr_call_state_impl(const V3SystemLinkPlanStub *plan,
                                            const V3LoweringPlanStub *lowering,
                                            const V3LoweredFunctionStub *current_function,
                                            const V3ImportAlias *aliases,
                                            size_t alias_count,
                                            V3AsmLocalSlot *locals,
                                            size_t *local_count,
                                            size_t local_cap,
                                            int32_t *next_offset_io,
                                            const char *expr_text,
                                            int call_depth,
                                            int32_t *max_call_depth_io,
                                            V3ExprPrepScratch *scratch) {
    static const char *OPS[] = {
        "||", "&&", "==", "!=", "<=", ">=", "<<", ">>", "<", ">", "|", "^", "&", "+", "-", "*", "/", "%"
    };
#define expr (scratch->expr)
#define outer (scratch->outer)
#define base_name (scratch->base_name)
#define field_name (scratch->field_name)
#define index_expr (scratch->index_expr)
#define if_cond (scratch->if_cond)
#define if_true (scratch->if_true)
#define if_false (scratch->if_false)
#define ternary_cond (scratch->ternary_cond)
#define ternary_true (scratch->ternary_true)
#define ternary_false (scratch->ternary_false)
#define named_field (scratch->named_field)
#define named_expr (scratch->named_expr)
#define callee (scratch->callee)
#define arg_text (scratch->arg_text)
#define args (scratch->args)
    size_t arg_count = 0U;
    size_t i;
    v3_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return true;
    }
    if (v3_parse_named_arg_meta(expr,
                                named_field,
                                sizeof(named_field),
                                named_expr,
                                sizeof(named_expr))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          named_expr,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (v3_trim_outer_parens(expr, outer, sizeof(outer))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          outer,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (expr[0] == '!') {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          expr + 1,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (expr[0] == '-' && expr[1] != '\0' &&
        !v3_parse_int_literal_text(expr, NULL)) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          expr + 1,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (v3_parse_address_of_expr(expr, base_name, sizeof(base_name)) ||
        v3_parse_deref_expr(expr, base_name, sizeof(base_name))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          base_name,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (v3_parse_if_expr(expr,
                         if_cond,
                         sizeof(if_cond),
                         if_true,
                         sizeof(if_true),
                         if_false,
                         sizeof(if_false))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          if_cond,
                                          call_depth,
                                          max_call_depth_io) &&
               v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          if_true,
                                          call_depth,
                                          max_call_depth_io) &&
               v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          if_false,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (v3_parse_ternary_expr(expr,
                              ternary_cond,
                              sizeof(ternary_cond),
                              ternary_true,
                              sizeof(ternary_true),
                              ternary_false,
                              sizeof(ternary_false))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          ternary_cond,
                                          call_depth,
                                          max_call_depth_io) &&
               v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          ternary_true,
                                          call_depth,
                                          max_call_depth_io) &&
               v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          ternary_false,
                                          call_depth,
                                          max_call_depth_io);
    }
    for (i = 0; i < sizeof(OPS) / sizeof(OPS[0]); ++i) {
        int32_t op_index = v3_find_top_level_binary_op_last(expr, OPS[i]);
        if (op_index >= 0) {
            char left[4096];
            char right[4096];
            int next_call_depth = call_depth + 1;
            snprintf(left, sizeof(left), "%.*s", op_index, expr);
            snprintf(right, sizeof(right), "%s", expr + op_index + strlen(OPS[i]));
            v3_trim_copy_text(left, left, sizeof(left));
            v3_trim_copy_text(right, right, sizeof(right));
            v3_update_max_i32(max_call_depth_io, next_call_depth);
            return v3_prepare_expr_call_state(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              local_cap,
                                              next_offset_io,
                                              left,
                                              next_call_depth,
                                              max_call_depth_io) &&
                   v3_prepare_expr_call_state(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              local_cap,
                                              next_offset_io,
                                              right,
                                              next_call_depth,
                                              max_call_depth_io);
        }
    }
    if (v3_find_expr_top_level_const(lowering,
                                     current_function->owner_module_path,
                                     aliases,
                                     alias_count,
                                     expr) != NULL) {
        return true;
    }
    if (v3_parse_member_access_expr(expr, base_name, sizeof(base_name), field_name, sizeof(field_name))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          base_name,
                                          call_depth,
                                          max_call_depth_io);
    }
    if (v3_parse_index_access_expr(expr, base_name, sizeof(base_name), index_expr, sizeof(index_expr))) {
        return v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                          base_name,
                                          call_depth,
                                          max_call_depth_io) &&
               v3_prepare_expr_call_state(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          local_cap,
                                          next_offset_io,
                                              index_expr,
                                              call_depth,
                                              max_call_depth_io);
    }
    if (v3_parse_list_literal_text(expr, args, &arg_count, CHENG_V3_MAX_CALL_ARGS)) {
        for (i = 0; i < arg_count; ++i) {
            if (!v3_prepare_expr_call_state(plan,
                                            lowering,
                                            current_function,
                                            aliases,
                                            alias_count,
                                            locals,
                                            local_count,
                                            local_cap,
                                            next_offset_io,
                                            args[i],
                                            call_depth,
                                            max_call_depth_io)) {
                return false;
            }
        }
        return true;
    }
    if (v3_parse_call_text(expr, callee, sizeof(callee), args, &arg_count, CHENG_V3_MAX_CALL_ARGS) ||
        v3_parse_prefix_single_arg_call(expr, callee, sizeof(callee), arg_text, sizeof(arg_text))) {
        V3AsmCallTarget target;
        bool has_target = false;
        bool is_constructor_call = false;
        V3ResultIntrinsicKind result_kind;
        int next_call_depth = call_depth + 1;
        const char *ctor_base = strrchr(callee, '.');
        ctor_base = ctor_base ? ctor_base + 1 : callee;
        is_constructor_call = ctor_base[0] >= 'A' && ctor_base[0] <= 'Z';
        if (arg_count == 0U && arg_text[0] != '\0') {
            snprintf(args[0], sizeof(args[0]), "%s", arg_text);
            arg_count = 1U;
        }
        if (strcmp(callee, "new") == 0 && arg_count == 1U) {
            return true;
        }
        if (strcmp(callee, "sizeof") == 0 && arg_count == 1U) {
            return true;
        }
        {
            char cast_target_type[256];
            char cast_target_abi[32];
            if (arg_count == 1U &&
                v3_resolve_scalar_or_pointer_cast_target(lowering,
                                                         current_function->owner_module_path,
                                                         aliases,
                                                         alias_count,
                                                         callee,
                                                         cast_target_type,
                                                         sizeof(cast_target_type),
                                                         cast_target_abi,
                                                         sizeof(cast_target_abi))) {
                return v3_prepare_expr_call_state(plan,
                                                  lowering,
                                                  current_function,
                                                  aliases,
                                                  alias_count,
                                                  locals,
                                                  local_count,
                                                  local_cap,
                                                  next_offset_io,
                                                  args[0],
                                                  call_depth,
                                                  max_call_depth_io);
            }
        }
        if ((strcmp(callee, "int") == 0 ||
             strcmp(callee, "int64") == 0 ||
             strcmp(callee, "int32") == 0 ||
             strcmp(callee, "uint32") == 0 ||
             strcmp(callee, "uint64") == 0 ||
             strcmp(callee, "int16") == 0 ||
             strcmp(callee, "uint16") == 0 ||
             strcmp(callee, "int8") == 0 ||
             strcmp(callee, "uint8") == 0 ||
             strcmp(callee, "ptr") == 0 ||
             strcmp(callee, "cstring") == 0 ||
             strcmp(callee, "bool") == 0) && arg_count == 1U) {
            return v3_prepare_expr_call_state(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              local_cap,
                                              next_offset_io,
                                              args[0],
                                              call_depth,
                                              max_call_depth_io);
        }
        v3_update_max_i32(max_call_depth_io, next_call_depth);
        result_kind = v3_resolve_result_intrinsic_kind(lowering,
                                                       current_function->owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       callee);
        has_target = v3_resolve_call_target(plan,
                                            lowering,
                                            current_function,
                                            aliases,
                                            alias_count,
                                            callee,
                                            &target);
        for (i = 0; i < arg_count; ++i) {
            if (!v3_prepare_expr_call_state(plan,
                                            lowering,
                                            current_function,
                                            aliases,
                                            alias_count,
                                            locals,
                                            local_count,
                                            local_cap,
                                            next_offset_io,
                                            args[i],
                                            next_call_depth,
                                            max_call_depth_io)) {
                fprintf(stderr,
                        "[cheng_v3_seed] prepare call arg state failed caller=%s callee=%s arg_index=%zu expr=%s\n",
                        current_function->symbol_text,
                        callee,
                        i,
                        args[i]);
                return false;
            }
            if (is_constructor_call) {
                continue;
            }
            if (has_target &&
                i < target.param_count &&
                target.param_is_var[i]) {
                continue;
            }
            if (has_target &&
                i < target.param_count &&
                v3_abi_class_scalar_or_ptr(target.param_abi_classes[i])) {
                continue;
            }
            if (!v3_prepare_composite_call_arg_temp(plan,
                                                    lowering,
                                                    current_function,
                                                    aliases,
                                                    alias_count,
                                                    locals,
                                                    local_count,
                                                    local_cap,
                                                    next_offset_io,
                                                    callee,
                                                    i,
                                                    args[i],
                                                    has_target && i < target.param_count
                                                        ? target.param_types[i]
                                                        : "",
                                                    has_target && i < target.param_count
                                                        ? target.param_abi_classes[i]
                                                        : "")) {
                fprintf(stderr,
                        "[cheng_v3_seed] prepare composite call arg temp failed caller=%s callee=%s arg_index=%zu expr=%s has_target=%d\n",
                        current_function->symbol_text,
                        callee,
                        i,
                        args[i],
                        has_target ? 1 : 0);
                return false;
            }
        }
        if ((result_kind == V3_RESULT_INTRINSIC_IS_ERR ||
             result_kind == V3_RESULT_INTRINSIC_IS_OK ||
             result_kind == V3_RESULT_INTRINSIC_VALUE ||
             result_kind == V3_RESULT_INTRINSIC_ERROR ||
             result_kind == V3_RESULT_INTRINSIC_ERROR_TEXT ||
             result_kind == V3_RESULT_INTRINSIC_ERROR_INFO_OF) &&
            arg_count == 1U &&
            !v3_prepare_composite_expr_temp(plan,
                                            lowering,
                                            current_function,
                                            aliases,
                                            alias_count,
                                            locals,
                                            local_count,
                                            local_cap,
                                            next_offset_io,
                                            args[0])) {
            return false;
        }
    }
#undef expr
#undef outer
#undef base_name
#undef field_name
#undef index_expr
#undef if_cond
#undef if_true
#undef if_false
#undef ternary_cond
#undef ternary_true
#undef ternary_false
#undef named_field
#undef named_expr
#undef callee
#undef arg_text
#undef args
    return true;
}

static bool v3_prepare_expr_call_state(const V3SystemLinkPlanStub *plan,
                                       const V3LoweringPlanStub *lowering,
                                       const V3LoweredFunctionStub *current_function,
                                       const V3ImportAlias *aliases,
                                       size_t alias_count,
                                       V3AsmLocalSlot *locals,
                                       size_t *local_count,
                                       size_t local_cap,
                                       int32_t *next_offset_io,
                                       const char *expr_text,
                                       int call_depth,
                                       int32_t *max_call_depth_io) {
    V3ExprPrepScratch *scratch = (V3ExprPrepScratch *)v3_xmalloc(sizeof(V3ExprPrepScratch));
    memset(scratch, 0, sizeof(V3ExprPrepScratch));
    bool ok = v3_prepare_expr_call_state_impl(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              local_cap,
                                              next_offset_io,
                                              expr_text,
                                              call_depth,
                                              max_call_depth_io,
                                              scratch);
    free(scratch);
    return ok;
}

static void v3_emit_reg_to_return(char *out,
                                  size_t cap,
                                  int src_reg_index,
                                  const char *abi_class) {
    if (v3_abi_class_word_reg(abi_class)) {
        v3_text_appendf(out, cap, "  mov w0, w%d\n", src_reg_index);
    } else if (strcmp(abi_class, "i64") == 0 || strcmp(abi_class, "ptr") == 0) {
        if (src_reg_index != 0) {
            v3_text_appendf(out, cap, "  mov x0, x%d\n", src_reg_index);
        }
    }
}

static bool v3_emit_sp_adjust(char *out, size_t cap, bool subtract, int32_t amount) {
    if (amount < 0) {
        return false;
    }
    if (amount == 0) {
        return true;
    }
    if (amount <= 4095) {
        v3_text_appendf(out, cap, "  %s sp, sp, #%d\n", subtract ? "sub" : "add", amount);
        return true;
    }
    if (!v3_emit_mov_imm(out, cap, 17, amount)) {
        return false;
    }
    v3_text_appendf(out, cap, "  %s sp, sp, x17\n", subtract ? "sub" : "add");
    return true;
}

static bool v3_emit_sp_offset_address(char *out, size_t cap, int dst_reg, int32_t offset) {
    if (offset < 0) {
        return false;
    }
    if (offset == 0) {
        v3_text_appendf(out, cap, "  mov x%d, sp\n", dst_reg);
        return true;
    }
    if (offset <= 4095) {
        v3_text_appendf(out, cap, "  add x%d, sp, #%d\n", dst_reg, offset);
        return true;
    }
    if (!v3_emit_mov_imm(out, cap, 17, offset)) {
        return false;
    }
    v3_text_appendf(out, cap, "  add x%d, sp, x17\n", dst_reg);
    return true;
}

static bool v3_emit_add_address_offset(char *out,
                                       size_t cap,
                                       int dst_reg,
                                       int src_reg,
                                       int32_t offset) {
    if (offset < 0) {
        return false;
    }
    if (offset == 0) {
        if (dst_reg != src_reg) {
            v3_text_appendf(out, cap, "  mov x%d, x%d\n", dst_reg, src_reg);
        }
        return true;
    }
    if (offset <= 4095) {
        v3_text_appendf(out, cap, "  add x%d, x%d, #%d\n", dst_reg, src_reg, offset);
        return true;
    }
    if (!v3_emit_mov_imm(out, cap, 17, offset)) {
        return false;
    }
    v3_text_appendf(out, cap, "  add x%d, x%d, x17\n", dst_reg, src_reg);
    return true;
}

static bool v3_emit_sp_store_reg(char *out,
                                 size_t cap,
                                 int32_t offset,
                                 const char *abi_class,
                                 int src_reg) {
    if (!v3_emit_sp_offset_address(out, cap, 16, offset)) {
        return false;
    }
    v3_emit_store_scalar_to_address(out, cap, 16, 0, abi_class, src_reg);
    return true;
}

static bool v3_emit_sp_load_reg(char *out,
                                size_t cap,
                                int32_t offset,
                                const char *abi_class,
                                int dst_reg) {
    if (!v3_emit_sp_offset_address(out, cap, 16, offset)) {
        return false;
    }
    v3_emit_load_scalar_from_address(out, cap, 16, 0, abi_class, dst_reg);
    return true;
}

static bool v3_emit_function_epilogue(char *out, size_t cap, int32_t frame_size) {
    int32_t save_offset = frame_size - 16;
    if (save_offset < 0) {
        return false;
    }
    if (save_offset <= 504 && (save_offset % 8) == 0) {
        v3_text_appendf(out, cap, "  ldp x29, x30, [sp, #%d]\n", save_offset);
    } else if (!v3_emit_sp_offset_address(out, cap, 16, save_offset)) {
        return false;
    } else {
        v3_text_appendf(out, cap, "  ldp x29, x30, [x16]\n");
    }
    if (!v3_emit_sp_adjust(out, cap, false, frame_size)) {
        return false;
    }
    v3_text_appendf(out, cap, "  ret\n");
    return true;
}

static bool v3_validate_scalar_function_frame_layout(const V3LoweredFunctionStub *function,
                                                     int32_t max_call_depth,
                                                     int32_t call_arg_base,
                                                     int32_t string_temp_base,
                                                     int32_t string_temp_stride,
                                                     int32_t frame_size) {
    int32_t spill_layers = max_call_depth + 2;
    int32_t save_offset = frame_size - 16;
    int32_t call_arg_end;
    int32_t string_temp_end;
    if (spill_layers < 2) {
        spill_layers = 2;
    }
    call_arg_end = call_arg_base + spill_layers * CHENG_V3_CALL_ARG_SPILL_STRIDE;
    string_temp_end = string_temp_base;
    if (string_temp_stride > 0) {
        string_temp_end += string_temp_stride * spill_layers;
    }
    if (call_arg_end > string_temp_base) {
        fprintf(stderr,
                "[cheng_v3_seed] invalid frame layout function=%s call_args_overlap string_temp_base=%d call_arg_end=%d max_call_depth=%d frame_size=%d\n",
                function->symbol_text,
                string_temp_base,
                call_arg_end,
                max_call_depth,
                frame_size);
        return false;
    }
    if (string_temp_end + 16 > save_offset) {
        fprintf(stderr,
                "[cheng_v3_seed] invalid frame layout function=%s string_temps_overlap_save call_arg_base=%d string_temp_base=%d string_temp_stride=%d max_call_depth=%d string_temp_end=%d save_offset=%d frame_size=%d\n",
                function->symbol_text,
                call_arg_base,
                string_temp_base,
                string_temp_stride,
                max_call_depth,
                string_temp_end,
                save_offset,
                frame_size);
        return false;
    }
    return true;
}

static void v3_maybe_debug_scalar_function_frame_layout(const V3LoweredFunctionStub *function,
                                                        int32_t next_offset,
                                                        int32_t max_call_depth,
                                                        int32_t max_string_literal_temps,
                                                        int32_t call_arg_base,
                                                        int32_t string_temp_base,
                                                        int32_t string_temp_stride,
                                                        int32_t frame_size) {
    const char *needle = getenv("CHENG_V3_DEBUG_FRAME_LAYOUT");
    int32_t spill_layers = max_call_depth + 2;
    int32_t string_temp_end = string_temp_base;
    if (!needle || needle[0] == '\0') {
        return;
    }
    if (strcmp(needle, "1") != 0 &&
        strstr(function->symbol_text, needle) == NULL) {
        return;
    }
    if (spill_layers < 2) {
        spill_layers = 2;
    }
    if (string_temp_stride > 0) {
        string_temp_end += string_temp_stride * spill_layers;
    }
    fprintf(stderr,
            "[cheng_v3_seed] frame-debug function=%s next_offset=%d max_call_depth=%d max_string_literals=%d call_arg_base=%d string_temp_base=%d string_temp_stride=%d string_temp_end=%d frame_size=%d save_offset=%d\n",
            function->symbol_text,
            next_offset,
            max_call_depth,
            max_string_literal_temps,
            call_arg_base,
            string_temp_base,
            string_temp_stride,
            string_temp_end,
            frame_size,
            frame_size - 16);
}

