    v3_bytebuf_align_zero(&section, 2U);
    exit_name_rva = section_rva + (uint32_t)section.len;
    v3_bytebuf_append_zero_fill(&section, 2U);
    v3_bytebuf_append_cstring_raw(&section, "ExitProcess");
